# ── DPI awareness — must run before any Tk window is created ──────────────────
# Without this, Windows bitmap-upscales the whole window at high-DPI settings,
# causing the blurry / pixelated appearance users see on 125 %+ displays.
import ctypes as _ctypes
try:
    _ctypes.windll.shcore.SetProcessDpiAwareness(2)   # PROCESS_PER_MONITOR_DPI_AWARE
except AttributeError:
    try:
        _ctypes.windll.user32.SetProcessDPIAware()
    except AttributeError:
        pass
except OSError:
    pass

