# URL to a JSON manifest describing the latest build. Leave empty to disable
# the auto-update check entirely (useful for forks / private builds).
#
# Manifest schema:
#   {
#     "version":      "1.1.0",
#     "download_url": "https://.../BudgetPlanner.exe",
#     "sha256":       "<hex>",           # optional, verified if present
#     "notes":        "what changed",    # optional
#     "min_version":  "1.0.0"            # optional, skip if local < this
#   }
#
# Example (GitHub-hosted raw file):
#   https://raw.githubusercontent.com/<user>/<repo>/main/version.json
