# Index items by slot for quick lookup
AVATAR_ITEMS_BY_SLOT: Dict[str, list] = {}
for _aid, _aitem in AVATAR_ITEMS.items():
    AVATAR_ITEMS_BY_SLOT.setdefault(_aitem["slot"], []).append((_aid, _aitem))

# Animation levels by rarity — 0 = static, 1+ = animated
_RARITY_ANIM = {"common": 0, "rare": 1, "epic": 2, "legendary": 3}


def _avatar_anchors(cx: float, cy_head: float, head_r: float = 44.0) -> Dict[str, tuple]:
    """Return anchor (x, y) for each avatar slot.

    *cx* is the horizontal centre; *cy_head* is the vertical centre of
    the head circle. *head_r* is the head radius — all per-slot offsets
    are expressed as ratios of it so anchors stay in the right place at
    any canvas size. (The reference values were tuned at head_r ≈ 44.)
    All item draw-commands are offset relative to the anchor for their
    slot.
    """
    return {
        "background": (cx, cy_head),                          # backgrounds fill canvas via rect_abs
        "aura":       (cx, cy_head + head_r * 0.455),         # slightly below head centre — wraps whole bust
        "outfit":     (cx, cy_head + head_r * 1.818),         # body oval sits below head
        "eyes":       (cx, cy_head + head_r * 0.091),         # slightly below head centre
        "hair":       (cx, cy_head - head_r * 0.500),         # above head
        "accessory":  (cx, cy_head),                          # items self-position
    }


def _exec_avatar_draw(canvas: "tk.Canvas", cmd: tuple, ax: float, ay: float,
                       cw: float, ch: float, anim_frame: int = 0,
                       anim_level: int = 0, scale: float = 1.0):
    """Execute one draw command tuple on *canvas*.

    Each command is ``(method, coords, kwargs)`` where coords are
    relative to the slot anchor *(ax, ay)*. *scale* multiplies the
    relative offsets so items shrink/grow with the canvas. Stroke
    widths scale too (rounded, min 1) to keep proportions right.

    When *anim_frame* > 0 and *anim_level* > 0, animation transforms
    are applied:
      level 1 (rare):      text particles float gently
      level 2 (epic):      + arc rotation, outline shimmer
      level 3 (legendary): + glow pulse on outlines, wider float
    """
    method, coords, kwargs = cmd

    if method == "rect_abs":
        x1, y1, x2, y2 = coords
        canvas.create_rectangle(x1 * cw, y1 * ch, x2 * cw, y2 * ch, **kwargs)
        return

    # ── Animation transforms ────────────────────────────────────────
    if anim_frame > 0 and anim_level > 0:
        kwargs = dict(kwargs)  # avoid mutating the constant

        if method == "text":
            # Floating particles — per-particle phase so they desync
            tx, ty = coords
            phase = (hash(str(coords)) % 60)
            amp = 1.5 + anim_level * 0.7
            offset_y = math.sin((anim_frame + phase) * 0.10) * amp
            coords = (tx, ty + offset_y)

        if method == "arc" and anim_level >= 2:
            # Slow arc rotation for epic+
            if kwargs.get("style") == "arc" and "start" in kwargs:
                kwargs["start"] = kwargs["start"] + anim_frame * 1.4

        if anim_level >= 3 and method in ("oval", "arc", "polygon"):
            # Glow-pulse: widen outlines for legendary
            if kwargs.get("outline"):
                base_w = kwargs.get("width", 1)
                pulse = abs(math.sin(anim_frame * 0.07)) * 1.5
                kwargs["width"] = max(1, int(base_w + pulse))

    # Scale stroke widths proportionally (at scale<1 a 2px outline would
    # otherwise dominate a tiny avatar).
    if scale != 1.0 and "width" in kwargs and method in (
            "oval", "arc", "rectangle", "polygon", "line"):
        kwargs = dict(kwargs)
        kwargs["width"] = max(1, int(round(kwargs["width"] * scale)))

    # Translate relative coords to absolute canvas coords (with scaling)
    if method in ("oval", "arc", "rectangle"):
        x1, y1, x2, y2 = coords
        abs_coords = (ax + x1 * scale, ay + y1 * scale,
                      ax + x2 * scale, ay + y2 * scale)
        getattr(canvas, f"create_{method}")(*abs_coords, **kwargs)
    elif method == "polygon":
        abs_pts = [(ax + px * scale, ay + py * scale) for px, py in coords]
        canvas.create_polygon(abs_pts, **kwargs)
    elif method == "line":
        abs_pts = [(ax + px * scale, ay + py * scale) for px, py in coords]
        canvas.create_line(abs_pts, **kwargs)
    elif method == "text":
        tx, ty = coords
        # Text: scale position and font size (if numeric font tuple given)
        if scale != 1.0 and "font" in kwargs:
            font = kwargs["font"]
            if isinstance(font, tuple) and len(font) >= 2 and isinstance(font[1], (int, float)):
                new_size = max(6, int(round(abs(font[1]) * scale)))
                kwargs = dict(kwargs)
                kwargs["font"] = (font[0], new_size) + tuple(font[2:])
        canvas.create_text(ax + tx * scale, ay + ty * scale, **kwargs)


def draw_avatar(canvas: "tk.Canvas", equipped: dict, w: int = 260, h: int = 340,
                anim_frame: int = 0):
    """Render a bust-portrait avatar onto *canvas*.

    When *anim_frame* > 0 rare+ items receive animation effects
    (floating particles, rotating arcs, pulsing outlines).
    """
    canvas.delete("all")
    canvas.configure(width=w, height=h)

    cx = w / 2
    cy_head = h * 0.33
    head_r = min(w, h) * 0.17          # ~44 px at 260×340
    # Scale factor relative to reference size (260×340, head_r=44.2).
    # Used to scale per-item draw commands and hardcoded face pixels so
    # the figure renders cleanly at any canvas size.
    s = head_r / 44.2
    def p(n: float) -> float:
        return n * s

    anchors = _avatar_anchors(cx, cy_head, head_r)

    # Skin palette — warm mid-tone with highlight / shadow / blush variants
    skin      = "#d4a574"
    skin_hi   = "#ddb88a"   # forehead highlight (closer to skin for softer blend)
    skin_hi2  = "#e6c89c"   # bright highlight (nose, lip)
    skin_sh   = "#bf9470"   # chin / neck shadow (warmer, less contrast)
    skin_sh2  = "#ae8464"   # deep shadow (jaw, ear inner)
    skin_out  = "#cda07a"   # head outline (closer to skin — softer edge)
    skin_blush = "#d8a088"  # cheek warmth (subtler pink)
    skin_mid  = "#d0a078"   # intermediate between skin and shadow

    # Helper: per-item animation level
    def _al(item):
        return _RARITY_ANIM.get(item["rarity"], 0) if anim_frame else 0

    # ── 1. Background ───────────────────────────────────────────────
    bg_id = equipped.get("background", "")
    bg_item = AVATAR_ITEMS.get(bg_id)
    if bg_item and bg_item["draw"]:
        bx, by = anchors["background"]
        al = _al(bg_item)
        for cmd in bg_item["draw"]:
            _exec_avatar_draw(canvas, cmd, bx, by, w, h, anim_frame, al, scale=s)

    # ── 2. Aura ─────────────────────────────────────────────────────
    aura_id = equipped.get("aura", "")
    aura_item = AVATAR_ITEMS.get(aura_id)
    if aura_item and aura_item["draw"]:
        ax, ay = anchors["aura"]
        al = _al(aura_item)
        for cmd in aura_item["draw"]:
            _exec_avatar_draw(canvas, cmd, ax, ay, w, h, anim_frame, al, scale=s)

    # ── 3. Outfit (shoulder-torso polygon) ──────────────────────────
    outfit_id = equipped.get("outfit", "")
    outfit_item = AVATAR_ITEMS.get(outfit_id)
    if outfit_item and outfit_item["draw"]:
        ox, oy = anchors["outfit"]
        al = _al(outfit_item)
        for cmd in outfit_item["draw"]:
            _exec_avatar_draw(canvas, cmd, ox, oy, w, h, anim_frame, al, scale=s)
    else:
        # Fallback: plain dark shoulder shape with soft gradient
        ox, oy = anchors["outfit"]
        canvas.create_polygon(
            ox - p(56), oy - p(22), ox - p(74), oy + p(14), ox - p(64), oy + p(155),
            ox + p(64), oy + p(155), ox + p(74), oy + p(14), ox + p(56), oy - p(22),
            fill="#2d3442", outline="#3d4656", width=max(1, int(round(2 * s))),
            smooth=True, splinesteps=12)
        canvas.create_polygon(
            ox - p(50), oy - p(18), ox - p(66), oy + p(14), ox - p(58), oy + p(148),
            ox + p(58), oy + p(148), ox + p(66), oy + p(14), ox + p(50), oy - p(18),
            fill="#374151", outline="",
            smooth=True, splinesteps=12)
        canvas.create_polygon(
            ox - p(44), oy - p(14), ox - p(58), oy + p(14), ox - p(52), oy + p(140),
            ox + p(52), oy + p(140), ox + p(58), oy + p(14), ox + p(44), oy - p(14),
            fill="#4b5563", outline="",
            smooth=True, splinesteps=12)

    # ── 4. Base character ───────────────────────────────────────────
    # Dimensions derived from head radius so everything scales together
    nw_top = head_r * 0.36             # neck width at jaw
    nw_bot = head_r * 0.48             # neck width at collar
    neck_len = head_r * 0.52           # neck length
    neck_top = cy_head + head_r - p(3)
    neck_bot = neck_top + neck_len
    er = head_r * 0.18                 # ear radius

    # Jaw/chin shadow — three layers for soft gradient falloff
    canvas.create_oval(cx - head_r * 0.58, cy_head + head_r * 0.40,
                       cx + head_r * 0.58, neck_bot + p(8),
                       fill=skin_sh2, outline="")
    canvas.create_oval(cx - head_r * 0.52, cy_head + head_r * 0.46,
                       cx + head_r * 0.52, neck_bot + p(5),
                       fill=skin_mid, outline="")
    canvas.create_oval(cx - head_r * 0.45, cy_head + head_r * 0.52,
                       cx + head_r * 0.45, neck_bot + p(3),
                       fill=skin_sh, outline="")

    # Neck — tapered polygon (wider at collar)
    canvas.create_polygon(
        cx - nw_top, neck_top,
        cx + nw_top, neck_top,
        cx + nw_bot, neck_bot,
        cx - nw_bot, neck_bot,
        fill=skin, outline="", smooth=True, splinesteps=8)

    # Neck left shadow edge
    canvas.create_polygon(
        cx - nw_top, neck_top,
        cx - nw_top * 0.45, neck_top,
        cx - nw_bot * 0.45, neck_bot,
        cx - nw_bot, neck_bot,
        fill=skin_sh, outline="", smooth=True, splinesteps=8)
    # Neck right shadow edge (lighter)
    canvas.create_polygon(
        cx + nw_top * 0.5, neck_top,
        cx + nw_top, neck_top,
        cx + nw_bot, neck_bot,
        cx + nw_bot * 0.5, neck_bot,
        fill="#c89e78", outline="", smooth=True, splinesteps=8)

    # Neck center crease (very subtle — matches skin_mid)
    canvas.create_line(cx, neck_top + p(6), cx, neck_bot - p(4),
                       fill=skin_mid, width=1)

    # Collarbone hints (soft, using intermediate tone)
    canvas.create_arc(cx - nw_bot * 1.2, neck_bot - p(4),
                      cx - p(2), neck_bot + p(8),
                      start=15, extent=150, style="arc",
                      outline=skin_mid, width=1)
    canvas.create_arc(cx + p(2), neck_bot - p(4),
                      cx + nw_bot * 1.2, neck_bot + p(8),
                      start=15, extent=150, style="arc",
                      outline=skin_mid, width=1)

    # Ears (behind head edge) — left ear with soft inner gradient
    canvas.create_oval(cx - head_r - er * 0.6, cy_head - er * 1.1,
                       cx - head_r + er * 0.6, cy_head + er * 1.1,
                       fill=skin, outline=skin_mid, width=1)
    canvas.create_oval(cx - head_r - er * 0.35, cy_head - er * 0.7,
                       cx - head_r + er * 0.5, cy_head + er * 0.7,
                       fill=skin_mid, outline="")
    canvas.create_oval(cx - head_r - er * 0.15, cy_head - er * 0.4,
                       cx - head_r + er * 0.35, cy_head + er * 0.4,
                       fill=skin_sh, outline="")
    # Right ear
    canvas.create_oval(cx + head_r - er * 0.6, cy_head - er * 1.1,
                       cx + head_r + er * 0.6, cy_head + er * 1.1,
                       fill=skin, outline=skin_mid, width=1)
    canvas.create_oval(cx + head_r - er * 0.5, cy_head - er * 0.7,
                       cx + head_r + er * 0.35, cy_head + er * 0.7,
                       fill=skin_mid, outline="")
    canvas.create_oval(cx + head_r - er * 0.35, cy_head - er * 0.4,
                       cx + head_r + er * 0.15, cy_head + er * 0.4,
                       fill=skin_sh, outline="")

    # Head circle
    canvas.create_oval(cx - head_r, cy_head - head_r,
                       cx + head_r, cy_head + head_r,
                       fill=skin, outline=skin_out, width=1)

    # Forehead highlight — three graduated layers for soft 3-D blend
    hl = head_r * 0.55
    # Wide soft base (barely lighter than skin)
    canvas.create_oval(cx - hl - p(8), cy_head - hl - p(8),
                       cx + hl - p(8), cy_head + hl * 0.3,
                       fill=skin_mid, outline="")
    # Mid highlight
    canvas.create_oval(cx - hl - p(4), cy_head - hl - p(5),
                       cx + hl - p(12), cy_head + hl * 0.15,
                       fill=skin_hi, outline="")
    # Bright forehead spot
    canvas.create_oval(cx - hl * 0.5, cy_head - hl - p(2),
                       cx + hl * 0.1, cy_head - hl * 0.3,
                       fill=skin_hi2, outline="")

    # Cheekbone highlights
    canvas.create_oval(cx - head_r * 0.6, cy_head + head_r * 0.02,
                       cx - head_r * 0.18, cy_head + head_r * 0.28,
                       fill=skin_hi, outline="")
    canvas.create_oval(cx + head_r * 0.18, cy_head + head_r * 0.02,
                       cx + head_r * 0.6, cy_head + head_r * 0.28,
                       fill=skin_hi, outline="")

    # Subtle blush (warm pink undertone on cheeks)
    canvas.create_oval(cx - head_r * 0.56, cy_head + head_r * 0.1,
                       cx - head_r * 0.2, cy_head + head_r * 0.34,
                       fill=skin_blush, outline="")
    canvas.create_oval(cx + head_r * 0.2, cy_head + head_r * 0.1,
                       cx + head_r * 0.56, cy_head + head_r * 0.34,
                       fill=skin_blush, outline="")

    # Jaw line shadow arcs
    canvas.create_arc(cx - head_r * 1.02, cy_head + head_r * 0.3,
                      cx - head_r * 0.15, cy_head + head_r * 1.08,
                      start=285, extent=52, style="arc",
                      outline=skin_sh, width=1)
    canvas.create_arc(cx + head_r * 0.15, cy_head + head_r * 0.3,
                      cx + head_r * 1.02, cy_head + head_r * 1.08,
                      start=203, extent=52, style="arc",
                      outline=skin_sh, width=1)

    # Eyebrows — soft warm-brown arcs (thin for natural look)
    brow_w = head_r * 0.30
    brow_y = cy_head - head_r * 0.12
    brow_h = max(2.0, head_r * 0.11)
    canvas.create_arc(cx - head_r * 0.38 - brow_w, brow_y - brow_h,
                      cx - head_r * 0.38 + brow_w, brow_y + brow_h,
                      start=15, extent=150, style="arc",
                      outline="#a8876a", width=1)
    canvas.create_arc(cx + head_r * 0.38 - brow_w, brow_y - brow_h,
                      cx + head_r * 0.38 + brow_w, brow_y + brow_h,
                      start=15, extent=150, style="arc",
                      outline="#a8876a", width=1)

    # Nose — soft bridge line, rounded ball, gentle nostril shadows
    canvas.create_line(cx, cy_head - head_r * 0.02,
                       cx, cy_head + head_r * 0.22,
                       fill=skin_mid, width=1)
    nose_ball_w  = max(2.0, head_r * 0.113)   # ~5 @ head_r=44
    nose_inner_w = max(1.5, head_r * 0.068)   # ~3 @ head_r=44
    nose_hl_w    = max(1.0, head_r * 0.045)   # ~2 @ head_r=44
    nostril_gap  = max(1.0, head_r * 0.045)   # ~2 @ head_r=44
    # Nose ball — outer soft edge
    canvas.create_oval(cx - nose_ball_w, cy_head + head_r * 0.18,
                       cx + nose_ball_w, cy_head + head_r * 0.38,
                       fill=skin_mid, outline="")
    # Nose ball — inner
    canvas.create_oval(cx - nose_inner_w, cy_head + head_r * 0.20,
                       cx + nose_inner_w, cy_head + head_r * 0.34,
                       fill=skin_out, outline="")
    # Nose highlight
    canvas.create_oval(cx - nose_hl_w, cy_head + head_r * 0.16,
                       cx + nose_hl_w * 0.5, cy_head + head_r * 0.26,
                       fill=skin_hi2, outline="")
    # Nostril shadows (softer)
    canvas.create_oval(cx - nose_ball_w, cy_head + head_r * 0.29,
                       cx - nostril_gap, cy_head + head_r * 0.34,
                       fill=skin_sh, outline="")
    canvas.create_oval(cx + nostril_gap, cy_head + head_r * 0.29,
                       cx + nose_ball_w, cy_head + head_r * 0.34,
                       fill=skin_sh, outline="")

    # Mouth — soft natural lip rendering
    m_w = head_r * 0.34
    # Upper lip line (warm, subtle)
    canvas.create_arc(cx - m_w, cy_head + head_r * 0.36,
                      cx + m_w, cy_head + head_r * 0.6,
                      start=200, extent=140, style="arc",
                      outline="#be8a70", width=1)
    # Cupid's bow
    canvas.create_line(cx - m_w * 0.35, cy_head + head_r * 0.445,
                       cx, cy_head + head_r * 0.42,
                       cx + m_w * 0.35, cy_head + head_r * 0.445,
                       fill="#be8a70", width=1, smooth=True)
    # Lower lip — soft warm arc
    canvas.create_arc(cx - m_w * 0.8, cy_head + head_r * 0.44,
                      cx + m_w * 0.8, cy_head + head_r * 0.66,
                      start=20, extent=-140, style="arc",
                      outline="#cca088", width=1)
    # Lip highlight — soft center
    lip_hl_w = max(1.5, head_r * 0.068)
    canvas.create_oval(cx - lip_hl_w, cy_head + head_r * 0.47,
                       cx + lip_hl_w, cy_head + head_r * 0.53,
                       fill=skin_hi, outline="")

    # ── 5. Eyes ─────────────────────────────────────────────────────
    eyes_id = equipped.get("eyes", "")
    eyes_item = AVATAR_ITEMS.get(eyes_id)
    if eyes_item and eyes_item["draw"]:
        ex, ey = anchors["eyes"]
        al = _al(eyes_item)
        for cmd in eyes_item["draw"]:
            _exec_avatar_draw(canvas, cmd, ex, ey, w, h, anim_frame, al, scale=s)
    else:
        # Default almond-shaped eyes with lid, iris, pupil, catch-light
        ex, ey = anchors["eyes"]
        # Geometry driven by head_r so everything scales together
        eye_off   = max(4.0, head_r * 0.27)   # ~12 @ head_r=44
        sclera_w  = max(3.0, head_r * 0.20)   # ~9
        sclera_h  = max(2.0, head_r * 0.11)   # ~5
        lid_h_top = max(2.0, head_r * 0.16)   # ~7
        lid_h_bot = max(1.5, head_r * 0.068)  # ~3
        iris_outer_w = max(2.0, head_r * 0.136)   # ~6
        iris_mid_w   = max(2.0, head_r * 0.113)   # ~5
        iris_mid_h   = max(1.5, head_r * 0.091)   # ~4
        iris_in_r    = max(1.5, head_r * 0.068)   # ~3
        pup_r        = max(1.0, head_r * 0.045)   # ~2
        hl_r         = max(0.8, head_r * 0.032)   # ~1.4

        for side in (-1, 1):
            ox_e = ex + side * eye_off
            # Upper eyelid shadow (soft)
            canvas.create_arc(ox_e - sclera_w, ey - lid_h_top,
                              ox_e + sclera_w, ey + lid_h_bot,
                              start=10, extent=160, style="arc",
                              outline=skin_mid, width=1)
            # Sclera — wider almond (soft outline)
            canvas.create_oval(ox_e - sclera_w, ey - sclera_h,
                               ox_e + sclera_w, ey + sclera_h,
                               fill="#f4f0ec", outline="#c8b8a8", width=1)
            # Outer iris ring
            canvas.create_oval(ox_e - iris_outer_w, ey - sclera_h,
                               ox_e + iris_outer_w, ey + sclera_h,
                               fill="#5d4037", outline="#4a3028")
            # Iris mid
            canvas.create_oval(ox_e - iris_mid_w, ey - iris_mid_h,
                               ox_e + iris_mid_w, ey + iris_mid_h,
                               fill="#6d503f", outline="")
            # Iris inner
            canvas.create_oval(ox_e - iris_in_r, ey - iris_in_r,
                               ox_e + iris_in_r, ey + iris_in_r,
                               fill="#54382a", outline="")
            # Pupil
            canvas.create_oval(ox_e - pup_r, ey - pup_r,
                               ox_e + pup_r, ey + pup_r,
                               fill="#1a1a1a", outline="")
            # Catch-light
            canvas.create_oval(ox_e + hl_r * 0.7, ey - hl_r * 2.1,
                               ox_e + hl_r * 2.1, ey - hl_r * 0.7,
                               fill="#ffffff", outline="")
            # Lower lid hint (very subtle)
            canvas.create_arc(ox_e - sclera_w * 0.8, ey - lid_h_bot,
                              ox_e + sclera_w * 0.8, ey + lid_h_top,
                              start=200, extent=140, style="arc",
                              outline="#d4c0b0", width=1)

    # ── 6. Hair ─────────────────────────────────────────────────────
    hair_id = equipped.get("hair", "")
    hair_item = AVATAR_ITEMS.get(hair_id)
    if hair_item and hair_item["draw"]:
        hx, hy = anchors["hair"]
        al = _al(hair_item)
        for cmd in hair_item["draw"]:
            _exec_avatar_draw(canvas, cmd, hx, hy, w, h, anim_frame, al, scale=s)

    # ── 7. Accessory ────────────────────────────────────────────────
    acc_id = equipped.get("accessory", "")
    acc_item = AVATAR_ITEMS.get(acc_id)
    if acc_item and acc_item["draw"]:
        accx, accy = anchors["accessory"]
        al = _al(acc_item)
        for cmd in acc_item["draw"]:
            _exec_avatar_draw(canvas, cmd, accx, accy, w, h, anim_frame, al, scale=s)


def _draw_gerald(canvas: "tk.Canvas", w: int = 180, h: int = 240, expression: str = "normal"):
    """Draw Gerald — the tutorial guide character.

    Gerald has exclusive items not available to the player:
    teal-jade vest, auburn messy spikes, asymmetric wink eyes.

    All pixel offsets scale with ``s = min(w, h) / 180`` so the figure
    renders cleanly at any canvas size (60×80 commentator, 120×150
    tutorial panel, 180×240 reference).
    """
    canvas.delete("all")
    canvas.configure(width=w, height=h)
    cx = w / 2
    # Head vertical position: keep room for the body underneath at small
    # canvas sizes so the vest doesn't vanish off the bottom.
    s = min(w, h) / 180.0
    head_r = min(w, h) * 0.19
    cy_head = max(head_r + 4 * s, h * 0.32)

    def p(n: float) -> float:
        """Scale a reference-size pixel value."""
        return n * s

    skin     = "#d4a574"
    skin_hi  = "#ddb88a"
    skin_sh  = "#bf9470"
    skin_mid = "#d0a078"

    # ── Body — teal-jade vest over white shirt ──────────────────────
    bx, by = cx, cy_head + p(64)
    # White undershirt
    canvas.create_polygon(
        bx - p(42), by - p(16), bx - p(56), by + p(10), bx - p(48), by + p(120),
        bx + p(48), by + p(120), bx + p(56), by + p(10), bx + p(42), by - p(16),
        fill="#e2e8f0", outline="#cbd5e1", width=1,
        smooth=True, splinesteps=12)
    # Teal vest — left panel
    canvas.create_polygon(
        bx - p(36), by - p(14), bx - p(50), by + p(8), bx - p(44), by + p(110),
        bx - p(8),  by + p(110), bx - p(8),  by - p(4),
        fill="#0d9488", outline="#0f766e", width=max(1, int(round(2 * s))),
        smooth=True, splinesteps=10)
    # Teal vest — right panel
    canvas.create_polygon(
        bx + p(36), by - p(14), bx + p(50), by + p(8), bx + p(44), by + p(110),
        bx + p(8),  by + p(110), bx + p(8),  by - p(4),
        fill="#0d9488", outline="#0f766e", width=max(1, int(round(2 * s))),
        smooth=True, splinesteps=10)
    # Vest buttons
    btn_r = max(1.0, p(2))
    for yb in (by + p(20), by + p(40), by + p(60)):
        canvas.create_oval(bx - btn_r, yb - btn_r, bx + btn_r, yb + btn_r,
                           fill="#fbbf24", outline="#d97706")

    # ── Neck ────────────────────────────────────────────────────────
    nw_top = head_r * 0.34
    nw_bot = head_r * 0.44
    neck_top = cy_head + head_r - p(2)
    neck_bot = neck_top + head_r * 0.45
    canvas.create_oval(cx - head_r * 0.4, cy_head + head_r * 0.55,
                       cx + head_r * 0.4, neck_bot + p(2),
                       fill=skin_sh, outline="")
    canvas.create_polygon(
        cx - nw_top, neck_top, cx + nw_top, neck_top,
        cx + nw_bot, neck_bot, cx - nw_bot, neck_bot,
        fill=skin, outline="", smooth=True, splinesteps=8)

    # ── Head ────────────────────────────────────────────────────────
    canvas.create_oval(cx - head_r, cy_head - head_r,
                       cx + head_r, cy_head + head_r,
                       fill=skin, outline=skin_mid, width=1)
    hl = head_r * 0.5
    canvas.create_oval(cx - hl - p(3), cy_head - hl - p(4),
                       cx + hl - p(8), cy_head + hl * 0.25 - p(4),
                       fill=skin_hi, outline="")

    # ── Nose ────────────────────────────────────────────────────────
    canvas.create_line(cx, cy_head + head_r * 0.04,
                       cx, cy_head + head_r * 0.26,
                       fill=skin_mid, width=1)
    nose_w = max(1.5, head_r * 0.09)
    canvas.create_oval(cx - nose_w, cy_head + head_r * 0.2,
                       cx + nose_w, cy_head + head_r * 0.34,
                       fill=skin_mid, outline="")

    # ── Mouth — cheeky smirk (asymmetric) ──────────────────────────
    if expression == "wink":
        canvas.create_arc(cx - head_r * 0.28, cy_head + head_r * 0.34,
                          cx + head_r * 0.36, cy_head + head_r * 0.66,
                          start=200, extent=140, style="arc",
                          outline=skin_sh, width=max(1, int(round(2 * s))))
    else:
        canvas.create_arc(cx - head_r * 0.3, cy_head + head_r * 0.32,
                          cx + head_r * 0.34, cy_head + head_r * 0.64,
                          start=205, extent=130, style="arc",
                          outline=skin_sh, width=1)

    # ── Eyes — left normal, right wink ──────────────────────────────
    lex, ley = cx - head_r * 0.28, cy_head + head_r * 0.02
    rex, rey = cx + head_r * 0.28, cy_head + head_r * 0.02

    # Eye geometry scales with head size, not fixed pixels
    eye_hw = max(3.0, head_r * 0.21)   # sclera half-width
    eye_hh = max(2.0, head_r * 0.15)   # sclera half-height
    iris_r = max(1.5, head_r * 0.09)
    pup_r  = max(1.0, head_r * 0.05)
    hl_r   = max(0.8, head_r * 0.04)

    def _draw_eye(cx_e: float, cy_e: float):
        canvas.create_oval(cx_e - eye_hw, cy_e - eye_hh,
                           cx_e + eye_hw, cy_e + eye_hh,
                           fill="#f4f0ec", outline=skin_mid, width=1)
        canvas.create_oval(cx_e - iris_r, cy_e - iris_r,
                           cx_e + iris_r, cy_e + iris_r,
                           fill="#6b4226", outline="")
        canvas.create_oval(cx_e - pup_r, cy_e - pup_r,
                           cx_e + pup_r, cy_e + pup_r,
                           fill="#1a1a1a", outline="")
        canvas.create_oval(cx_e + hl_r * 0.6, cy_e - hl_r * 2,
                           cx_e + hl_r * 2, cy_e - hl_r * 0.6,
                           fill="#ffffff", outline="")

    _draw_eye(lex, ley)
    if expression == "wink":
        canvas.create_line(rex - eye_hw * 0.86, rey, rex + eye_hw * 0.86, rey,
                           fill=skin_mid, width=max(1, int(round(2 * s))))
        # Cheeky uptick
        canvas.create_line(rex + eye_hw * 0.57, rey,
                           rex + eye_hw,         rey - eye_hh * 0.6,
                           fill=skin_mid, width=max(1, int(round(2 * s))))
    else:
        _draw_eye(rex, rey)

    # Left eyebrow — raised (soft)
    brow_hw = max(3.0, head_r * 0.24)
    brow_hh = max(2.0, head_r * 0.14)
    canvas.create_arc(lex - brow_hw, ley - brow_hh * 2.0,
                      lex + brow_hw, ley - brow_hh * 0.6,
                      start=20, extent=140, style="arc",
                      outline="#6b4420", width=1)
    # Right eyebrow — lowered (cheeky, soft)
    canvas.create_arc(rex - brow_hw, rey - brow_hh * 1.6,
                      rex + brow_hw, rey - brow_hh * 0.4,
                      start=20, extent=140, style="arc",
                      outline="#6b4420", width=1)

    # ── Hair — messy auburn spikes ──────────────────────────────────
    hx, hy = cx, cy_head - head_r * 0.48
    hair_c = "#8b3a1a"
    hair_h = "#a0441e"
    # Main hair mass
    canvas.create_arc(cx - head_r * 1.08, hy - head_r * 0.15,
                      cx + head_r * 1.08, hy + head_r * 0.75,
                      fill=hair_c, outline="",
                      start=0, extent=180, style="pieslice")
    # Spikes — offsets expressed as head_r ratios so they scale cleanly
    #   (sx_r, sw_r, sh_r, col) — ratios relative to head_r
    spike_specs = [
        (-0.41, 0.20, -0.82, hair_h),
        (-0.12, 0.18, -1.05, hair_c),
        ( 0.18, 0.20, -0.88, hair_h),
        ( 0.47, 0.15, -0.64, hair_c),
        (-0.64, 0.15, -0.53, hair_c),
    ]
    for sx_r, sw_r, sh_r, col in spike_specs:
        sx, sw, sh = head_r * sx_r, head_r * sw_r, head_r * sh_r
        canvas.create_polygon(
            hx + sx - sw, hy + p(4), hx + sx, hy + sh,
            hx + sx + sw, hy + p(4),
            fill=col, outline="", smooth=True, splinesteps=4)
    # Side flicks
    canvas.create_arc(cx - head_r * 1.1, cy_head - head_r * 0.2,
                      cx - head_r * 0.5, cy_head + head_r * 0.3,
                      fill=hair_c, outline="",
                      start=80, extent=100, style="pieslice")
    canvas.create_arc(cx + head_r * 0.5, cy_head - head_r * 0.2,
                      cx + head_r * 1.1, cy_head + head_r * 0.3,
                      fill=hair_c, outline="",
                      start=0, extent=100, style="pieslice")


