def previous_calendar_month_window(today: date) -> tuple[date, date]:
    """First and last day of the calendar month before ``today``."""
    first_this = today.replace(day=1)
    last_prev = first_this - timedelta(days=1)
    first_prev = last_prev.replace(day=1)
    return first_prev, last_prev


def outgoing_category_totals(
    transactions: List[TransactionRecord], start: date, end: date
) -> Dict[str, float]:
    """Sum money_out by category between ``start`` and ``end`` (inclusive)."""
    out: Dict[str, float] = {}
    for tx in transactions:
        if tx.direction() != "out" or tx.matched_type == "ignore":
            continue
        if tx.tx_date < start or tx.tx_date > end:
            continue
        cat = (tx.category or "").strip() or "Uncategorized"
        out[cat] = out.get(cat, 0.0) + tx.money_out
    return out


def percents_from_amounts(amounts: Dict[str, float]) -> Dict[str, float]:
    total = sum(amounts.values())
    if total <= 0:
        return {k: 0.0 for k in amounts}
    return {k: round(100.0 * v / total, 2) for k, v in amounts.items()}


def normalize_desc_text(desc: str) -> str:
    return re.sub(r"\s+", " ", (desc or "")).strip()


def normalize_merchant_key(desc: str) -> str:
    return normalize_desc_text(desc).lower()


def clamp(value: float, low: float, high: float) -> float:
    return max(low, min(high, value))


def month_bounds(any_day: date) -> tuple[date, date]:
    first_day = any_day.replace(day=1)
    last_day = any_day.replace(day=calendar.monthrange(any_day.year, any_day.month)[1])
    return first_day, last_day


def extract_merchant_name(desc: str) -> str:
    text = normalize_desc_text(desc).upper()
    text = re.sub(r"\b(POS|VISA|DEBIT|CREDIT|PURCHASE|PAYMENT|TRANSFER|DIRECT DEBIT|CARD|ONLINE)\b", " ", text)
    text = re.sub(r"\d+", " ", text)
    text = re.sub(r"[^A-Z& ]+", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    if not text:
        return "Unknown Merchant"
    parts = [p for p in text.split() if len(p) >= 2]
    if not parts:
        return "Unknown Merchant"
    return " ".join(parts[:3]).title()


def merchant_group_key(desc: str) -> str:
    merchant = extract_merchant_name(desc).lower()
    merchant = re.sub(r"\b(australia|pty|ltd|store|stores|market|markets|service|services|payment|payments)\b", " ", merchant)
    merchant = re.sub(r"\s+", " ", merchant).strip()
    return merchant or normalize_merchant_key(desc)


