@dataclass
class GameStats:
    # Core
    total_score: int = 0
    level: int = 1
    streak_pays: int = 0
    best_streak: int = 0
    total_pays_processed: int = 0
    last_score_gain: int = 0
    achievements: List[str] = field(default_factory=list)
    mini_game_high_score: int = 0
    mini_game_rounds_won: int = 0
    # Progression systems
    gems: int = 0
    prestige_level: int = 0
    score_multiplier: float = 1.0
    streak_shields: int = 0
    active_buffs: List[str] = field(default_factory=list)
    season_year_month: str = ""
    season_xp: int = 0
    season_claimed_tiers: List[int] = field(default_factory=list)
    daily_challenges: List[dict] = field(default_factory=list)
    daily_challenges_date: str = ""
    perks_unlocked: List[str] = field(default_factory=list)
    lifetime_gems_earned: int = 0
    # Collection system
    cards_owned: List[str] = field(default_factory=list)   # list of card_ids (duplicates allowed)
    packs_opened: int = 0
    # Character system
    character_items_owned: List[str] = field(default_factory=lambda: ["hair_short_dark", "eyes_focused_brown", "outfit_starter_hoodie", "background_midnight"])
    character_equipped: Dict[str, str] = field(default_factory=lambda: {
        "hair": "hair_short_dark",
        "eyes": "eyes_focused_brown",
        "outfit": "outfit_starter_hoodie",
        "accessory": "",
        "aura": "",
        "background": "background_midnight",
    })
    character_favorites: List[str] = field(default_factory=list)
    # Streak chain (True = good pay, False = broken)
    streak_history: List[bool] = field(default_factory=list)
    # Last money-personality snapshot (for trend arrows). {"attrs": {...}, "archetype_id": "...", "captured_on": "YYYY-MM-DD"}
    personality_snapshot: dict = field(default_factory=dict)
    # Integrity
    last_pay_scored_date: str = ""   # YYYY-MM-DD — prevents same-day multi-scoring
    # Arcade daily earn caps — prevents grinding mini-games for infinite rewards
    arcade_daily_date: str = ""      # YYYY-MM-DD — rolls over at calendar day
    arcade_gold_today: int = 0
    arcade_gems_today: int = 0

    def to_dict(self):
        return asdict(self)

    @classmethod
    def from_dict(cls, data):
        return cls(
            total_score=int(data.get("total_score", 0)),
            level=int(data.get("level", 1)),
            streak_pays=int(data.get("streak_pays", 0)),
            best_streak=int(data.get("best_streak", 0)),
            total_pays_processed=int(data.get("total_pays_processed", 0)),
            last_score_gain=int(data.get("last_score_gain", 0)),
            achievements=list(data.get("achievements", [])),
            mini_game_high_score=int(data.get("mini_game_high_score", 0)),
            mini_game_rounds_won=int(data.get("mini_game_rounds_won", 0)),
            gems=int(data.get("gems", 0)),
            prestige_level=int(data.get("prestige_level", 0)),
            score_multiplier=float(data.get("score_multiplier", 1.0)),
            streak_shields=int(data.get("streak_shields", 0)),
            active_buffs=list(data.get("active_buffs", [])),
            season_year_month=str(data.get("season_year_month", "")),
            season_xp=int(data.get("season_xp", 0)),
            season_claimed_tiers=list(data.get("season_claimed_tiers", [])),
            daily_challenges=list(data.get("daily_challenges", [])),
            daily_challenges_date=str(data.get("daily_challenges_date", "")),
            perks_unlocked=list(data.get("perks_unlocked", [])),
            lifetime_gems_earned=int(data.get("lifetime_gems_earned", 0)),
            cards_owned=list(data.get("cards_owned", [])),
            packs_opened=int(data.get("packs_opened", 0)),
            character_items_owned=list(data.get("character_items_owned", ["hair_short_dark", "eyes_focused_brown", "outfit_starter_hoodie", "background_midnight"])),
            character_equipped=dict(data.get("character_equipped", {
                "hair": "hair_short_dark",
                "eyes": "eyes_focused_brown",
                "outfit": "outfit_starter_hoodie",
                "accessory": "",
                "aura": "",
                "background": "background_midnight",
            })),
            character_favorites=list(data.get("character_favorites", [])),
            streak_history=list(data.get("streak_history", [])),
            personality_snapshot=dict(data.get("personality_snapshot", {})),
            last_pay_scored_date=str(data.get("last_pay_scored_date", "")),
            arcade_daily_date=str(data.get("arcade_daily_date", "")),
            arcade_gold_today=int(data.get("arcade_gold_today", 0)),
            arcade_gems_today=int(data.get("arcade_gems_today", 0)),
        )


