@dataclass
class TransactionRecord:
    tx_date: date
    description: str
    money_in: float = 0.0
    money_out: float = 0.0
    balance: Optional[float] = None
    source_file: str = ""
    fingerprint: str = ""
    matched_type: str = "unmatched"
    matched_target: str = ""
    category: str = ""
    confidence: str = "low"
    needs_review: bool = True
    user_verified: bool = False
    notes: str = ""

    def amount(self) -> float:
        return self.money_in if self.money_in > 0 else self.money_out

    def direction(self) -> str:
        return "in" if self.money_in > 0 else "out"

    def to_dict(self):
        d = asdict(self)
        d["tx_date"] = self.tx_date.isoformat()
        return d

    @classmethod
    def from_dict(cls, data):
        return cls(
            datetime.strptime(data["tx_date"], "%Y-%m-%d").date(),
            data["description"],
            float(data.get("money_in", 0.0)),
            float(data.get("money_out", 0.0)),
            float(data["balance"]) if data.get("balance") not in (None, "") else None,
            data.get("source_file", ""),
            data.get("fingerprint", ""),
            data.get("matched_type", "unmatched"),
            data.get("matched_target", ""),
            data.get("category", ""),
            data.get("confidence", "low"),
            bool(data.get("needs_review", True)),
            bool(data.get("user_verified", False)),
            data.get("notes", ""),
        )


@dataclass
class MerchantMemoryEntry:
    """Remember verified classification per normalized description + direction (for repeat imports)."""
    category: str
    matched_type: str = "discretionary"
    matched_target: str = ""
    direction: str = "out"

    def to_dict(self):
        return asdict(self)

    @classmethod
    def from_dict(cls, data):
        return cls(
            data.get("category", ""),
            data.get("matched_type", "discretionary"),
            data.get("matched_target", ""),
            data.get("direction", "out"),
        )


@dataclass
class AppState:
    pay_frequency: str = "fortnightly"
    emergency_fund_target: float = 5000.0
    incomes: List[IncomeEntry] = field(default_factory=list)
    bills: List[Bill] = field(default_factory=list)
    funds: List[Fund] = field(default_factory=list)
    goals: List[Goal] = field(default_factory=list)
    game: GameStats = field(default_factory=GameStats)
    transactions: List[TransactionRecord] = field(default_factory=list)
    advanced_match_rules: List[AdvancedMatchRule] = field(default_factory=list)
    expense_categories: List[str] = field(default_factory=lambda: list(DEFAULT_EXPENSE_CATEGORIES))
    merchant_memory: Dict[str, MerchantMemoryEntry] = field(default_factory=dict)
    expense_target_order: List[str] = field(
        default_factory=lambda: ["Food", "Fuel", "Groceries", "Subscription", "General", "Other"]
    )
    expense_target_pct: List[float] = field(
        default_factory=lambda: [18.0, 15.0, 22.0, 12.0, 23.0, 10.0]
    )
    last_target_submit: Optional[date] = None
    target_is_locked: bool = False
    target_unlock_events_this_month: int = 0
    last_month_scored: Optional[str] = None  # "YYYY-MM"
    last_seen_tx_month: Optional[str] = None  # "YYYY-MM"
    last_safe_to_spend: float = 0.0
    last_reserved_total: float = 0.0
    last_fund_total: float = 0.0
    last_goal_total: float = 0.0
    last_invest_total: float = 0.0
    onboarding_complete: bool = False
    tutorial_complete: bool = False
    income_baseline: float = 0.0   # EMA of recent pays — used for integrity flagging
    transfer_accounts: Dict = field(default_factory=lambda: {
        "spending": {"name": "Everyday Account", "hint": "Where your pay lands and daily spending comes from"},
        "bills": {"name": "Bills Account", "hint": "Direct debits, rent, subscriptions — auto-debited from here"},
        "savings": {"name": "Savings Account", "hint": "Sinking funds + goals — money you're building up"},
        "invest": {"name": "Investment Account", "hint": "Brokerage or high-interest account for investing"},
    })
    # Fingerprints of committed income-classified transactions awaiting user
    # confirmation to log as pay + trigger allocation. A card on the Today tab
    # surfaces each pending entry with "Log as pay" / "Dismiss" actions.
    pending_income_confirmations: List[str] = field(default_factory=list)
    # Gerald custom aliases: {"subs": "Netflix + Spotify"} — user-defined shortcuts expanded before parsing.
    gerald_aliases: Dict[str, str] = field(default_factory=dict)
    # Gerald reminders: [{"id": int, "text": str, "due_date": "YYYY-MM-DD", "created": "YYYY-MM-DD", "dismissed": bool}]
    gerald_reminders: List[Dict] = field(default_factory=list)

    def to_dict(self):
        return {
            "pay_frequency": self.pay_frequency,
            "emergency_fund_target": self.emergency_fund_target,
            "incomes": [x.to_dict() for x in self.incomes],
            "bills": [x.to_dict() for x in self.bills],
            "funds": [x.to_dict() for x in self.funds],
            "goals": [x.to_dict() for x in self.goals],
            "game": self.game.to_dict(),
            "transactions": [x.to_dict() for x in self.transactions],
            "advanced_match_rules": [x.to_dict() for x in self.advanced_match_rules],
            "expense_categories": list(self.expense_categories),
            "merchant_memory": {k: v.to_dict() for k, v in self.merchant_memory.items()},
            "expense_target_order": list(self.expense_target_order),
            "expense_target_pct": list(self.expense_target_pct),
            "last_target_submit": self.last_target_submit.isoformat() if self.last_target_submit else None,
            "target_is_locked": bool(self.target_is_locked),
            "target_unlock_events_this_month": int(self.target_unlock_events_this_month),
            "last_month_scored": self.last_month_scored,
            "last_seen_tx_month": self.last_seen_tx_month,
            "last_safe_to_spend": self.last_safe_to_spend,
            "last_reserved_total": self.last_reserved_total,
            "last_fund_total": self.last_fund_total,
            "last_goal_total": self.last_goal_total,
            "last_invest_total": self.last_invest_total,
            "onboarding_complete": self.onboarding_complete,
            "tutorial_complete": self.tutorial_complete,
            "income_baseline": self.income_baseline,
            "transfer_accounts": self.transfer_accounts,
            "pending_income_confirmations": list(self.pending_income_confirmations),
            "gerald_aliases": dict(self.gerald_aliases),
            "gerald_reminders": list(self.gerald_reminders),
        }

    @classmethod
    def from_dict(cls, data):
        raw_cats = data.get("expense_categories")
        if not raw_cats:
            merged_cats = list(DEFAULT_EXPENSE_CATEGORIES)
        else:
            merged_cats = list(raw_cats)
            for d in DEFAULT_EXPENSE_CATEGORIES:
                if not any(x.lower() == d.lower() for x in merged_cats):
                    merged_cats.append(d)
        merged_cats.sort(key=str.lower)
        mem_raw = data.get("merchant_memory") or {}
        merchant_memory = {k: MerchantMemoryEntry.from_dict(v) for k, v in mem_raw.items()}
        et_order = data.get("expense_target_order")
        if not et_order:
            et_order = ["Food", "Fuel", "Groceries", "Subscription", "General", "Other"]
        et_pct = data.get("expense_target_pct")
        if not et_pct or len(et_pct) != len(et_order):
            et_pct = [100.0 / len(et_order)] * len(et_order)
        pct_sum = sum(float(x) for x in et_pct)
        if pct_sum > 0:
            et_pct = [round(100.0 * float(x) / pct_sum, 2) for x in et_pct]
        else:
            et_pct = [100.0 / len(et_order)] * len(et_order)
        lt_raw = data.get("last_target_submit")
        last_target_submit = datetime.strptime(lt_raw, "%Y-%m-%d").date() if lt_raw else None
        target_is_locked = bool(data.get("target_is_locked", False))
        target_unlock_events_this_month = int(data.get("target_unlock_events_this_month", 0))
        last_month_scored = data.get("last_month_scored")
        last_seen_tx_month = data.get("last_seen_tx_month")
        return cls(
            data.get("pay_frequency", "fortnightly"),
            float(data.get("emergency_fund_target", 5000.0)),
            [IncomeEntry.from_dict(x) for x in data.get("incomes", [])],
            [Bill.from_dict(x) for x in data.get("bills", [])],
            [Fund.from_dict(x) for x in data.get("funds", [])],
            [Goal.from_dict(x) for x in data.get("goals", [])],
            GameStats.from_dict(data.get("game", {})),
            [TransactionRecord.from_dict(x) for x in data.get("transactions", [])],
            [AdvancedMatchRule.from_dict(x) for x in data.get("advanced_match_rules", [])],
            merged_cats,
            merchant_memory,
            list(et_order),
            et_pct,
            last_target_submit,
            target_is_locked,
            target_unlock_events_this_month,
            last_month_scored,
            last_seen_tx_month,
            float(data.get("last_safe_to_spend", 0.0)),
            float(data.get("last_reserved_total", 0.0)),
            float(data.get("last_fund_total", 0.0)),
            float(data.get("last_goal_total", 0.0)),
            float(data.get("last_invest_total", 0.0)),
            bool(data.get("onboarding_complete", False)),
            bool(data.get("tutorial_complete", False)),
            float(data.get("income_baseline", 0.0)),
            data.get("transfer_accounts", {
                "spending": {"name": "Everyday Account", "hint": "Where your pay lands and daily spending comes from"},
                "bills": {"name": "Bills Account", "hint": "Direct debits, rent, subscriptions — auto-debited from here"},
                "savings": {"name": "Savings Account", "hint": "Sinking funds + goals — money you're building up"},
                "invest": {"name": "Investment Account", "hint": "Brokerage or high-interest account for investing"},
            }),
            list(data.get("pending_income_confirmations", [])),
            dict(data.get("gerald_aliases", {})),
            list(data.get("gerald_reminders", [])),
        )


