class BudgetEngine:
    PAY_CYCLE_DAYS = {"weekly": 7, "fortnightly": 14, "monthly": 30}

    def __init__(self, state: AppState):
        self.state = state

    def current_cycle_days(self) -> int:
        return self.PAY_CYCLE_DAYS.get(self.state.pay_frequency, 14)

    def days_until(self, due_date: Optional[date]) -> int:
        if due_date is None:
            return 999999
        return (due_date - date.today()).days

    def pays_until(self, due_date: Optional[date]) -> int:
        if due_date is None:
            return 1
        days = max(self.days_until(due_date), 0)
        return max(1, math.ceil(days / self.current_cycle_days()) if days > 0 else 1)

    def bill_recommended_allocation(self, bill: Bill) -> float:
        return round(max(bill.amount - bill.current_saved, 0.0) / self.pays_until(bill.due_date), 2)

    def fund_recommended_allocation(self, fund: Fund) -> float:
        remaining = max(fund.target_amount - fund.current_saved, 0.0)
        if fund.contribution_mode == "fixed":
            return min(round(fund.fixed_amount, 2), remaining)
        return round(remaining / self.pays_until(fund.target_date), 2)

    def goal_remaining(self, goal: Goal) -> float:
        return max(goal.target_amount - goal.current_saved, 0.0)

    def next_due_date(self, due_date: date, frequency: str) -> date:
        if frequency == "monthly":
            import calendar
            month = due_date.month % 12 + 1
            year = due_date.year + (1 if due_date.month == 12 else 0)
            day = min(due_date.day, calendar.monthrange(year, month)[1])
            return due_date.replace(year=year, month=month, day=day)
        return {
            "weekly": due_date + timedelta(days=7),
            "fortnightly": due_date + timedelta(days=14),
            "yearly": due_date.replace(year=due_date.year + 1),
        }.get(frequency, due_date)

    def mark_bill_paid(self, bill: Bill):
        bill.current_saved = 0.0
        if bill.frequency != "one-off":
            while bill.due_date <= date.today():
                bill.due_date = self.next_due_date(bill.due_date, bill.frequency)

    def allocate_pay(self, pay_amount: float, *, apply: bool = False, investment_mode: str = "fixed", investment_value: float = 0.0, minimum_buffer: float = 0.0) -> dict:
        remaining = round(pay_amount, 2)
        rb = rf = rg = ri = 0.0
        bill_breakdown: list = []
        fund_breakdown: list = []
        goal_breakdown: list = []
        warnings: list[str] = []
        priority_order = {"essential": 0, "important": 1, "optional": 2}

        for idx, bill in sorted(enumerate(self.state.bills), key=lambda x: (priority_order.get(x[1].priority, 9), x[1].due_date)):
            rec = self.bill_recommended_allocation(bill)
            actual = round(min(rec, max(remaining, 0.0)), 2)
            rb += actual
            remaining -= actual
            bill_breakdown.append((idx, bill.name, actual, rec))
            if actual + 0.009 < rec:
                warnings.append(f"Bill underfunded this pay: {bill.name} needs ${rec:.2f}, allocated ${actual:.2f}.")

        for idx, fund in sorted(enumerate(self.state.funds), key=lambda x: (priority_order.get(x[1].priority, 9), self.days_until(x[1].target_date))):
            rec = self.fund_recommended_allocation(fund)
            actual = round(min(rec, max(remaining, 0.0)), 2)
            rf += actual
            remaining -= actual
            fund_breakdown.append((idx, fund.name, actual, rec))
            if actual + 0.009 < rec:
                warnings.append(f"Fund behind recommended contribution: {fund.name} needs ${rec:.2f}, allocated ${actual:.2f}.")

        for idx, goal in sorted(enumerate(self.state.goals), key=lambda x: x[1].priority):
            target = goal.value if goal.mode == "fixed" else max(remaining, 0.0) * (goal.value / 100.0)
            actual = round(min(target, self.goal_remaining(goal), max(remaining, 0.0)), 2)
            rg += actual
            remaining -= actual
            goal_breakdown.append((idx, goal.name, actual, target))
            if target > 0 and actual + 0.009 < target:
                warnings.append(f"Goal contribution reduced this pay: {goal.name} target was ${target:.2f}, allocated ${actual:.2f}.")

        invest_base = max(remaining - minimum_buffer, 0.0)
        if investment_mode == "percent":
            ri = round(min(invest_base * (investment_value / 100.0), invest_base), 2)
        else:
            ri = round(min(investment_value, invest_base), 2)
        remaining -= ri

        if apply:
            for idx, _, actual, _ in bill_breakdown:
                self.state.bills[idx].current_saved = round(min(self.state.bills[idx].amount, self.state.bills[idx].current_saved + actual), 2)
            for idx, _, actual, _ in fund_breakdown:
                self.state.funds[idx].current_saved = round(min(self.state.funds[idx].target_amount, self.state.funds[idx].current_saved + actual), 2)
            for idx, _, actual, _ in goal_breakdown:
                self.state.goals[idx].current_saved = round(min(self.state.goals[idx].target_amount, self.state.goals[idx].current_saved + actual), 2)

        self.state.last_reserved_total = round(rb, 2)
        self.state.last_fund_total = round(rf, 2)
        self.state.last_goal_total = round(rg, 2)
        self.state.last_invest_total = round(ri, 2)
        self.state.last_safe_to_spend = round(max(remaining, 0.0), 2)

        return {
            "pay_amount": round(pay_amount, 2),
            "bill_total": round(rb, 2),
            "fund_total": round(rf, 2),
            "goal_total": round(rg, 2),
            "invest_total": round(ri, 2),
            "safe_to_spend": self.state.last_safe_to_spend,
            "warnings": warnings,
            "bill_breakdown": bill_breakdown,
            "fund_breakdown": fund_breakdown,
            "goal_breakdown": goal_breakdown,
        }


class BudgetGameEngine:
    def __init__(self, state: AppState):
        self.state = state

    def level_from_score(self, score: int) -> int:
        return max(1, score // 250 + 1)

    def _expense_mix_match_bonus(self) -> tuple[int, list[str]]:
        """Bonus for how close last calendar month's spending mix was to a *submitted* target mix.

        The mix bonus only applies if the user has submitted the target mix. After the first day
        without a submission, the maximum potential bonus decays gradually until it reaches zero.
        """
        labels = self.state.expense_target_order
        targets = self.state.expense_target_pct
        if not labels or len(labels) != len(targets):
            return 0, ["Expense mix vs target: +0 (no usable target mix yet)."]

        if not self.state.last_target_submit:
            return 0, ["Expense mix vs target: +0 (submit a target mix on the Score tab to start scoring)."]

        today = date.today()
        days_since = max((today - self.state.last_target_submit).days, 0)

        start, end = previous_calendar_month_window(today)
        amounts = outgoing_category_totals(self.state.transactions, start, end)
        total_amt = sum(amounts.values())
        if total_amt <= 0:
            return 0, [f"Expense mix vs target: +0 (need committed outgoing data for {start.isoformat()}–{end.isoformat()})."]

        lo = [x.lower() for x in labels]
        bucket: Dict[str, float] = {lo[i]: 0.0 for i in range(len(lo))}
        other_key = "other" if "other" in bucket else None
        for cat, amt in amounts.items():
            cl = cat.lower()
            if cl in bucket:
                bucket[cl] += amt
            elif other_key is not None:
                bucket[other_key] += amt
            else:
                bucket[lo[-1]] += amt

        actual_vec = [100.0 * bucket[lo[i]] / total_amt for i in range(len(lo))]
        d = sum(abs(actual_vec[i] - targets[i]) for i in range(len(lo)))

        base_bonus = max(0, min(35, round(35 * (1.0 - d / 200.0))))
        if days_since <= 1:
            decay_factor = 1.0
        else:
            # After the first day without a submission, decay over the next 14 days to zero.
            decay_days = 14.0
            decay_factor = max(0.0, 1.0 - (days_since - 1) / decay_days)
        final_bonus = int(round(base_bonus * decay_factor))

        lines = [
            f"Expense mix vs target (last month {start.isoformat()}–{end.isoformat()}): +{final_bonus}",
            f"- Mix distance: {d:.1f} (lower is closer to your target pie)",
            f"- Target last submitted: {self.state.last_target_submit.isoformat()} (days since submit: {days_since})",
        ]
        if final_bonus < base_bonus:
            lines.append(f"- Daily decay cap reduced bonus from {base_bonus} to {final_bonus} (submit a fresh target to reset).")
        return final_bonus, lines

    def score_month_end_mix(self, year: int, month: int) -> tuple[int, list[str]]:
        """Score the *full month* mix bonus once, for (year, month) using committed transactions."""
        start = date(year, month, 1)
        if month == 12:
            end = date(year + 1, 1, 1) - timedelta(days=1)
        else:
            end = date(year, month + 1, 1) - timedelta(days=1)
        bonus, lines = self._expense_mix_match_bonus()
        # Rewrite first line to explicitly say month-end score.
        lines = [f"Month-end mix score for {start.strftime('%b %Y')}: {lines[0].split(':', 1)[-1].strip()}"] + lines[1:]
        return bonus, lines

    # ── Progression Systems ───────────────────────────────────────────────────

    def ensure_season(self):
        """Start or reset the season if the calendar month has changed."""
        current_ym = date.today().strftime("%Y-%m")
        g = self.state.game
        if g.season_year_month != current_ym:
            g.season_year_month = current_ym
            g.season_xp = 0
            g.season_claimed_tiers = []
            g.perks_unlocked = [p for p in g.perks_unlocked if p != "season_boost"]

    def add_season_xp(self, amount: int) -> List[int]:
        """Add Season XP (with Scholar bonus). Returns newly claimable tier indices."""
        g = self.state.game
        self.ensure_season()
        bonus = 1.25 if "season_boost" in g.perks_unlocked else 1.0
        g.season_xp += max(1, int(round(amount * bonus)))
        return [i for i, (xp, _, _, _) in enumerate(SEASON_TIERS)
                if g.season_xp >= xp and i not in g.season_claimed_tiers]

    def claim_season_tier(self, tier_idx: int) -> dict:
        """Claim a season tier reward. Returns reward info dict or empty if not claimable."""
        g = self.state.game
        if tier_idx in g.season_claimed_tiers or tier_idx >= len(SEASON_TIERS):
            return {}
        xp_threshold, reward_type, reward_amount, tier_name = SEASON_TIERS[tier_idx]
        if g.season_xp < xp_threshold:
            return {}
        g.season_claimed_tiers.append(tier_idx)
        if reward_type == "gold":
            g.total_score += reward_amount
            g.level = self.level_from_score(g.total_score)
        elif reward_type == "gems":
            g.gems += reward_amount
            g.lifetime_gems_earned += reward_amount
        return {"tier_name": tier_name, "reward_type": reward_type, "reward_amount": reward_amount}

    def generate_daily_challenges(self):
        """Generate 3 daily challenges if not already done today."""
        import random
        g = self.state.game
        today_str = date.today().isoformat()
        if g.daily_challenges_date == today_str and len(g.daily_challenges) == 3:
            return
        picked = random.sample(CHALLENGE_POOL, min(3, len(CHALLENGE_POOL)))
        g.daily_challenges = [
            {"id": c[0], "description": c[1], "trigger": c[2],
             "reward_type": c[3], "reward_amount": c[4], "completed": False}
            for c in picked
        ]
        g.daily_challenges_date = today_str

    def complete_challenge(self, trigger: str) -> List[dict]:
        """Mark matching incomplete challenges done and award rewards."""
        g = self.state.game
        completed = []
        for ch in g.daily_challenges:
            if ch.get("trigger") == trigger and not ch.get("completed"):
                ch["completed"] = True
                if ch["reward_type"] == "gold":
                    g.total_score += ch["reward_amount"]
                    g.level = self.level_from_score(g.total_score)
                elif ch["reward_type"] == "gems":
                    g.gems += ch["reward_amount"]
                    g.lifetime_gems_earned += ch["reward_amount"]
                self.add_season_xp(15)
                completed.append(dict(ch))
        return completed

    def draw_fortune_card(self) -> dict:
        """Draw a weighted random fortune card and apply its effect."""
        import random
        g = self.state.game
        cards = list(FORTUNE_CARDS)
        if "fortune_up" in g.perks_unlocked:
            cards = [(t, s, tx, eff, amt, int(w * 1.3) if eff != "none" else max(1, w - 5))
                     for t, s, tx, eff, amt, w in cards]
        weights = [c[5] for c in cards]
        title, symbol, text, effect_type, effect_amount, _ = random.choices(cards, weights=weights, k=1)[0]
        if effect_type == "gold":
            g.total_score += effect_amount
            g.level = self.level_from_score(g.total_score)
        elif effect_type == "gems":
            g.gems += effect_amount
            g.lifetime_gems_earned += effect_amount
        elif effect_type == "season_xp":
            self.add_season_xp(effect_amount)
        elif effect_type == "buff_double_mix":
            if "double_mix" not in g.active_buffs:
                g.active_buffs.append("double_mix")
        elif effect_type == "buff_streak_shield":
            g.streak_shields += 1
        return {"title": title, "symbol": symbol, "text": text,
                "effect_type": effect_type, "effect_amount": effect_amount}

    def _perk_multiplier_bonus(self) -> float:
        return self.state.game.perks_unlocked.count("score_boost") * 0.10

    def buy_perk(self, perk_id: str) -> tuple:
        """Buy a perk. Returns (success: bool, message: str)."""
        g = self.state.game
        perk = next((p for p in PERK_SHOP_ITEMS if p[0] == perk_id), None)
        if not perk:
            return False, "Unknown perk."
        pid, name, _, gem_cost, max_stacks = perk
        if g.perks_unlocked.count(perk_id) >= max_stacks:
            return False, f"{name} is already at max level."
        if g.gems < gem_cost:
            return False, f"Not enough Gems. Need {gem_cost}, have {g.gems}."
        g.gems -= gem_cost
        g.perks_unlocked.append(perk_id)
        if perk_id == "score_boost":
            g.score_multiplier = round(1.0 + g.prestige_level * 0.10 + self._perk_multiplier_bonus(), 2)
        elif perk_id == "streak_shield":
            g.streak_shields += 1
        return True, f"{name} purchased!"

    def check_card_set_completions(self) -> list:
        """Check all card sets and auto-unlock any completed set rewards.
        Returns list of (set_name, reward_item_name) for newly completed sets."""
        g = self.state.game
        unique_owned = set(g.cards_owned)
        newly_completed = []
        for sid, sname, sdesc, card_ids, reward_item_id in CARD_SETS:
            if reward_item_id in g.character_items_owned:
                continue  # already claimed
            if all(cid in unique_owned for cid in card_ids):
                g.character_items_owned.append(reward_item_id)
                item = AVATAR_ITEMS.get(reward_item_id, {})
                newly_completed.append((sname, item.get("name", reward_item_id)))
        return newly_completed

    def card_set_progress(self) -> dict:
        """Return completion progress for all card sets.
        Returns {set_id: (owned_count, total_count, is_complete, reward_claimed)}"""
        g = self.state.game
        unique_owned = set(g.cards_owned)
        result = {}
        for sid, sname, sdesc, card_ids, reward_item_id in CARD_SETS:
            owned_count = sum(1 for cid in card_ids if cid in unique_owned)
            total = len(card_ids)
            complete = owned_count == total
            claimed = reward_item_id in g.character_items_owned
            result[sid] = (owned_count, total, complete, claimed)
        return result

    def buy_avatar_item(self, item_id: str) -> tuple:
        """Buy an avatar cosmetic. Returns (success, message)."""
        g = self.state.game
        item = AVATAR_ITEMS.get(item_id)
        if not item:
            return False, "Unknown item."
        if item_id in g.character_items_owned:
            return False, "Already owned."
        req = item.get("unlock_req")
        if req:
            t, v = req["type"], req["value"]
            if t == "level" and g.level < v:
                return False, f"Requires Level {v}."
            if t == "achievement" and v not in g.achievements:
                return False, f"Requires achievement: {v}."
            if t == "streak" and g.best_streak < v:
                return False, f"Requires best streak of {v}."
            if t == "prestige" and g.prestige_level < v:
                return False, f"Requires Prestige {v}."
            if t == "card_set":
                # Card set items can't be bought — auto-awarded on set completion
                return False, f"Complete the '{v.replace('set_', '').title()}' card set to unlock."
        ct, cost = item["cost_type"], item["cost"]
        if ct == "gold":
            if g.total_score < cost:
                return False, f"Need {cost} Gold (have {g.total_score})."
            g.total_score -= cost
            g.level = max(1, g.total_score // 250 + 1)
        elif ct == "gems":
            if g.gems < cost:
                return False, f"Need {cost} Gems (have {g.gems})."
            g.gems -= cost
        g.character_items_owned.append(item_id)
        return True, f"Unlocked: {item['name']}!"

    def equip_avatar_item(self, item_id: str) -> tuple:
        """Equip an owned avatar item. Returns (success, message)."""
        g = self.state.game
        if item_id not in g.character_items_owned:
            return False, "Item not owned."
        item = AVATAR_ITEMS.get(item_id)
        if not item:
            return False, "Unknown item."
        g.character_equipped[item["slot"]] = item_id
        return True, f"Equipped {item['name']}."

    def unequip_avatar_slot(self, slot: str) -> tuple:
        """Clear an equipment slot. Returns (success, message)."""
        g = self.state.game
        if slot not in g.character_equipped or not g.character_equipped.get(slot):
            return False, "Slot is already empty."
        g.character_equipped[slot] = ""
        return True, f"Unequipped {slot}."

    def open_pack(self, pack_type_id: str) -> dict:
        """Purchase and open a card pack. Returns {success, message, cards, cost_type, cost}."""
        import random
        g = self.state.game
        pack_data = next((p for p in PACK_TYPES if p[0] == pack_type_id), None)
        if not pack_data:
            return {"success": False, "message": "Unknown pack type.", "cards": []}
        _, name, _, cost_type, cost, card_count, rarity_weights, _ = pack_data
        # Check affordability
        if cost_type == "gold":
            if g.total_score < cost:
                return {"success": False, "message": f"Need {cost} Gold (you have {g.total_score}).", "cards": []}
            g.total_score -= cost
            # Recalc level
            g.level = max(1, g.total_score // 250 + 1)
        else:  # gems
            if g.gems < cost:
                return {"success": False, "message": f"Need {cost} Gems (you have {g.gems}).", "cards": []}
            g.gems -= cost
        # Draw cards
        rarities = list(rarity_weights.keys())
        weights = list(rarity_weights.values())
        pool_by_rarity: dict = {}
        for cid, cname, crarity, *_ in CARD_POOL:
            pool_by_rarity.setdefault(crarity, []).append((cid, cname, crarity) + tuple(_))
        drawn = []
        for _ in range(card_count):
            chosen_rarity = random.choices(rarities, weights=weights, k=1)[0]
            pool = pool_by_rarity.get(chosen_rarity, [])
            if not pool:
                # fallback to common
                pool = pool_by_rarity.get("common", list(CARD_POOL))
            card = random.choice(pool)
            drawn.append(card)
            g.cards_owned.append(card[0])
            # Apply bonus if card has one and is first copy
            if g.cards_owned.count(card[0]) == 1 and card[5]:
                bonus = card[5]
                if "+Gold" in bonus or "Gold bonus" in bonus:
                    try:
                        amt = int("".join(c for c in bonus if c.isdigit()))
                        g.total_score += amt
                    except Exception:
                        pass
                elif "+Gems" in bonus or "+1 Gem" in bonus:
                    try:
                        amt = int("".join(c for c in bonus if c.isdigit()))
                        g.gems += amt
                        g.lifetime_gems_earned += amt
                    except Exception:
                        pass
                elif "+Season XP" in bonus:
                    try:
                        amt = int("".join(c for c in bonus if c.isdigit()))
                        g.season_xp += amt
                    except Exception:
                        pass
        g.packs_opened += 1
        # Achievement: first pack
        if g.packs_opened == 1 and "Pack Hunter" not in g.achievements:
            g.achievements.append("Pack Hunter")
        # Achievement: 5 packs
        if g.packs_opened >= 5 and "Fortune's Favourite" not in g.achievements:
            g.achievements.append("Fortune's Favourite")
        # Check card set completions — auto-claim rewards
        set_completions = self.check_card_set_completions()
        return {"success": True, "message": f"Opened {name}!", "cards": drawn,
                "cost_type": cost_type, "cost": cost,
                "set_completions": set_completions}

    def recycle_duplicate(self, card_id: str) -> dict:
        """Recycle one duplicate copy of a card for 1 Gem."""
        g = self.state.game
        if g.cards_owned.count(card_id) < 2:
            return {"success": False, "message": "You need at least 2 copies to recycle a duplicate."}
        g.cards_owned.remove(card_id)
        g.gems += 1
        g.lifetime_gems_earned += 1
        card = CARD_BY_ID.get(card_id)
        name = card[1] if card else card_id
        return {"success": True, "message": f"Recycled duplicate '{name}' for +1 Gem."}

    def prestige(self):
        """Reset score to 0, grant prestige level and permanent score multiplier."""
        g = self.state.game
        g.prestige_level += 1
        g.score_multiplier = round(1.0 + g.prestige_level * 0.10 + self._perk_multiplier_bonus(), 2)
        g.total_score = 0
        g.level = 1
        ach = f"Prestige {g.prestige_level}"
        if ach not in g.achievements:
            g.achievements.append(ach)

    def _check_achievements(self, is_good_pay: bool):
        """Check and award all achievement chains."""
        g = self.state.game
        for milestone, title in [(3, "Streak Starter"), (7, "Streak Builder"), (14, "Streak Master"), (30, "Streak Legend")]:
            if g.streak_pays >= milestone and title not in g.achievements:
                g.achievements.append(title)
        for threshold, title in [(500, "500 Score Club"), (1000, "1,000 Score Club"), (2500, "2,500 Score Club")]:
            if g.total_score >= threshold and title not in g.achievements:
                g.achievements.append(title)
        for count, title in [(1, "First Pay Processed"), (10, "10 Pays Processed"), (52, "Veteran Budgeter")]:
            if g.total_pays_processed >= count and title not in g.achievements:
                g.achievements.append(title)
        for gems_threshold, title in [(10, "Gem Collector"), (50, "Gem Hoarder")]:
            if g.lifetime_gems_earned >= gems_threshold and title not in g.achievements:
                g.achievements.append(title)

    def _update_income_baseline(self, pay_amount: float):
        """Exponential moving average of income. Called from UI after each pay."""
        b = self.state.income_baseline
        if b <= 0:
            self.state.income_baseline = pay_amount
        else:
            # 80% weight on existing baseline, 20% on new — slow drift, resistant to one-off spikes
            self.state.income_baseline = round(0.80 * b + 0.20 * pay_amount, 2)

    def score_pay(self, pay_amount: float, allocation: dict) -> dict:
        g = self.state.game
        today_str = date.today().isoformat()

        # ── Integrity: same-day duplicate limit ───────────────────────────────
        # After the first 2 pays (learning phase), cap any second pay on the same calendar day
        # at 10 points. This prevents rapid-entry farming while allowing legitimate same-day use.
        already_scored_today = (g.last_pay_scored_date == today_str and g.total_pays_processed >= 2)

        reserved = allocation["bill_total"] + allocation["fund_total"] + allocation["goal_total"] + allocation["invest_total"]
        ratio = 0 if pay_amount <= 0 else reserved / pay_amount
        base_points = min(int(ratio * 100), 40)
        breakdown = [f"Saved/reserved ratio bonus: +{base_points}"]
        if ratio >= 0.10:
            base_points += 10; breakdown.append("Reserved at least 10%: +10")
        if ratio >= 0.25:
            base_points += 15; breakdown.append("Reserved at least 25%: +15")
        if ratio >= 0.40:
            base_points += 20; breakdown.append("Reserved at least 40%: +20")
        penalty = len(allocation["warnings"]) * 8
        if penalty:
            base_points -= penalty; breakdown.append(f"Warnings penalty: -{penalty}")
        base_points = max(base_points, 0)

        # ── Integrity: cap same-day repeat scoring ────────────────────────────
        if already_scored_today:
            base_points = min(base_points, 10)
            breakdown.append("Integrity cap: second pay scored today — points limited to 10 (one full-score pay per day).")

        # ── Integrity: flag abnormally large pays vs established baseline ─────
        baseline = self.state.income_baseline
        if baseline > 0 and pay_amount > baseline * 4.0:
            breakdown.append(
                f"Note: This pay (${pay_amount:,.0f}) is significantly larger than your typical "
                f"pay of ~${baseline:,.0f}. Scoring is ratio-based so Gold earned is proportional — "
                f"but the streak count depends on consistent real behaviour over time."
            )

        # Double-mix buff (consumed on use)
        mix_bonus, mix_lines = self._expense_mix_match_bonus()
        if "double_mix" in g.active_buffs:
            mix_bonus *= 2
            g.active_buffs.remove("double_mix")
            breakdown.append("Double Mix buff active! Mix points doubled.")
        base_points += mix_bonus
        breakdown.extend(mix_lines)

        # Score multiplier from prestige + perks
        points = base_points
        if g.score_multiplier > 1.0:
            points = int(round(base_points * g.score_multiplier))
            breakdown.append(f"Score multiplier x{g.score_multiplier:.1f}: {base_points} -> {points}")

        # Streak: threshold uses pre-multiplier points to stay meaningful
        is_good_pay = base_points >= 35
        if not is_good_pay and g.streak_shields > 0:
            g.streak_shields -= 1
            is_good_pay = True
            breakdown.append(f"Streak Shield activated! Shields left: {g.streak_shields}")

        g.total_pays_processed += 1
        g.last_pay_scored_date = today_str
        g.last_score_gain = points
        g.total_score += points
        g.streak_pays = g.streak_pays + 1 if is_good_pay else 0
        g.best_streak = max(g.best_streak, g.streak_pays)
        g.streak_history.append(is_good_pay)
        if len(g.streak_history) > 30:
            g.streak_history = g.streak_history[-30:]  # keep last 30

        # Gems from streaks
        gems_earned = 0
        if g.streak_pays >= 3:
            gems_earned += 1
            breakdown.append(f"+1 Gem (streak of {g.streak_pays})")
        if g.streak_pays in (5, 10, 15, 20, 25, 30):
            gems_earned += 2
            breakdown.append(f"+2 Gems (streak milestone: {g.streak_pays}!)")
        if "gem_magnet" in g.perks_unlocked and g.streak_pays >= 1:
            gems_earned += 1
            breakdown.append("+1 Gem (Gem Magnet perk)")
        if gems_earned:
            g.gems += gems_earned
            g.lifetime_gems_earned += gems_earned

        # Season XP
        season_xp_gain = 20 + (10 if is_good_pay else 0)
        self.add_season_xp(season_xp_gain)
        if is_good_pay:
            breakdown.append("+10 bonus Season XP (good pay)")

        prev = g.level
        g.level = self.level_from_score(g.total_score)
        self._check_achievements(is_good_pay)

        # Daily challenge checks
        completed_challenges = self.complete_challenge("pay")
        if ratio >= 0.40:
            completed_challenges += self.complete_challenge("pay_40")
        if is_good_pay:
            completed_challenges += self.complete_challenge("pay_35")
        if g.streak_pays >= 1:
            completed_challenges += self.complete_challenge("streak")

        return {
            "points": points,
            "level_up": g.level > prev,
            "breakdown": breakdown,
            "gems_earned": gems_earned,
            "completed_challenges": completed_challenges,
        }


class PDFTransactionImporter:
    DATE_RE = re.compile(r"^(\d{1,2}\s+[A-Za-z]{3}\s+\d{4})\s+(.*)$")
    MONEY_RE = re.compile(r"-?\$?[\d,]+\.\d{2}")

    def read_pdf_text(self, path: Path) -> str:
        try:
            from pypdf import PdfReader  # type: ignore
            reader = PdfReader(str(path))
            return "\n".join(page.extract_text() or "" for page in reader.pages)
        except Exception as exc:
            raise RuntimeError(f"Could not read PDF text. Install pypdf. {exc}")

    def parse_amount(self, text: str) -> float:
        return float(text.replace("$", "").replace(",", "").strip())

    def normalize_desc(self, desc: str) -> str:
        return normalize_desc_text(desc)

    def fingerprint(self, tx_date: date, desc: str, amount: float, direction: str) -> str:
        return f"{tx_date.isoformat()}|{direction}|{amount:.2f}|{self.normalize_desc(desc).lower()}"

    def extract_transactions(self, path: Path) -> tuple[list[TransactionRecord], list[str]]:
        text = self.read_pdf_text(path)
        lines = [ln.rstrip() for ln in text.splitlines() if ln.strip()]
        candidates: List[str] = []
        qa: List[str] = []
        for line in lines:
            if re.match(r"^\d{1,2}\s+[A-Za-z]{3}\s+\d{4}\s+", line):
                candidates.append(line)
            elif candidates and not re.match(r"^(Date|Description|Money in|Money out|Balance|Page )", line):
                if not re.match(r"^(Transaction history|Current balance|Available balance|Account )", line):
                    candidates[-1] += " " + line.strip()

        out: List[TransactionRecord] = []
        seen = set()
        for raw in candidates:
            m = self.DATE_RE.match(raw)
            if not m:
                qa.append(f"Skipped row, no date match: {raw}")
                continue
            date_text, tail = m.group(1), m.group(2)
            monies = self.MONEY_RE.findall(tail)
            if len(monies) < 2:
                qa.append(f"Skipped row, not enough money columns: {raw}")
                continue
            try:
                tx_date = datetime.strptime(date_text, "%d %b %Y").date()
            except ValueError:
                qa.append(f"Skipped row, bad date: {raw}")
                continue
            balance_text = monies[-1]
            amount_text = monies[0]
            try:
                amount = abs(self.parse_amount(amount_text))
                balance = self.parse_amount(balance_text)
            except ValueError:
                qa.append(f"Skipped row, bad money parse: {raw}")
                continue
            desc = tail
            for part in monies:
                desc = desc.replace(part, " ")
            desc = self.normalize_desc(desc) or "Unknown Transaction"
            direction = "out" if amount_text.strip().startswith("-") else "in"
            fp = self.fingerprint(tx_date, desc, amount, direction)
            if fp in seen:
                continue
            seen.add(fp)
            rec = TransactionRecord(tx_date, desc, money_in=amount if direction == "in" else 0.0, money_out=amount if direction == "out" else 0.0, balance=balance, source_file=path.name, fingerprint=fp)
            out.append(rec)
        qa.insert(0, f"Rows detected: {len(candidates)}")
        qa.insert(1, f"Transactions parsed: {len(out)}")
        return out, qa


class TransactionMatcher:
    def __init__(self, state: AppState):
        self.state = state

    def classify_category(self, desc: str, direction: str = "out") -> str:
        # First, check merchant memory for a previously verified category
        mem_key = normalize_merchant_key(desc)
        if mem_key in self.state.merchant_memory:
            mem = self.state.merchant_memory[mem_key]
            if mem.direction == direction and mem.category:
                return mem.category
        desc_l = desc.lower()
        if any(k in desc_l for k in ["coles", "woolworths", "aldi", "iga", "foodworks", "costco"]):
            return "Groceries"
        if any(k in desc_l for k in ["bp ", "ampol", "shell", "7-eleven", "caltex", "united petro", "puma energy"]):
            return "Fuel"
        if any(k in desc_l for k in ["netflix", "spotify", "microsoft", "apple.com", "google play", "adobe", "amazon prime", "stan ", "binge", "foxtel", "paramount"]):
            return "Subscription"
        if any(k in desc_l for k in ["mcdonald", "kfc", "subway", "hungry jack", "domino", "pizza", "uber eat", "deliveroo", "doordash", "menulog"]):
            return "Food"
        if any(k in desc_l for k in ["woolworths petrol", "coles express"]):
            return "Fuel"
        if direction == "in":
            return "Income"
        return "General"

    def _name_match(self, desc: str, name: str) -> bool:
        parts = [p for p in re.split(r"\W+", name.lower()) if len(p) >= 3]
        desc_l = desc.lower()
        return any(p in desc_l for p in parts)

    def merchant_key(self, tx: TransactionRecord) -> str:
        return merchant_group_key(tx.description)

    def summarize_import_insights(self, transactions: List[TransactionRecord]) -> dict:
        merchant_counts: Dict[str, int] = {}
        merchant_samples: Dict[str, str] = {}
        merchant_amounts: Dict[str, List[float]] = {}
        unusual: List[str] = []
        new_merchants: List[str] = []
        known_memory = {merchant_group_key(k) for k in self.state.merchant_memory.keys()}
        known_rules = {merchant_group_key(r.keyword) for r in self.state.advanced_match_rules if r.keyword}
        committed_by_merchant: Dict[str, List[float]] = {}
        for tx in self.state.transactions:
            if tx.direction() != "out" or tx.matched_type == "ignore":
                continue
            committed_by_merchant.setdefault(self.merchant_key(tx), []).append(tx.money_out)

        for tx in transactions:
            if tx.direction() != "out" or tx.matched_type == "ignore":
                continue
            key = self.merchant_key(tx)
            merchant_counts[key] = merchant_counts.get(key, 0) + 1
            merchant_samples.setdefault(key, extract_merchant_name(tx.description))
            merchant_amounts.setdefault(key, []).append(tx.money_out)
            history = committed_by_merchant.get(key, [])
            if history:
                avg = sum(history) / len(history)
                if avg > 0 and tx.money_out >= avg * 1.8 and tx.money_out - avg >= 20:
                    unusual.append(f"{merchant_samples[key]} looks high: ${tx.money_out:,.2f} vs usual ${avg:,.2f}")
            elif key not in known_memory and key not in known_rules:
                if merchant_samples[key] not in new_merchants:
                    new_merchants.append(merchant_samples[key])

        recurring = []
        for key, count in merchant_counts.items():
            amounts = merchant_amounts.get(key, [])
            if count >= 2:
                spread = max(amounts) - min(amounts) if amounts else 0.0
                avg = sum(amounts) / max(len(amounts), 1)
                if avg > 0 and spread <= max(3.0, avg * 0.12):
                    recurring.append(f"{merchant_samples[key]} appears recurring ({count} charges around ${avg:,.2f})")

        recurring.sort()
        unusual.sort()
        new_merchants.sort()
        return {
            "recurring": recurring[:5],
            "unusual": unusual[:5],
            "new_merchants": new_merchants[:8],
        }

    def match(self, tx: TransactionRecord) -> TransactionRecord:
        desc_l = tx.description.lower()
        for rule in self.state.advanced_match_rules:
            if not rule.is_active:
                continue
            kw = rule.keyword.lower().strip()
            matched = False
            if rule.rule_type == "exact" and kw and desc_l == kw:
                matched = True
            elif rule.rule_type == "contains" and kw and kw in desc_l:
                matched = True
            elif rule.rule_type == "amount_contains" and kw and kw in desc_l and abs(tx.amount() - rule.amount) <= 2.0:
                matched = True
            if matched:
                tx.matched_type = rule.matched_type
                tx.matched_target = rule.matched_target
                tx.category = rule.category or self.classify_category(tx.description, tx.direction())
                tx.confidence = "manual"
                tx.needs_review = False
                tx.user_verified = True
                tx.notes = f"Matched by rule: {rule.rule_name}"
                return tx

        mem_key = normalize_merchant_key(tx.description)
        if mem_key in self.state.merchant_memory:
            mem = self.state.merchant_memory[mem_key]
            if mem.direction == tx.direction():
                tx.matched_type = mem.matched_type
                tx.matched_target = mem.matched_target
                tx.category = mem.category or self.classify_category(tx.description, tx.direction())
                tx.confidence = "memory"
                tx.needs_review = False
                tx.user_verified = True
                tx.notes = "Matched from saved merchant/category memory"
                return tx

        if tx.money_in > 0:
            tx.matched_type = "income"
            tx.category = "income"
            tx.confidence = "low"
            tx.needs_review = True
            tx.user_verified = False
            return tx

        for bill in self.state.bills:
            if self._name_match(tx.description, bill.name) or (abs(tx.money_out - bill.amount) <= 2.0 and abs((tx.tx_date - bill.due_date).days) <= 45):
                tx.matched_type = "linked_bill"
                tx.matched_target = bill.name
                tx.category = bill.category
                tx.confidence = "medium"
                tx.needs_review = True
                tx.user_verified = False
                return tx

        for fund in self.state.funds:
            if self._name_match(tx.description, fund.name):
                tx.matched_type = "linked_fund"
                tx.matched_target = fund.name
                tx.category = fund.category
                tx.confidence = "medium"
                tx.needs_review = True
                tx.user_verified = False
                return tx

        tx.matched_type = "discretionary"
        tx.category = self.classify_category(tx.description, tx.direction())
        tx.confidence = "low"
        tx.needs_review = True
        tx.user_verified = False
        return tx


# -----------------------------
# Gerald — Conversational Setup Assistant (rule-based)
# -----------------------------

_GERALD_FREQ_PATTERNS = [
    (r"\b(one[- ]?off|one[- ]?time|onetime|just once|only once|once off)\b", "one-off"),
    (r"\b(fortnightly|bi[- ]?weekly|every (?:two|2) weeks?|every fortnight|fortnight)\b", "fortnightly"),
    (r"\b(weekly|per week|each week|every week|a week)\b", "weekly"),
    (r"\b(monthly|per month|each month|every month|a month)\b", "monthly"),
    (r"\b(yearly|annually|per year|each year|every year|a year|annual)\b", "yearly"),
]

_GERALD_PRIORITY_PATTERNS = [
    (r"\b(essential|critical|must[- ]have|required|mandatory|core)\b", "essential"),
    (r"\b(important|normal|standard|regular)\b", "important"),
    (r"\b(optional|nice[- ]to[- ]have|low priority|skippable|maybe)\b", "optional"),
]

_GERALD_MONTHS = {
    "january": 1, "jan": 1, "february": 2, "feb": 2, "march": 3, "mar": 3,
    "april": 4, "apr": 4, "may": 5, "june": 6, "jun": 6, "july": 7, "jul": 7,
    "august": 8, "aug": 8, "september": 9, "sep": 9, "sept": 9,
    "october": 10, "oct": 10, "november": 11, "nov": 11, "december": 12, "dec": 12,
}

_GERALD_WEEKDAYS = {
    "monday": 0, "mon": 0, "tuesday": 1, "tue": 1, "tues": 1,
    "wednesday": 2, "wed": 2, "thursday": 3, "thu": 3, "thurs": 3,
    "friday": 4, "fri": 4, "saturday": 5, "sat": 5, "sunday": 6, "sun": 6,
}

_GERALD_STOP_TOKENS = {
    "a", "an", "the", "for", "at", "on", "by", "of", "with", "to", "from", "and",
    "bill", "bills", "fund", "funds", "goal", "goals", "sinking", "my",
    "add", "new", "create", "make", "set", "setup", "save", "up", "put",
    "contribute", "deposit", "toward", "towards", "into",
    "pay", "income", "paycheck", "paychecks", "wage", "wages",
    "got", "just", "paid", "me", "log", "received", "came", "in", "i",
    "dollars", "dollar", "bucks", "usd", "aud",
    "please", "thanks", "thank", "you", "can",
    "priority", "due", "target", "amount", "each", "every", "per",
    "would", "like", "want", "need", "have",
}

_GERALD_WRITTEN_NUMBERS = {
    "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5,
    "six": 6, "seven": 7, "eight": 8, "nine": 9, "ten": 10,
    "eleven": 11, "twelve": 12, "thirteen": 13, "fourteen": 14, "fifteen": 15,
    "sixteen": 16, "seventeen": 17, "eighteen": 18, "nineteen": 19,
    "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50, "sixty": 60,
    "seventy": 70, "eighty": 80, "ninety": 90,
    "hundred": 100, "thousand": 1000, "million": 1_000_000,
}

_GERALD_NUMBER_WORD_PATTERN = re.compile(
    r"\b(?:(?:zero|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve|"
    r"thirteen|fourteen|fifteen|sixteen|seventeen|eighteen|nineteen|twenty|thirty|"
    r"forty|fifty|sixty|seventy|eighty|ninety|hundred|thousand|million)"
    r"(?:[\s-]+(?:and\s+)?)?){1,6}\b",
    re.IGNORECASE,
)


def _gerald_parse_written_number(phrase: str):
    words = re.findall(r"[a-z]+", phrase.lower().replace("-", " "))
    total, current = 0, 0
    found = False
    for w in words:
        if w == "and":
            continue
        if w in _GERALD_WRITTEN_NUMBERS:
            found = True
            val = _GERALD_WRITTEN_NUMBERS[w]
            if val >= 1000:
                current = max(current, 1) * val
                total += current
                current = 0
            elif val == 100:
                current = max(current, 1) * val
            else:
                current += val
    return (total + current) if found else None


