class GeraldAssistant:
    """Rule-based conversational setup assistant.

    Parses user intents and extracts entities to create bills, funds,
    goals, and incomes via natural language. Stateful slot-filling for
    multi-turn flows with explicit confirm-before-apply and undo.
    """

    INTENT_LABELS = {
        "add_bill":     "add a bill",
        "add_fund":     "add a fund",
        "add_goal":     "add a goal",
        "add_income":   "log a pay",
    }

    REQUIRED_SLOTS = {
        "add_bill":   ["name", "amount", "frequency", "due_date"],
        "add_fund":   ["name", "target_amount"],
        "add_goal":   ["name", "target_amount"],
        "add_income": ["amount", "received_on"],
    }

    OPTIONAL_SLOTS = {
        "add_bill":   ["priority"],
        "add_fund":   ["target_date", "priority"],
        "add_goal":   ["target_date", "priority"],
        "add_income": ["source"],
    }

    SLOT_PROMPTS = {
        "name":          "What's the name?",
        "amount":        "How much? (e.g. $15 or 1500)",
        "target_amount": "What's the target amount? (e.g. $5000)",
        "frequency":     "How often — weekly, fortnightly, monthly, yearly, or one-off?",
        "due_date":      "When's the next due date? (e.g. \"25th\", \"next friday\", \"2026-05-01\")",
        "received_on":   "What date? (\"today\", \"yesterday\", or YYYY-MM-DD)",
    }

    def __init__(self, app):
        self.app = app
        self.transcript: list = []   # [{"role": "user"|"gerald", "text": str, "expression": str}]
        self.pending: dict = {}      # {"intent": str, "slots": {...}, "awaiting": "confirm" | "slot:NAME" | None}
        self.undo_stack: list = []   # [{"kind": "bill"|"fund"|"goal"|"income", "index": int, "snapshot": obj, "label": str}, ...]
        # Last item the user or Gerald acted on — enables "contribute $50" w/o name
        # after "show me Holiday fund", etc. Stored as (kind, index).
        self.last_target: tuple | None = None
        # Last list shown to the user (for pronoun resolution: "the first one", "the second").
        # Stored as [(kind, idx), ...] in display order.
        self.last_list: list = []
        # Last time we fired a proactive alert — rate-limit per app session.
        self._last_alert_ts: float = 0.0
        # Mute flag — "be quiet" / "stop alerts" turns this on; "alerts on" clears it.
        self._alerts_muted: bool = False
        self._say(
            "Hey — I'm Gerald. Tell me what to add: bills, funds, goals, or a pay. "
            "Natural phrasing works — \"add bill Netflix $15 monthly due 25th\" or "
            "\"I got paid $2500 today\". Type \"help\" for the menu.",
            "wink",
        )
        # Flag so the first contextual greet only fires once per session
        self._contextual_opened = False
        # Track whether we've already scanned reminders this session so we don't
        # repeatedly fire due-reminder toasts on every interaction.
        self._reminders_scanned = False

    # ── Last-target memory ───────────────────────────────────────────────────

    def _set_last_target(self, kind: str, idx: int) -> None:
        """Remember the most recently referenced bill/fund/goal."""
        if kind in ("bill", "fund", "goal") and isinstance(idx, int) and idx >= 0:
            self.last_target = (kind, idx)

    def _resolve_last_target(self):
        """Return the currently-remembered (kind, item) or (None, None) if stale/gone."""
        if not self.last_target:
            return (None, None)
        kind, idx = self.last_target
        coll = {"bill": self.app.state.bills,
                "fund": self.app.state.funds,
                "goal": self.app.state.goals}.get(kind)
        if coll is None or idx < 0 or idx >= len(coll):
            self.last_target = None
            return (None, None)
        return (kind, coll[idx])

    def _set_last_list(self, kind: str, items_or_indices) -> None:
        """Remember a list just shown so user can say 'the second one'.

        Accepts either a list of objects (will derive their current indices) or
        already-resolved (kind, idx) tuples.
        """
        coll = {"bill": self.app.state.bills,
                "fund": self.app.state.funds,
                "goal": self.app.state.goals,
                "mixed": None}.get(kind)
        out = []
        if kind == "mixed":
            out = list(items_or_indices)
        elif coll is not None:
            for x in items_or_indices:
                if isinstance(x, int):
                    out.append((kind, x))
                else:
                    try:
                        out.append((kind, coll.index(x)))
                    except ValueError:
                        continue
        self.last_list = out[:20]

    _PRONOUN_ORDINALS = {
        "first": 0, "1st": 0, "one": 0,
        "second": 1, "2nd": 1, "two": 1,
        "third": 2, "3rd": 2, "three": 2,
        "fourth": 3, "4th": 3, "four": 3,
        "fifth": 4, "5th": 4, "five": 4,
        "sixth": 5, "6th": 5, "six": 5,
        "last": -1, "final": -1,
    }

    def _resolve_reference(self, query: str):
        """Try to resolve pronoun-like queries ('it', 'that one', 'the first one') against memory.

        Returns (kind, item) or (None, None).
        """
        q = (query or "").lower().strip()
        # Bare pronouns → last_target
        if q in ("it", "that", "that one", "this", "this one", "the one", "same one", "same"):
            return self._resolve_last_target()
        # Ordinals ("the first", "second one", "last")
        m = re.search(r"\b(?:the\s+)?(first|1st|second|2nd|third|3rd|fourth|4th|fifth|5th|sixth|6th|last|final)\b(?:\s+one)?", q)
        if m:
            key = m.group(1)
            if key in self._PRONOUN_ORDINALS and self.last_list:
                pos = self._PRONOUN_ORDINALS[key]
                if -len(self.last_list) <= pos < len(self.last_list):
                    kind, idx = self.last_list[pos]
                    coll = {"bill": self.app.state.bills,
                            "fund": self.app.state.funds,
                            "goal": self.app.state.goals}.get(kind)
                    if coll and 0 <= idx < len(coll):
                        return (kind, coll[idx])
        # Explicit position ("#2", "number 3", "item 2")
        m = re.search(r"\b(?:#|number\s+|item\s+|row\s+)(\d+)\b", q)
        if m:
            pos = int(m.group(1)) - 1
            if self.last_list and 0 <= pos < len(self.last_list):
                kind, idx = self.last_list[pos]
                coll = {"bill": self.app.state.bills,
                        "fund": self.app.state.funds,
                        "goal": self.app.state.goals}.get(kind)
                if coll and 0 <= idx < len(coll):
                    return (kind, coll[idx])
        return (None, None)

    # ── Contextual opener ────────────────────────────────────────────────────

    def greet_contextually(self) -> None:
        """Append a state-aware opening line. Call when the user opens Gerald."""
        if self._contextual_opened:
            return
        self._contextual_opened = True
        try:
            line, expr = self._compose_contextual_opener()
        except Exception:
            return
        if line:
            self._say(line, expr)

    def _compose_contextual_opener(self):
        app = self.app
        s = app.state
        today = date.today()
        # 1. Overdue bills > anything else
        overdue = [b for b in s.bills if b.due_date and b.due_date < today]
        if overdue:
            n = len(overdue)
            names = ", ".join(b.name for b in overdue[:2])
            extra = "" if n <= 2 else f" +{n-2} more"
            return (f"Heads up — {n} bill{'s' if n != 1 else ''} overdue "
                    f"({names}{extra}). Say \"mark {overdue[0].name} paid\" "
                    f"when you've handled it.", "normal")
        # 2. Pending reviews
        pending = len([tx for tx in s.transactions
                       if tx.needs_review and not tx.user_verified]) + \
                  len([tx for tx in app.latest_import
                       if tx.needs_review and not tx.user_verified])
        if pending >= 3:
            return (f"You have {pending} transactions waiting for review. "
                    f"Say \"open transactions\" to clear them, or I can walk "
                    f"you through bulk ops.", "normal")
        # 3. Bills due in next 7 days
        upcoming = sorted([b for b in s.bills
                           if b.due_date and today <= b.due_date <= today +
                           timedelta(days=7)], key=lambda b: b.due_date)
        if upcoming:
            n = len(upcoming)
            next_b = upcoming[0]
            days = (next_b.due_date - today).days
            when = "today" if days == 0 else ("tomorrow" if days == 1 else f"in {days}d")
            return (f"{n} bill{'s' if n != 1 else ''} due this week — "
                    f"{next_b.name} is up {when}. Want the rundown? "
                    f"Say \"what's due\".", "normal")
        # 4. Pay overdue check
        if hasattr(app, "_check_pay_overdue"):
            try:
                if app._check_pay_overdue():
                    return ("Looks like a pay is overdue. When you get it, "
                            "say \"I got paid $<amount> today\" and I'll "
                            "allocate it.", "normal")
            except Exception:
                pass
        # 5. Claimable season tiers
        try:
            ensure_fn = getattr(app.game_engine, "ensure_season", None)
            if ensure_fn:
                ensure_fn()
            claimable = 0
            g = s.game
            for idx, (xp, *_rest) in enumerate(SEASON_TIERS):
                if g.season_xp >= xp and idx not in g.season_claimed_tiers:
                    claimable += 1
            if claimable:
                return (f"You have {claimable} season tier"
                        f"{'s' if claimable != 1 else ''} to claim. "
                        f"Say \"claim\" to grab them.", "wink")
        except Exception:
            pass
        # 6. Streak milestone / good vibes
        streak = s.game.streak_pays
        if streak >= 5:
            return (f"Streak of {streak} — you're on a roll. Ask \"savings "
                    f"rate\" or \"what's due\" anytime.", "wink")
        # 7. First-time / near-empty state
        if not s.incomes:
            return ("No pay logged yet — when one lands, say \"I got paid "
                    "$X today\" and I'll split it across bills, funds, "
                    "and goals.", "normal")
        # 8. Default
        return ("All calm. Ask me \"savings rate\", \"my biggest fund\", "
                "\"show overdue bills\", or \"how much on food this month\".",
                "normal")

    # ── Public API ───────────────────────────────────────────────────────

    def handle(self, text: str) -> None:
        text = (text or "").strip()
        if not text:
            return
        self.transcript.append({"role": "user", "text": text, "expression": "normal"})
        # Expand user-defined aliases before any routing — but skip for alias
        # management commands so "forget alias subs" doesn't rewrite "subs" first.
        _lower_raw = text.lower()
        _is_alias_cmd = bool(
            re.search(r"\b(forget|remove|delete)\s+alias\b", _lower_raw)
            or re.match(r"^\s*unalias\b", _lower_raw)
            or re.search(r"\b(list|show)\s+(?:my\s+)?aliases?\b", _lower_raw)
            or re.match(r"^\s*when\s+i\s+say\b", _lower_raw)
            or re.match(r"^\s*alias\s+", _lower_raw)
        )
        if not _is_alias_cmd:
            text = self._expand_aliases(text)
        try:
            # Chain: only split when we're not mid-slot-fill
            if not self.pending.get("awaiting"):
                parts = self._split_chained(text)
                if len(parts) > 1:
                    results = []
                    for part in parts:
                        try:
                            r, _e = self._route(part)
                        except Exception as e:
                            r = f"(leg failed: {e})"
                        # Don't auto-confirm pending flows mid-chain
                        if self.pending.get("awaiting") == "confirm":
                            # Auto-confirm each slot-filled intent in a chain
                            r2, _ = self._handle_confirm("yes", "yes")
                            results.append(r); results.append(r2)
                        else:
                            results.append(r)
                    reply = "Done — chained:\n• " + "\n• ".join(str(x).split("\n")[0] for x in results)
                    expr = "wink"
                    self._say(reply, expr)
                    return
            reply, expr = self._route(text)
        except Exception as e:  # defensive — never crash the chat
            reply, expr = (f"Something went sideways: {e}. Try rephrasing?", "normal")
            self._reset_pending()
        self._say(reply, expr)

    def _say(self, text: str, expression: str = "normal") -> None:
        self.transcript.append({"role": "gerald", "text": text, "expression": expression})

    def _reset_pending(self) -> None:
        self.pending = {}

    # ── Dispatcher ───────────────────────────────────────────────────────

    def _route(self, text: str):
        lower = text.lower().strip()

        # Slot-fill continuation takes priority
        awaiting = self.pending.get("awaiting", "")
        if awaiting == "disambig":
            return self._handle_disambig_reply(text, lower)
        if awaiting.startswith("wizard:"):
            return self._continue_wizard(text, lower, awaiting[7:])
        if awaiting.startswith("slot:"):
            # Allow cancel even mid-flow
            if re.fullmatch(r"\s*(cancel|nevermind|nvm|stop|abort|quit|forget it)\s*\.?", lower):
                return self._handle_cancel()
            reply = self._continue_slot_fill(text, lower, awaiting[5:])
            # If we were inside a wizard and the slot-fill finished, advance the wizard.
            if not self.pending.get("awaiting") and self.pending.get("_wizard"):
                snap = self.pending["_wizard"]
                self.pending = snap
                follow, _ = self._wizard_advance(skipped=False)
                return (reply[0] + "\n\n" + follow, reply[1])
            return reply
        if awaiting == "confirm":
            reply = self._handle_confirm(text, lower)
            if not self.pending.get("awaiting") and self.pending.get("_wizard"):
                snap = self.pending["_wizard"]
                self.pending = snap
                follow, _ = self._wizard_advance(skipped=False)
                return (reply[0] + "\n\n" + follow, reply[1])
            return reply

        # Bulk / "all"/"each" commands take priority over single-intent classify
        bulk = self._handle_bulk(text)
        if bulk is not None:
            return bulk

        intent = self._classify_intent(lower)

        if intent == "greet":         return self._handle_greet()
        if intent == "help":          return self._handle_help()
        if intent == "undo":          return self._handle_undo(text)
        if intent == "summary":       return self._handle_summary()
        if intent == "navigate":      return self._handle_navigate(lower)
        if intent == "cancel":        return self._handle_cancel()
        if intent == "yes":           return ("Nothing pending to confirm.", "normal")
        if intent == "no":            return ("All good — no worries.", "normal")
        if intent == "thanks":        return self._handle_thanks()
        if intent == "meta":          return self._handle_meta()
        if intent == "where_am_i":    return self._handle_where()
        if intent in ("add_bill", "add_fund", "add_goal", "add_income"):
            return self._start_flow(intent, text, lower)
        if intent == "contribute":    return self._handle_contribute(text)
        if intent == "rename":        return self._handle_rename(text)
        if intent == "update":        return self._handle_update(text)
        if intent == "list_bills":    return self._handle_list_bills()
        if intent == "list_funds":    return self._handle_list_funds()
        if intent == "list_goals":    return self._handle_list_goals()
        if intent == "list_incomes":  return self._handle_list_incomes()
        if intent == "delete_bill":   return self._handle_delete("bill", text)
        if intent == "delete_fund":   return self._handle_delete("fund", text)
        if intent == "delete_goal":   return self._handle_delete("goal", text)
        if intent == "mark_paid":     return self._handle_mark_paid(text)
        if intent == "due":           return self._handle_due(text)
        if intent == "pace":          return self._handle_pace()
        if intent == "forecast":      return self._handle_forecast()
        if intent == "next_action":   return self._handle_next()
        if intent == "stats":         return self._handle_stats(text)
        if intent == "savings_rate": return self._handle_savings_rate(text)
        if intent == "spend_category": return self._handle_spend_category(text)
        if intent == "goal_eta":      return self._handle_goal_eta(text)
        if intent == "top_item":      return self._handle_top_item(text)
        if intent == "list_filtered": return self._handle_list_filtered(text)
        if intent == "explain":       return self._handle_explain(text)
        if intent == "plan_goal":     return self._handle_plan_goal(text)
        if intent == "history":       return self._handle_history()
        if intent == "mute_alerts":   return self._handle_mute_alerts(True)
        if intent == "unmute_alerts": return self._handle_mute_alerts(False)
        if intent == "setup_wizard":  return self._handle_setup_wizard()
        if intent == "alias_add":     return self._handle_alias_add(text)
        if intent == "alias_list":    return self._handle_alias_list()
        if intent == "alias_remove":  return self._handle_alias_remove(text)
        if intent == "reminder_add":  return self._handle_reminder_add(text)
        if intent == "reminder_list": return self._handle_reminder_list()
        if intent == "reminder_dismiss": return self._handle_reminder_dismiss(text)
        if intent == "why":           return self._handle_why(text)
        if intent == "whatif":        return self._handle_whatif(text)
        if intent == "tx_list":       return self._handle_tx_list(text)
        if intent == "tx_frequent":   return self._handle_tx_frequent(text)
        if intent == "tx_tag_last":   return self._handle_tx_tag_last(text)
        if intent == "buy_perk":      return self._handle_buy_perk(text)
        if intent == "claim_tier":    return self._handle_claim_tier(text)
        if intent == "prestige":      return self._handle_prestige(text)
        if intent == "import":        return self._handle_import()
        return self._handle_unknown(text)

    # ── Intent classification ────────────────────────────────────────────

    def _classify_intent(self, lower: str) -> str:
        # Tutor / glossary — "what is X" / "explain X" — must come first so it beats
        # keyword-matched intents like prestige on "what is prestige".
        if re.match(r"^\s*(explain|define|teach me about|tell me about)\s+\S+", lower):
            return "explain"
        if re.match(r"^\s*(what\s+(?:is|are)|what'?s|how\s+does|how\s+do)\s+(?:a\s+|an\s+|the\s+)?\S+", lower) and \
                not re.search(r"\b(my|due|left|to spend|should|next|pace|overdue|saving|savings rate|biggest|top)\b", lower):
            # Verify it's a known glossary key or plausibly asking for one
            return "explain"
        # Why — explain a computed number. Must come before pace/stats since those
        # keyword-match "safe to spend" / "my streak" / "savings rate" first.
        if re.search(r"\bwhy\s+(?:is|are|did|do|does|am|has|were|was)\b", lower):
            return "why"
        # What-if — simulate without mutating. Must come before "what" classifiers.
        if re.search(r"\bwhat\s+if\b", lower):
            return "whatif"
        # Short-word exact matches
        if re.fullmatch(r"\s*(undo|revert|rollback|take it back)\s*\.?", lower):
            return "undo"
        # "undo last N" / "undo contribution to X" / "undo rename X"
        if re.match(r"^\s*undo\s+", lower):
            return "undo"
        if re.fullmatch(r"\s*(help|\?|commands|what can you do|what do you do|menu)\s*\.?", lower):
            return "help"
        if re.fullmatch(r"\s*(cancel|nevermind|nvm|stop|abort|quit|forget it)\s*\.?", lower):
            return "cancel"
        if re.fullmatch(r"\s*(yes|yep|yeah|yup|y|ok|okay|sure|confirm|do it|add it|go|affirmative|correct)\s*\.?", lower):
            return "yes"
        if re.fullmatch(r"\s*(no|nope|nah|n|negative|don't|dont)\s*\.?", lower):
            return "no"
        if re.fullmatch(r"\s*(thanks|thank you|thx|ty|cheers|appreciate it|appreciated|nice one|good job|well done)\s*\.?", lower):
            return "thanks"
        if re.fullmatch(r"\s*(who are you|what are you|what is gerald|who is gerald)\s*\??\s*", lower):
            return "meta"
        if re.fullmatch(r"\s*(what page(?: am i on)?|where am i|current tab|what tab)\s*\??\s*", lower):
            return "where_am_i"
        if re.match(r"^(hi|hello|hey|yo|sup|g'?day|howdy|morning|evening)\b", lower):
            return "greet"
        # What should I do / next action
        if re.search(r"\b(what (?:should|do|could|can|would) i do|what's next|what now|next action|priorit(?:y|ies)|where should i start|what to focus on)\b", lower):
            return "next_action"
        # Summary
        if re.search(r"\b(summary|overview|status|how am i doing|how'm i doing|where do i stand|recap|state of (?:the nation|play|affairs)|how's it looking|how it look)\b", lower):
            return "summary"
        # Pace / safe to spend
        if re.search(r"\b(safe to spend|daily pace|spending pace|how's my pace|am i overspending|over ?spending|burn rate|how much can i spend)\b", lower) \
                or re.fullmatch(r"\s*pace\s*\??\s*", lower):
            return "pace"
        # Forecast
        if re.search(r"\b(forecast|cashflow|cash flow|outlook|projection|what's ahead|what's coming)\b", lower):
            return "forecast"
        # Due / upcoming (read-only report — must not swallow "set X due to …")
        if re.search(r"\b(what'?s due|due (?:soon|this week|this month|today|tomorrow|now)|upcoming|coming up|coming due|what bills are due|when is my|when's my)\b", lower) \
                or re.fullmatch(r"\s*due\s*\??\s*", lower):
            return "due"
        # Import
        if re.search(r"\bimport\b.*\b(pdf|statement|bank|transactions?|file)\b", lower) or re.fullmatch(r"\s*import\s*\.?", lower):
            return "import"
        # Navigate
        if re.search(r"\b(open|show me|take me to|go to|switch to|navigate to|jump to)\b", lower) and re.search(
                r"\b(today|setup|score|transactions|income|collection|avatar|review|analysis|dashboard|bills|funds|goals|log pay)\b", lower):
            return "navigate"
        # Prestige
        if re.search(r"\bprestige\b", lower):
            return "prestige"
        # Buy perk — before generic "add" patterns
        if re.search(r"\b(buy|purchase|get)\b.*\b(perk|score boost|booster|streak shield|gem magnet|season scholar|fortune hunter|multiplier|shield|magnet|scholar)\b", lower):
            return "buy_perk"
        # Claim tier
        if re.search(r"\bclaim\b", lower):
            return "claim_tier"
        # Stats (my score / my gems / my streak / my level)
        if re.search(r"\b(?:my|how many|how much|what's my|whats my)\s+(score|gold|gems?|level|streak|multiplier|rank|pays? logged|progress)\b", lower) or \
           re.fullmatch(r"\s*(score|gems?|streak|level|multiplier)\s*\??\s*", lower):
            return "stats"
        # Alerts mute / unmute (early — explicit words)
        if re.search(r"\b(be quiet|stop (?:alert|nagging|bothering)|mute (?:alert|notif)|shush|quiet mode)\b", lower) or re.fullmatch(r"\s*(mute|silent)\s*\.?", lower):
            return "mute_alerts"
        if re.search(r"\b(alerts?\s+on|unmute|start (?:alert|nagging)|speak up)\b", lower):
            return "unmute_alerts"
        # Setup wizard — scripted onboarding
        if re.search(r"\b(help me (?:set up|setup|get started)|walk me through (?:setup|set up|this)|setup wizard|guided setup|onboard me|start over|reset wizard|begin setup|set me up)\b", lower):
            return "setup_wizard"
        # Aliases
        if re.search(r"\bwhen\s+i\s+say\b.*\b(?:you\s+mean|means?|=)\b", lower) or \
           re.search(r"\b(?:alias|shortcut|define)\s+\S+\s+(?:=|means?|as|be|to)\s+", lower) or \
           re.search(r"\blet\s+\S+\s+(?:=|mean|be)\s+", lower):
            return "alias_add"
        if re.search(r"\b(list|show)\s+(?:my\s+)?aliases\b", lower) or re.fullmatch(r"\s*aliases\s*\.?", lower):
            return "alias_list"
        if re.search(r"\b(?:forget|remove|delete|clear)\s+(?:the\s+)?alias\b", lower) or re.search(r"\bunalias\b", lower):
            return "alias_remove"
        # Reminders
        if re.search(r"\b(remind\s+me|nudge\s+me)\b", lower):
            return "reminder_add"
        if re.search(r"\b(list|show)\s+(?:my\s+)?reminders\b", lower) or re.fullmatch(r"\s*reminders\s*\.?", lower):
            return "reminder_list"
        if re.search(r"\b(?:dismiss|clear|delete|remove|done)\s+(?:reminder|nudge)\b", lower) or \
           re.search(r"\breminder\s+\d+\s+done\b", lower):
            return "reminder_dismiss"
        # Transaction queries
        if re.search(r"\b(?:tag|categor(?:ize|ise)|classify|label)\s+(?:the\s+)?last\s+(?:tx|transaction)\b", lower):
            return "tx_tag_last"
        if re.search(r"\b(most\s+frequent|top\s+merchants?|frequent\s+merchants?|who\s+(?:do\s+)?i\s+pay\s+(?:most|often))\b", lower):
            return "tx_frequent"
        if re.search(r"\btransactions?\s+(?:from|over|under|above|below)\b", lower) or \
           re.search(r"\banything\s+over\s+\$\d", lower) or \
           re.search(r"\b(who|what)\s+did\s+i\s+pay\b", lower):
            return "tx_list"
        # Goal planner — "save $X by <date>" or "plan to save $X"
        if (re.search(r"\b(save|reach|build|reach target|hit target|plan(?:\s+to)?\s+save|goal of)\b", lower) and \
                re.search(r"\$\d|\d+(?:\.\d+)?(?:k)?\b|\bthousand\b|\bhundred\b", lower)) and \
                re.search(r"\b(by|before|until|in)\b", lower) and not re.search(r"\b(add|create)\s+(?:a\s+)?(?:goal|fund)\b", lower):
            return "plan_goal"
        # Savings rate
        if re.search(r"\b(savings?\s+rate|save\s+rate|saving\s+rate|how much am i saving|am i saving enough|saved this month)\b", lower):
            return "savings_rate"
        # Spend by category — "how much (did i spend) on X [this month|last month|ytd|this year]"
        if re.search(r"\b(?:how much|spend|spent|spending)\b.*\bon\b", lower) or re.search(r"\b(?:spend|spent|spending)\b\s+on\b", lower):
            return "spend_category"
        # Goal/fund ETA — "how long until X", "when will I finish X", "eta X"
        if re.search(r"\b(how long (?:until|till|before)|when (?:will|do) i (?:finish|hit|reach|complete)|eta(?:\s+for)?|finish by)\b", lower):
            return "goal_eta"
        # Top / biggest
        if re.search(r"\b(?:biggest|largest|smallest|most expensive|top|highest|lowest)\b.*\b(bills?|funds?|goals?|expenses?|categor(?:y|ies))\b", lower) or \
           re.search(r"\b(?:my|the)\s+(?:biggest|largest|top)\s+(bills?|funds?|goals?|expenses?|categor(?:y|ies))\b", lower):
            return "top_item"
        # Filtered lists — "bills over $100", "unpaid bills", "overdue bills", "essential bills", "funds under target"
        if re.search(r"\b(bill|fund|goal)s?\b\s+(over|under|above|below|>=|<=|>|<|less than|more than)\s+\$?\d", lower) or \
           re.search(r"\b(unpaid|overdue|upcoming|essential|critical|important|optional|low|behind|complete|completed|full|maxed|empty)\s+(bill|fund|goal)s?\b", lower):
            return "list_filtered"
        # Mark paid — check before update
        if (re.search(r"\bmark\b", lower) and re.search(r"\bpaid\b", lower)) or re.search(r"\bpaid (off|it)\b", lower):
            return "mark_paid"
        # Rename
        if re.search(r"\brename\b", lower) or (re.search(r"\bcall\b", lower) and re.search(r"\bto\b", lower) and re.search(r"\b(bill|fund|goal)\b", lower)):
            return "rename"
        # Update — "change X to", "update X", "make X monthly/essential/etc"
        if re.search(r"\b(change|update|edit|set)\b.*\b(to|as)\b", lower) and not re.search(r"\b(add|new)\s+(bill|fund|goal)\b", lower):
            return "update"
        if re.search(r"\bmake\b\s+\S+\s+(monthly|fortnightly|biweekly|weekly|yearly|annually|one[- ]?off|once|essential|critical|important|normal|optional|low)\b", lower):
            return "update"
        # Deletes — check before adds
        is_del = re.search(r"\b(delete|remove|drop|get rid of)\b", lower)
        if is_del and re.search(r"\bbill\b", lower):     return "delete_bill"
        if is_del and re.search(r"\bfund\b", lower):     return "delete_fund"
        if is_del and re.search(r"\bgoal\b", lower):     return "delete_goal"
        # Contribute: "add/put/contribute/deposit X to Y" — must have amount + direction prep
        has_amount = bool(re.search(r"\$\d|\b\d+(?:\.\d+)?(?:k)?\b|\bthousand\b|\bhundred\b", lower)) or bool(_GERALD_NUMBER_WORD_PATTERN.search(lower))
        has_direction = bool(re.search(r"\b(to|towards?|into|onto|on)\b", lower))
        if re.search(r"\b(put|contribute|deposit|toss|drop|chuck|push)\b", lower) and has_amount and has_direction:
            return "contribute"
        # Bare "contribute $X" — relies on last-target fallback
        if re.search(r"\b(contribute|deposit)\b", lower) and has_amount:
            return "contribute"
        if re.search(r"\badd\b", lower) and has_amount and has_direction and not re.search(r"\b(bill|fund|goal|income|pay)\b\s+(called|named)", lower) and not re.search(r"\badd\s+(?:a\s+)?(bill|fund|goal|income|new bill|new fund|new goal)\b", lower):
            return "contribute"
        # Lists
        is_list = re.search(r"\b(list|show|view|what are|see|tell me about)\b", lower) or re.match(r"^my\s+", lower)
        if is_list and re.search(r"\bbills?\b", lower):  return "list_bills"
        if is_list and re.search(r"\bfunds?\b", lower):  return "list_funds"
        if is_list and re.search(r"\bgoals?\b", lower):  return "list_goals"
        if is_list and re.search(r"\b(pay|incomes?|pays|paychecks?|wages?|pay history)\b", lower):
            return "list_incomes"
        # Adds
        if re.search(r"\b(add|new|create|make|set up|setup|start|open)\s+(a\s+)?bill\b", lower) or re.fullmatch(r"\s*bill\s*\.?", lower):
            return "add_bill"
        if re.search(r"\b(add|new|create|make|set up|setup|open|save for|save up for|start)\s+(a\s+)?(fund|sinking(?:\s+fund)?)\b", lower) or re.fullmatch(r"\s*fund\s*\.?", lower):
            return "add_fund"
        if re.search(r"\b(add|new|create|make|set|set up|setup|start)\s+(a\s+)?goal\b", lower) or re.fullmatch(r"\s*goal\s*\.?", lower):
            return "add_goal"
        if re.search(r"\b(got paid|just (?:got\s+)?paid|paid me|log pay|log a pay|add pay|add income|received pay|log income|paycheck|pay came in|pay arrived|wage came|new pay)\b", lower):
            return "add_income"
        if re.search(r"\b(add|new|create|log)\b.*\b(pay|income|wage|wages|paycheck)\b", lower):
            return "add_income"
        # "save for X" / "save up for X" → fund
        if re.search(r"\bsave (?:up )?for\b", lower):     return "add_fund"
        # History — "what did I just do", "recent actions"
        if re.search(r"\b(what did (?:i|we) (?:just )?do|recent actions?|action history|last actions?|history)\b", lower):
            return "history"
        return "unknown"

    # ── Entity extraction ────────────────────────────────────────────────

    def _extract_amount(self, text: str):
        """Return (amount, remaining_text) where matched chunk is masked out."""
        # $-prefixed with optional k suffix
        m = re.search(r"\$\s*([\d,]+(?:\.\d+)?)\s*([kK])?\b", text)
        if m:
            val = float(m.group(1).replace(",", ""))
            if m.group(2):
                val *= 1000
            return val, text[:m.start()] + " " + text[m.end():]
        # Bare number with k suffix
        m = re.search(r"\b([\d,]+(?:\.\d+)?)\s*([kK])\b", text)
        if m:
            val = float(m.group(1).replace(",", "")) * 1000
            return val, text[:m.start()] + " " + text[m.end():]
        # Plain number — but not followed by day-ordinal suffix, not a year, not a month/day context
        for m in re.finditer(r"(?<![\d.])([\d]{1,3}(?:,\d{3})+(?:\.\d+)?|\d+(?:\.\d+)?)(?![\d.])", text):
            end = m.end()
            # Look ahead: is this an ordinal day?
            rest = text[end:end + 3].lower()
            if rest.startswith(("st", "nd", "rd", "th")):
                continue
            raw = m.group(1).replace(",", "")
            try:
                val = float(raw)
            except ValueError:
                continue
            # Heuristic: avoid picking 4-digit years as amounts when they look like a year
            if val >= 1900 and val <= 2100 and "." not in raw and len(raw) == 4:
                # Could be a year in a date — skip
                continue
            return val, text[:m.start()] + " " + text[end:]
        # Written numbers ("fifty dollars", "two thousand", "five hundred bucks")
        m = _GERALD_NUMBER_WORD_PATTERN.search(text)
        if m:
            val = _gerald_parse_written_number(m.group(0))
            if val is not None and val > 0:
                return float(val), text[:m.start()] + " " + text[m.end():]
        return None, text

    def _extract_frequency(self, text: str):
        for pat, freq in _GERALD_FREQ_PATTERNS:
            m = re.search(pat, text, re.IGNORECASE)
            if m:
                return freq, text[:m.start()] + " " + text[m.end():]
        return None, text

    def _extract_priority(self, text: str):
        for pat, prio in _GERALD_PRIORITY_PATTERNS:
            m = re.search(pat, text, re.IGNORECASE)
            if m:
                return prio, text[:m.start()] + " " + text[m.end():]
        return None, text

    def _extract_date(self, text: str):
        """Parse a date expression. Returns (date | None, remaining_text)."""
        today = date.today()
        lower = text.lower()

        # YYYY-MM-DD
        m = re.search(r"\b(\d{4})-(\d{1,2})-(\d{1,2})\b", lower)
        if m:
            try:
                d = date(int(m.group(1)), int(m.group(2)), int(m.group(3)))
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        # DD/MM/YYYY or DD/MM (AU/UK default)
        m = re.search(r"\b(\d{1,2})/(\d{1,2})(?:/(\d{2,4}))?\b", lower)
        if m:
            try:
                dd = int(m.group(1)); mm = int(m.group(2))
                yy = m.group(3)
                year = int(yy) if yy else today.year
                if year < 100:
                    year += 2000
                d = date(year, mm, dd)
                if not yy and d < today:
                    d = date(year + 1, mm, dd)
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        # "today" / "tomorrow" / "yesterday"
        m = re.search(r"\btoday\b", lower)
        if m:
            return today, text[:m.start()] + " " + text[m.end():]
        m = re.search(r"\btomorrow\b", lower)
        if m:
            return today + timedelta(days=1), text[:m.start()] + " " + text[m.end():]
        m = re.search(r"\byesterday\b", lower)
        if m:
            return today - timedelta(days=1), text[:m.start()] + " " + text[m.end():]
        # "end of month" / "eom" / "end of the month" → last day of current month
        m = re.search(r"\b(?:end of (?:the\s+)?month|eom)\b", lower)
        if m:
            import calendar as _cal
            d = date(today.year, today.month, _cal.monthrange(today.year, today.month)[1])
            if d < today:
                nxt = _gerald_add_months(date(today.year, today.month, 1), 1)
                d = date(nxt.year, nxt.month, _cal.monthrange(nxt.year, nxt.month)[1])
            return d, text[:m.start()] + " " + text[m.end():]
        # "first of next month" / "first of the month" / "start of next month"
        m = re.search(r"\b(?:(?:first|1st|start)\s+of\s+(?:the\s+)?next\s+month|next\s+month(?:'s)?\s+(?:first|1st|start))\b", lower)
        if m:
            nxt = _gerald_add_months(date(today.year, today.month, 1), 1)
            return date(nxt.year, nxt.month, 1), text[:m.start()] + " " + text[m.end():]
        m = re.search(r"\b(?:first|1st|start)\s+of\s+(?:the\s+|this\s+)?month\b", lower)
        if m:
            # This month if today is the 1st, otherwise next month's 1st
            y, mth = today.year, today.month
            if today.day > 1:
                nxt = _gerald_add_months(date(y, mth, 1), 1)
                y, mth = nxt.year, nxt.month
            return date(y, mth, 1), text[:m.start()] + " " + text[m.end():]
        # "mid-month" / "mid month" → 15th of this month (or next if past)
        m = re.search(r"\bmid[-\s]?month\b", lower)
        if m:
            y, mth = today.year, today.month
            d = date(y, mth, 15)
            if d < today:
                nxt = _gerald_add_months(date(y, mth, 1), 1)
                d = date(nxt.year, nxt.month, 15)
            return d, text[:m.start()] + " " + text[m.end():]
        # "this friday" / "this monday" — same weekday this week or next if past
        m = re.search(r"\bthis\s+(monday|tuesday|wednesday|thursday|friday|saturday|sunday|mon|tue|tues|wed|thu|thurs|fri|sat|sun)\b", lower)
        if m:
            wd = _GERALD_WEEKDAYS[m.group(1)]
            delta = (wd - today.weekday()) % 7
            if delta == 0:
                delta = 7  # "this friday" when today IS friday → next friday
            d = today + timedelta(days=delta)
            return d, text[:m.start()] + " " + text[m.end():]
        # "in N days|weeks|months"
        m = re.search(r"\bin\s+(\d+)\s+(day|days|week|weeks|month|months)\b", lower)
        if m:
            n = int(m.group(1)); unit = m.group(2)
            if unit.startswith("day"):
                d = today + timedelta(days=n)
            elif unit.startswith("week"):
                d = today + timedelta(days=n * 7)
            else:
                d = _gerald_add_months(today, n)
            return d, text[:m.start()] + " " + text[m.end():]
        # "next week|month|year|friday..."
        m = re.search(r"\bnext\s+(week|month|year|monday|tuesday|wednesday|thursday|friday|saturday|sunday|mon|tue|tues|wed|thu|thurs|fri|sat|sun)\b", lower)
        if m:
            tok = m.group(1)
            if tok == "week":   d = today + timedelta(days=7)
            elif tok == "month": d = _gerald_add_months(today, 1)
            elif tok == "year":  d = date(today.year + 1, today.month, min(today.day, 28))
            else:
                wd = _GERALD_WEEKDAYS[tok]
                delta = (wd - today.weekday()) % 7
                delta = delta if delta >= 1 else 7
                d = today + timedelta(days=delta + 7)
            return d, text[:m.start()] + " " + text[m.end():]
        # Weekday name alone → next occurrence
        m = re.search(r"\b(monday|tuesday|wednesday|thursday|friday|saturday|sunday|mon|tue|tues|wed|thu|thurs|fri|sat|sun)\b", lower)
        if m:
            wd = _GERALD_WEEKDAYS[m.group(1)]
            delta = (wd - today.weekday()) % 7
            delta = delta if delta >= 1 else 7
            d = today + timedelta(days=delta)
            return d, text[:m.start()] + " " + text[m.end():]
        # "by december 2027" — month + year (no day) → last day of that month
        m = re.search(r"\b(?:by\s+)?(january|february|march|april|may|june|july|august|september|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|sept|oct|nov|dec)\s+(\d{4})\b", lower)
        if m:
            mm = _GERALD_MONTHS[m.group(1)]; yy = int(m.group(2))
            try:
                import calendar as _cal
                d = date(yy, mm, _cal.monthrange(yy, mm)[1])
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        # "december 5", "dec 5", "5 december", "5 dec", "the 5th of december"
        m = re.search(r"\b(january|february|march|april|may|june|july|august|september|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|sept|oct|nov|dec)\s+(\d{1,2})(?:st|nd|rd|th)?\b", lower)
        if m:
            mm = _GERALD_MONTHS[m.group(1)]; dd = int(m.group(2))
            try:
                d = date(today.year, mm, dd)
                if d < today:
                    d = date(today.year + 1, mm, dd)
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        # Month-only ("by december", "in december") → last day of that month this year (or next if past)
        m = re.search(r"\b(?:by|in|before|end of|around)\s+(january|february|march|april|may|june|july|august|september|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|sept|oct|nov|dec)\b", lower)
        if m:
            mm = _GERALD_MONTHS[m.group(1)]
            import calendar as _cal
            y = today.year
            try:
                d = date(y, mm, _cal.monthrange(y, mm)[1])
                if d < today:
                    d = date(y + 1, mm, _cal.monthrange(y + 1, mm)[1])
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        m = re.search(r"\b(\d{1,2})(?:st|nd|rd|th)?\s+(?:of\s+)?(january|february|march|april|may|june|july|august|september|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|sept|oct|nov|dec)\b", lower)
        if m:
            dd = int(m.group(1)); mm = _GERALD_MONTHS[m.group(2)]
            try:
                d = date(today.year, mm, dd)
                if d < today:
                    d = date(today.year + 1, mm, dd)
                return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        # Ordinal day alone: "25th" / "the 25th"  → this month if future, else next month
        m = re.search(r"\b(?:the\s+)?(\d{1,2})(?:st|nd|rd|th)\b", lower)
        if m:
            try:
                dd = int(m.group(1))
                if 1 <= dd <= 31:
                    y, mth = today.year, today.month
                    try:
                        d = date(y, mth, dd)
                    except ValueError:
                        d = _gerald_add_months(date(y, mth, 1), 1).replace(day=min(dd, 28))
                    if d < today:
                        base = _gerald_add_months(date(y, mth, 1), 1)
                        try:
                            d = date(base.year, base.month, dd)
                        except ValueError:
                            d = base.replace(day=28)
                    return d, text[:m.start()] + " " + text[m.end():]
            except ValueError:
                pass
        return None, text

    def _extract_name(self, working_text: str):
        """Pull a plausible entity name from text after other entities have been masked."""
        # Prefer quoted strings
        m = re.search(r"[\"']([^\"']+)[\"']", working_text)
        if m:
            return m.group(1).strip()
        # "called X" / "named X" — capture trailing phrase
        m = re.search(r"\b(?:called|named|for)\s+([A-Za-z][\w &'\-]{0,40})", working_text, re.IGNORECASE)
        if m:
            name = _gerald_clean_name(m.group(1))
            if name:
                return name
        # Fallback: strip keyword tokens and whitespace chunks, return longest remaining phrase
        tokens = re.findall(r"[A-Za-z][\w'\-]*", working_text)
        kept = [t for t in tokens if t.lower() not in _GERALD_STOP_TOKENS]
        if not kept:
            return None
        # Rejoin into contiguous phrases (separated by stop tokens in the original order)
        phrases, cur = [], []
        for t in re.findall(r"[A-Za-z][\w'\-]*|\s+", working_text):
            if not t.strip():
                continue
            if t.lower() in _GERALD_STOP_TOKENS:
                if cur:
                    phrases.append(" ".join(cur)); cur = []
            else:
                cur.append(t)
        if cur:
            phrases.append(" ".join(cur))
        phrases = [p.strip() for p in phrases if p.strip()]
        if not phrases:
            return None
        # Choose the longest phrase (word count)
        phrases.sort(key=lambda p: (-len(p.split()), -len(p)))
        return _gerald_clean_name(phrases[0])

    def _parse_entities(self, text: str) -> dict:
        working = text
        entities = {}
        freq, working = self._extract_frequency(working)
        if freq: entities["frequency"] = freq
        prio, working = self._extract_priority(working)
        if prio: entities["priority"] = prio
        d, working = self._extract_date(working)
        if d: entities["date"] = d
        amt, working = self._extract_amount(working)
        if amt is not None: entities["amount"] = amt
        name = self._extract_name(working)
        if name: entities["name"] = name
        return entities

    # ── Flow management ─────────────────────────────────────────────────

    def _start_flow(self, intent: str, text: str, lower: str):
        entities = self._parse_entities(text)
        slots = {}
        # Map entities into slot values per intent
        if intent == "add_bill":
            if "name" in entities:      slots["name"] = entities["name"]
            if "amount" in entities:    slots["amount"] = entities["amount"]
            if "frequency" in entities: slots["frequency"] = entities["frequency"]
            if "date" in entities:      slots["due_date"] = entities["date"]
            if "priority" in entities:  slots["priority"] = entities["priority"]
        elif intent == "add_fund":
            if "name" in entities:      slots["name"] = entities["name"]
            if "amount" in entities:    slots["target_amount"] = entities["amount"]
            if "date" in entities:      slots["target_date"] = entities["date"]
            if "priority" in entities:  slots["priority"] = entities["priority"]
        elif intent == "add_goal":
            if "name" in entities:      slots["name"] = entities["name"]
            if "amount" in entities:    slots["target_amount"] = entities["amount"]
            if "date" in entities:      slots["target_date"] = entities["date"]
        elif intent == "add_income":
            if "amount" in entities:    slots["amount"] = entities["amount"]
            if "date" in entities:      slots["received_on"] = entities["date"]
        self.pending = {"intent": intent, "slots": slots, "awaiting": None}
        return self._advance_flow()

    def _advance_flow(self):
        """Either ask for the next missing slot or move to confirmation."""
        intent = self.pending["intent"]
        slots = self.pending["slots"]
        missing = [s for s in self.REQUIRED_SLOTS[intent] if s not in slots]
        if missing:
            next_slot = missing[0]
            self.pending["awaiting"] = "slot:" + next_slot
            lead = self._flow_lead_in(slots, intent)
            return (lead + self.SLOT_PROMPTS[next_slot], "normal")
        # All required filled → confirm
        self.pending["awaiting"] = "confirm"
        return (self._confirmation_message(intent, slots), "wink")

    def _flow_lead_in(self, slots: dict, intent: str) -> str:
        """A short acknowledgement of what was understood so far."""
        parts = []
        if "name" in slots:
            parts.append(slots["name"])
        if "amount" in slots:
            parts.append(f"${slots['amount']:,.2f}")
        if "target_amount" in slots:
            parts.append(f"target ${slots['target_amount']:,.2f}")
        if "frequency" in slots:
            parts.append(slots["frequency"])
        if "due_date" in slots:
            parts.append(f"due {slots['due_date'].isoformat()}")
        if "target_date" in slots:
            parts.append(f"by {slots['target_date'].isoformat()}")
        if "received_on" in slots:
            parts.append(f"on {slots['received_on'].isoformat()}")
        if not parts:
            return ""
        return "Got: " + " · ".join(parts) + ". "

    def _continue_slot_fill(self, text: str, lower: str, slot: str):
        # Parse what the user typed as an answer for the specific slot
        slots = self.pending["slots"]
        if slot == "name":
            name = _gerald_clean_name(text)
            if not name:
                return ("Try a short name — like \"Netflix\" or \"Vacation\".", "normal")
            slots["name"] = name
        elif slot in ("amount", "target_amount"):
            amt, _ = self._extract_amount(text)
            if amt is None:
                return ("I need a number — try \"$15\" or \"1500\".", "normal")
            slots[slot] = amt
        elif slot == "frequency":
            freq, _ = self._extract_frequency(lower)
            if freq is None:
                return ("Pick one: weekly · fortnightly · monthly · yearly · one-off.", "normal")
            slots["frequency"] = freq
        elif slot == "due_date":
            d, _ = self._extract_date(lower)
            if d is None:
                return ("Couldn't read that date. Try \"25th\", \"next friday\", or \"2026-05-01\".", "normal")
            slots["due_date"] = d
        elif slot == "received_on":
            d, _ = self._extract_date(lower)
            if d is None:
                return ("Try \"today\", \"yesterday\", or \"2026-04-20\".", "normal")
            slots["received_on"] = d
        return self._advance_flow()

    def _confirmation_message(self, intent: str, slots: dict) -> str:
        desc = self._describe_commit(intent, slots)
        return f"Confirming: {desc}\n\nSay \"yes\" to commit, \"no\" to cancel, or \"edit <field>\" to change a value."

    def _describe_commit(self, intent: str, slots: dict) -> str:
        if intent == "add_bill":
            return (f"Bill · {slots['name']} · ${slots['amount']:,.2f} "
                    f"· {slots['frequency']} · due {slots['due_date'].isoformat()} "
                    f"· {slots.get('priority', 'essential')}")
        if intent == "add_fund":
            td = slots.get("target_date")
            td_s = f"by {td.isoformat()}" if td else "no date"
            return (f"Fund · {slots['name']} · target ${slots['target_amount']:,.2f} · {td_s} "
                    f"· {slots.get('priority', 'important')}")
        if intent == "add_goal":
            td = slots.get("target_date")
            td_s = f"by {td.isoformat()}" if td else "open-ended"
            return (f"Goal · {slots['name']} · ${slots['target_amount']:,.2f} · {td_s}")
        if intent == "add_income":
            return (f"Pay · ${slots['amount']:,.2f} · received {slots['received_on'].isoformat()}")
        return ""

    def _handle_confirm(self, text: str, lower: str):
        if re.fullmatch(r"\s*(yes|yep|yeah|yup|y|ok|okay|sure|confirm|do it|add it|go|affirmative|correct)\s*\.?", lower):
            return self._commit_pending()
        if re.fullmatch(r"\s*(no|nope|nah|n|negative|cancel|stop)\s*\.?", lower):
            self._reset_pending()
            return ("Cancelled — nothing was added.", "normal")
        m = re.match(r"\s*(edit|change|fix|update)\s+([a-z_ ]+)", lower)
        if m:
            target = m.group(2).strip().replace(" ", "_")
            slot_map = {
                "name": "name", "amount": "amount", "target": "target_amount",
                "target_amount": "target_amount", "freq": "frequency",
                "frequency": "frequency", "due": "due_date", "due_date": "due_date",
                "date": "due_date" if self.pending["intent"] == "add_bill" else "target_date",
                "target_date": "target_date", "priority": "priority",
                "received": "received_on", "received_on": "received_on",
            }
            slot = slot_map.get(target)
            if not slot:
                return (f"Don't know how to edit \"{target}\". Try \"edit amount\" or \"edit date\".", "normal")
            self.pending["slots"].pop(slot, None)
            self.pending["awaiting"] = "slot:" + slot
            prompt = self.SLOT_PROMPTS.get(slot, f"What should {slot} be?")
            return (prompt, "normal")
        return ("Say \"yes\" to commit, \"no\" to cancel, or \"edit <field>\" to change a value.", "normal")

    def _commit_pending(self):
        intent = self.pending["intent"]
        slots = self.pending["slots"]
        self._reset_pending()
        try:
            if intent == "add_bill":
                return self._commit_bill(slots)
            if intent == "add_fund":
                return self._commit_fund(slots)
            if intent == "add_goal":
                return self._commit_goal(slots)
            if intent == "add_income":
                return self._commit_income(slots)
        except Exception as e:
            return (f"Commit failed: {e}.", "normal")
        return ("Done.", "wink")

    # ── Commit operations ───────────────────────────────────────────────

    def _commit_bill(self, s: dict):
        bill = Bill(
            name=s["name"],
            amount=float(s["amount"]),
            due_date=s["due_date"],
            frequency=s["frequency"],
            priority=s.get("priority", "essential"),
            category="bill",
            current_saved=0.0,
        )
        self.app.state.bills.append(bill)
        idx = len(self.app.state.bills) - 1
        self.undo_stack.append({"kind": "bill", "index": idx, "snapshot": None,
                                 "label": f"added bill \"{bill.name}\""})
        self._after_commit("bills")
        self._set_last_target("bill", idx)
        return (f"Done. {bill.name} · ${bill.amount:,.2f} · {bill.frequency} "
                f"added to bills. \"undo\" to reverse.", "wink")

    def _commit_fund(self, s: dict):
        fund = Fund(
            name=s["name"],
            target_amount=float(s["target_amount"]),
            target_date=s.get("target_date"),
            priority=s.get("priority", "important"),
            current_saved=0.0,
            contribution_mode="auto",
            fixed_amount=0.0,
            category="fund",
        )
        self.app.state.funds.append(fund)
        idx = len(self.app.state.funds) - 1
        self.undo_stack.append({"kind": "fund", "index": idx, "snapshot": None,
                                 "label": f"added fund \"{fund.name}\""})
        self._after_commit("funds")
        self._set_last_target("fund", idx)
        return (f"Done. Fund \"{fund.name}\" targeting ${fund.target_amount:,.2f} is in. "
                f"\"undo\" to reverse.", "wink")

    def _commit_goal(self, s: dict):
        goal = Goal(
            name=s["name"],
            target_amount=float(s["target_amount"]),
            target_date=s.get("target_date"),
            priority=3,
            current_saved=0.0,
            mode="fixed",
            value=0.0,
        )
        self.app.state.goals.append(goal)
        idx = len(self.app.state.goals) - 1
        self.undo_stack.append({"kind": "goal", "index": idx, "snapshot": None,
                                 "label": f"added goal \"{goal.name}\""})
        self._after_commit("goals")
        self._set_last_target("goal", idx)
        return (f"Done. Goal \"{goal.name}\" · ${goal.target_amount:,.2f} is set. "
                f"\"undo\" to reverse.", "wink")

    def _commit_income(self, s: dict):
        entry = IncomeEntry(
            amount=float(s["amount"]),
            received_on=s["received_on"],
            source=s.get("source", "Primary Income"),
        )
        self.app.state.incomes.append(entry)
        idx = len(self.app.state.incomes) - 1
        self.undo_stack.append({"kind": "income", "index": idx, "snapshot": None,
                                 "label": f"logged pay ${entry.amount:,.0f}"})
        self._after_commit("income")
        return (f"Logged. ${entry.amount:,.2f} on {entry.received_on.isoformat()}. "
                f"Head to Log Pay to allocate it, or \"undo\" to reverse.", "wink")

    _REFRESH_MAP = {
        "bills":    ("refresh_bills", "refresh_today_tab"),
        "funds":    ("refresh_funds", "refresh_today_tab"),
        "goals":    ("refresh_goals", "refresh_today_tab"),
        "income":   ("refresh_income_tab", "refresh_today_tab"),
    }

    def _after_commit(self, which: str, toast: str = None):
        """Refresh only the tabs impacted by `which` and save state.

        `which` is one of bills/funds/goals/income. We deliberately skip the
        review tab (expensive — ~300ms) and transactions tab since they're
        driven by imported transactions, not Gerald-created records.
        """
        app = self.app
        try:
            app.save_state()
        except Exception:
            pass
        for fn in self._REFRESH_MAP.get(which, ("refresh_today_tab",)):
            if hasattr(app, fn):
                try:
                    getattr(app, fn)()
                except Exception:
                    pass
        if hasattr(app, "_show_toast"):
            msg = toast or f"Gerald updated your {which}."
            app._show_toast(msg, "success")

    # ── Undo ─────────────────────────────────────────────────────────────

    def _apply_undo_entry(self, entry: dict):
        """Perform a single undo step. Returns (label, base_kind) or raises."""
        app = self.app
        kind = entry["kind"]; idx = entry.get("index", -1); snapshot = entry.get("snapshot")
        if kind == "bill" and 0 <= idx < len(app.state.bills):
            removed = app.state.bills.pop(idx); return f"bill \"{removed.name}\"", "bill"
        if kind == "fund" and 0 <= idx < len(app.state.funds):
            removed = app.state.funds.pop(idx); return f"fund \"{removed.name}\"", "fund"
        if kind == "goal" and 0 <= idx < len(app.state.goals):
            removed = app.state.goals.pop(idx); return f"goal \"{removed.name}\"", "goal"
        if kind == "income" and 0 <= idx < len(app.state.incomes):
            removed = app.state.incomes.pop(idx); return f"pay (${removed.amount:,.2f})", "income"
        if kind in ("restore_bill", "restore_fund", "restore_goal") and snapshot is not None:
            base_kind = kind.split("_", 1)[1]
            coll = {"bill": app.state.bills, "fund": app.state.funds, "goal": app.state.goals}[base_kind]
            insert_at = min(max(idx, 0), len(coll))
            coll.insert(insert_at, snapshot)
            return f"{base_kind} \"{snapshot.name}\" (restored)", base_kind
        if kind == "contrib":
            tk = entry["target_kind"]; prev = entry["prev_saved"]
            coll = {"bill": app.state.bills, "fund": app.state.funds, "goal": app.state.goals}[tk]
            if not (0 <= idx < len(coll)):
                raise ValueError("target item gone")
            coll[idx].current_saved = prev
            return f"contribution to {tk} \"{coll[idx].name}\" (reset to ${prev:,.2f})", tk
        if kind == "rename":
            tk = entry["target_kind"]; prev = entry["prev_name"]
            coll = {"bill": app.state.bills, "fund": app.state.funds, "goal": app.state.goals}[tk]
            if not (0 <= idx < len(coll)):
                raise ValueError("target item gone")
            old_name = coll[idx].name
            coll[idx].name = prev
            return f"{tk} name \"{old_name}\" → \"{prev}\"", tk
        if kind == "update":
            tk = entry["target_kind"]; field = entry["field"]; prev = entry["prev"]
            coll = {"bill": app.state.bills, "fund": app.state.funds, "goal": app.state.goals}[tk]
            if not (0 <= idx < len(coll)):
                raise ValueError("target item gone")
            setattr(coll[idx], field, prev)
            return f"{tk} \"{coll[idx].name}\" {field} reverted", tk
        if kind == "alias_set":
            key = entry["key"]; prev = entry.get("prev")
            if prev is None:
                app.state.gerald_aliases.pop(key, None)
            else:
                app.state.gerald_aliases[key] = prev
            return f"alias \"{key}\" reverted", "alias"
        if kind == "alias_remove":
            app.state.gerald_aliases[entry["key"]] = entry["prev"]
            return f"alias \"{entry['key']}\" restored", "alias"
        if kind == "reminder_add":
            rid = entry["reminder_id"]
            app.state.gerald_reminders = [r for r in app.state.gerald_reminders if r.get("id") != rid]
            return f"reminder #{rid} removed", "reminder"
        if kind == "tx_tag":
            fp = entry["fingerprint"]; prev = entry["prev"]
            for tx in app.state.transactions:
                if tx.fingerprint == fp:
                    tx.category = prev
                    return "tx tag reverted", "tx"
            raise ValueError("transaction gone")
        raise ValueError("unknown undo kind")

    def _handle_undo(self, text: str = ""):
        if not self.undo_stack:
            return ("Nothing to undo.", "normal")
        lower = (text or "").lower()
        # "undo last N" / "undo N actions" — only count as multi-undo when explicit number given
        m = re.search(r"\blast\s+(\d+)\b|\b(\d+)\s+(?:actions?|steps?|changes?)\b", lower)
        count = int(m.group(1) or m.group(2)) if m else 0
        if count > 1:
            done = []
            for _ in range(min(count, len(self.undo_stack))):
                entry = self.undo_stack.pop()
                try:
                    label, base = self._apply_undo_entry(entry)
                except Exception:
                    continue
                done.append(label)
                self._after_commit(base + "s" if base != "income" else "income")
            if not done:
                return ("Couldn't undo those — items may be gone.", "normal")
            return (f"Reverted {len(done)} action{'s' if len(done) != 1 else ''}:\n• " + "\n• ".join(done), "normal")
        # "undo contribution to X" / "undo rename X" / "undo update to X" — find matching entry
        specific_kind = None
        if re.search(r"\b(contribution|contrib)\b", lower): specific_kind = "contrib"
        elif re.search(r"\brename\b", lower):                specific_kind = "rename"
        elif re.search(r"\bupdate|change|edit\b", lower):     specific_kind = "update"
        elif re.search(r"\badd(?:ed)?\b", lower):             specific_kind = ("bill", "fund", "goal", "income")
        elif re.search(r"\bdelete|remove|restore\b", lower):  specific_kind = ("restore_bill", "restore_fund", "restore_goal")
        # Target name search in undo_stack labels
        # "undo X where label contains X"
        # Strip leading "undo" and the kind keyword
        rest = re.sub(r"^\s*undo(\s+|$)", "", lower)
        rest = re.sub(r"^(the\s+)?(last\s+)?(contribution|contrib|rename|update|change|edit|add|delete|remove|restore)\s*(to\s+)?", "", rest)
        rest = _gerald_clean_name(rest).lower().strip()
        # Strip bare numbers — they shouldn't be treated as a name query
        if re.fullmatch(r"\d+", rest):
            rest = ""
        # Walk stack from top searching for match
        if specific_kind or rest:
            for i in range(len(self.undo_stack) - 1, -1, -1):
                entry = self.undo_stack[i]
                if specific_kind:
                    ek = entry["kind"]
                    if isinstance(specific_kind, tuple):
                        if ek not in specific_kind:
                            continue
                    elif ek != specific_kind:
                        continue
                if rest:
                    lbl = entry.get("label", "").lower()
                    if rest not in lbl:
                        continue
                # Found it
                self.undo_stack.pop(i)
                try:
                    label, base = self._apply_undo_entry(entry)
                except Exception as e:
                    return (f"Couldn't undo that: {e}.", "normal")
                self._after_commit(base + "s" if base != "income" else "income")
                return (f"Reverted — {label}.", "normal")
            if rest:
                return (f"No recent action matched \"{rest}\".", "normal")
        # Default: pop the top
        entry = self.undo_stack.pop()
        try:
            label, base = self._apply_undo_entry(entry)
        except Exception as e:
            return (f"Undo failed: {e}.", "normal")
        self._after_commit(base + "s" if base != "income" else "income")
        return (f"Reverted — {label}.", "normal")

    # ── List / navigate / summary / misc ─────────────────────────────────

    def _handle_list_bills(self):
        bills = self.app.state.bills
        if not bills:
            return ("No bills yet. Add one with \"add bill <name> $<amount> <frequency> due <date>\".", "normal")
        ordered = sorted(enumerate(bills), key=lambda p: p[1].due_date)
        self._set_last_list("bill", [idx for idx, _b in ordered])
        lines = [f"{i+1}. {b.name} · ${b.amount:,.2f} · {b.frequency} · due {b.due_date.isoformat()}"
                 for i, (_idx, b) in enumerate(ordered)]
        return (f"{len(bills)} bill{'s' if len(bills) != 1 else ''}:\n" + "\n".join(lines[:12]) +
                ("\n…" if len(bills) > 12 else ""), "normal")

    def _handle_list_funds(self):
        funds = self.app.state.funds
        if not funds:
            return ("No funds yet. Try \"add fund Vacation target $5000 by December\".", "normal")
        self._set_last_list("fund", list(range(len(funds))))
        lines = []
        for i, f in enumerate(funds):
            pct = 0 if f.target_amount <= 0 else (f.current_saved / f.target_amount) * 100
            td = f" · by {f.target_date.isoformat()}" if f.target_date else ""
            lines.append(f"{i+1}. {f.name} · ${f.current_saved:,.0f}/${f.target_amount:,.0f} ({pct:.0f}%){td}")
        return (f"{len(funds)} fund{'s' if len(funds) != 1 else ''}:\n" + "\n".join(lines), "normal")

    def _handle_list_goals(self):
        goals = self.app.state.goals
        if not goals:
            return ("No goals yet. Try \"add goal Emergency Fund $10000\".", "normal")
        self._set_last_list("goal", list(range(len(goals))))
        lines = []
        for i, g in enumerate(goals):
            pct = 0 if g.target_amount <= 0 else (g.current_saved / g.target_amount) * 100
            lines.append(f"{i+1}. {g.name} · ${g.current_saved:,.0f}/${g.target_amount:,.0f} ({pct:.0f}%)")
        return (f"{len(goals)} goal{'s' if len(goals) != 1 else ''}:\n" + "\n".join(lines), "normal")

    def _handle_list_incomes(self):
        incomes = self.app.state.incomes
        if not incomes:
            return ("No pay logged yet. Tell me \"I got paid $2500 today\" to record one.", "normal")
        recent = sorted(incomes, key=lambda x: x.received_on, reverse=True)[:6]
        lines = [f"{i.received_on.isoformat()} · ${i.amount:,.2f} · {i.source}" for i in recent]
        total = sum(i.amount for i in incomes)
        return (f"Last {len(recent)} pay record{'s' if len(recent) != 1 else ''} "
                f"(lifetime ${total:,.0f} across {len(incomes)}):\n" + "\n".join(lines), "normal")

    def _handle_delete(self, kind: str, text: str):
        # Expect a name after the delete keyword
        m = re.search(rf"\b(?:delete|remove|drop|get rid of)\b\s+(?:the\s+)?(?:{kind})\s+(.+)$", text, re.IGNORECASE)
        if not m:
            m = re.search(rf"\b(?:delete|remove|drop|get rid of)\b\s+(.+?)(?:\s+{kind}s?)?$", text, re.IGNORECASE)
        query = _gerald_clean_name(m.group(1)) if m else ""
        if not query:
            return (f"Which {kind}? Give me the name — e.g. \"delete {kind} Netflix\".", "normal")
        coll = {"bill": self.app.state.bills, "fund": self.app.state.funds, "goal": self.app.state.goals}[kind]
        candidates = _gerald_find_candidates(coll, query)
        if len(candidates) > 1:
            return self._disambiguate(kind, [(kind, c) for c in candidates], "delete", {})
        idx = candidates[0] if candidates else None
        if idx is None:
            return (f"No {kind} matching \"{query}\". Try \"list {kind}s\" to see what's there.", "normal")
        removed = coll.pop(idx)
        # Record undo (re-add the exact snapshot)
        self.undo_stack.append({"kind": "restore_" + kind, "index": idx, "snapshot": removed,
                                 "label": f"deleted {kind} \"{removed.name}\""})
        self._after_commit(kind + "s")
        return (f"Deleted {kind} \"{removed.name}\". \"undo\" to restore.", "normal")

    def _handle_mark_paid(self, text: str):
        m = re.search(r"\bmark\b\s+(.+?)\s+\bpaid\b", text, re.IGNORECASE)
        if not m:
            m = re.search(r"\bpaid\s+(?:off\s+)?(.+)$", text, re.IGNORECASE)
        raw_name = m.group(1) if m else ""
        query = _gerald_clean_name(raw_name)
        if not query:
            # Try last-target if it's a bill
            kind, item = self._resolve_last_target()
            if kind == "bill" and item is not None:
                idx = self.app.state.bills.index(item)
                query = item.name
            else:
                return ("Which bill? Try \"mark Netflix paid\".", "normal")
        else:
            # Try pronoun resolution
            kind_r, item_r = self._resolve_reference(raw_name)
            if kind_r == "bill" and item_r is not None:
                idx = self.app.state.bills.index(item_r)
            else:
                candidates = _gerald_find_candidates(self.app.state.bills, query)
                if len(candidates) > 1:
                    return self._disambiguate("bill", [("bill", c) for c in candidates],
                                               "mark_paid", {})
                idx = candidates[0] if candidates else None
        if idx is None:
            return (f"No bill matching \"{query}\". \"list bills\" shows what's there.", "normal")
        bill = self.app.state.bills[idx]
        try:
            self.app.engine.mark_bill_paid(bill)
        except Exception as e:
            return (f"Couldn't mark paid: {e}.", "normal")
        self._after_commit("bills")
        self._set_last_target("bill", idx)
        return (f"{bill.name} marked paid. Next due: {bill.due_date.isoformat()}.", "wink")

    def _handle_summary(self):
        s = self.app.state
        total_bills = sum(b.amount for b in s.bills)
        total_funds_target = sum(f.target_amount for f in s.funds)
        total_funds_saved = sum(f.current_saved for f in s.funds)
        total_goals_target = sum(g.target_amount for g in s.goals)
        total_goals_saved = sum(g.current_saved for g in s.goals)
        recent_pay = sorted(s.incomes, key=lambda x: x.received_on, reverse=True)[:1]
        last_pay = f"${recent_pay[0].amount:,.0f} on {recent_pay[0].received_on.isoformat()}" if recent_pay else "none yet"
        streak = s.game.streak_pays
        lines = [
            f"Bills: {len(s.bills)} · ${total_bills:,.0f}/cycle",
            f"Funds: {len(s.funds)} · ${total_funds_saved:,.0f}/${total_funds_target:,.0f}",
            f"Goals: {len(s.goals)} · ${total_goals_saved:,.0f}/${total_goals_target:,.0f}",
            f"Last pay: {last_pay}  ·  Streak: {streak}",
        ]
        return ("Here's the state of play:\n" + "\n".join(lines), "normal")

    def _handle_navigate(self, lower: str):
        name_map = {
            "today": "today", "dashboard": "today",
            "setup": "setup", "bills": "setup", "funds": "setup", "goals": "setup",
            "score": "score", "income": "income", "log pay": "income",
            "transactions": "transactions", "review": "review", "analysis": "review",
            "collection": "collection", "avatar": "character",
        }
        for key, tab in name_map.items():
            if re.search(rf"\b{re.escape(key)}\b", lower):
                if hasattr(self.app, "_show_page"):
                    self.app._show_page(tab)
                    if tab == "setup":
                        sub = "bills" if "bill" in lower else "funds" if "fund" in lower else "goals" if "goal" in lower else None
                        if sub and hasattr(self.app, "_show_setup_sub"):
                            self.app._show_setup_sub(sub)
                return (f"Jumping to {tab.title()}.", "wink")
        return ("Where to? Try \"today\", \"setup\", \"score\", \"income\", or \"review\".", "normal")

