# Auto-update
# -----------------------------

class AppUpdater:
    """Manifest-driven updater for frozen (PyInstaller) builds.

    Flow:
      1. check_async — fetch UPDATE_MANIFEST_URL off-thread, compare versions.
      2. download_async — stream the new .exe to <name>.new.exe with progress.
      3. apply_and_restart — write a .bat helper that waits for this PID to
         exit, renames files, relaunches the new exe. No admin rights needed
         as long as the user can write to the exe's folder.

    No-ops gracefully when run from source (not frozen) or when
    UPDATE_MANIFEST_URL is empty.
    """

    def __init__(self, app: "BudgetApp"):
        self.app = app
        self.current_version = APP_VERSION
        self.manifest: Optional[dict] = None
        self._checking = False
        self._downloading = False

    def is_frozen(self) -> bool:
        return bool(getattr(sys, "frozen", False))

    def enabled(self) -> bool:
        return self.is_frozen() and bool(UPDATE_MANIFEST_URL)

    @staticmethod
    def _parse_version(v: str) -> tuple:
        parts = []
        for p in (v or "").strip().lstrip("v").split("."):
            try:
                parts.append(int(re.match(r"\d+", p).group(0)) if re.match(r"\d+", p) else 0)
            except Exception:
                parts.append(0)
        return tuple(parts) or (0,)

    def is_newer(self, remote_ver: str) -> bool:
        try:
            return self._parse_version(remote_ver) > self._parse_version(self.current_version)
        except Exception:
            return False

    def check_async(self, on_result):
        """Fetch manifest off-thread. on_result(manifest_or_None, error_or_None)."""
        if self._checking:
            return
        if not self.enabled():
            on_result(None, "disabled")
            return
        self._checking = True

        def work():
            try:
                import urllib.request, ssl
                req = urllib.request.Request(
                    UPDATE_MANIFEST_URL,
                    headers={"User-Agent": f"BudgetPlanner/{APP_VERSION}"},
                )
                ctx = ssl.create_default_context()
                with urllib.request.urlopen(req, timeout=UPDATE_CHECK_TIMEOUT_SEC, context=ctx) as resp:
                    raw = resp.read()
                manifest = json.loads(raw.decode("utf-8", errors="replace"))
                self.manifest = manifest
                self.app.after(0, lambda: on_result(manifest, None))
            except Exception as e:
                self.app.after(0, lambda err=e: on_result(None, str(err)))
            finally:
                self._checking = False

        threading.Thread(target=work, daemon=True).start()

    def download_async(self, url: str, expected_sha: Optional[str], on_progress, on_done):
        """Stream to <exe>.new.exe. on_progress(done, total); on_done(ok, path_or_error)."""
        if self._downloading:
            return
        self._downloading = True
        exe_path = Path(sys.executable)
        new_path = exe_path.with_name(exe_path.stem + ".new" + exe_path.suffix)

        def work():
            try:
                import urllib.request, hashlib
                req = urllib.request.Request(
                    url,
                    headers={"User-Agent": f"BudgetPlanner/{APP_VERSION}"},
                )
                with urllib.request.urlopen(req, timeout=30) as resp:
                    total = int(resp.headers.get("Content-Length") or 0)
                    h = hashlib.sha256()
                    downloaded = 0
                    last_tick = 0
                    with open(new_path, "wb") as f:
                        while True:
                            chunk = resp.read(65536)
                            if not chunk:
                                break
                            f.write(chunk)
                            h.update(chunk)
                            downloaded += len(chunk)
                            # Throttle progress callbacks to ~20/sec
                            if downloaded - last_tick >= 262144 or downloaded == total:
                                last_tick = downloaded
                                self.app.after(0, lambda d=downloaded, t=total: on_progress(d, t))
                if expected_sha:
                    if h.hexdigest().lower() != expected_sha.lower():
                        try: new_path.unlink()
                        except Exception: pass
                        self.app.after(0, lambda: on_done(False, "Checksum mismatch — download rejected."))
                        return
                self.app.after(0, lambda p=str(new_path): on_done(True, p))
            except Exception as e:
                try: new_path.unlink()
                except Exception: pass
                self.app.after(0, lambda err=str(e): on_done(False, err))
            finally:
                self._downloading = False

        threading.Thread(target=work, daemon=True).start()

    def apply_and_restart(self, new_exe_path: str):
        """Spawn a detached .bat that swaps files once this process exits, then quit."""
        old = Path(sys.executable)
        new = Path(new_exe_path)
        if not new.exists():
            raise FileNotFoundError(f"New exe missing: {new}")
        backup = old.with_name(old.stem + ".old" + old.suffix)
        bat = old.parent / "_budget_update.bat"
        pid = os.getpid()

        # The .bat polls until our PID is gone, swaps files, relaunches, self-deletes.
        script = (
            "@echo off\r\n"
            "setlocal\r\n"
            ":wait\r\n"
            f'tasklist /FI "PID eq {pid}" 2>NUL | find "{pid}" >NUL\r\n'
            "if %ERRORLEVEL%==0 (\r\n"
            "  timeout /T 1 /NOBREAK >NUL\r\n"
            "  goto wait\r\n"
            ")\r\n"
            f'if exist "{backup}" del /F /Q "{backup}" >NUL 2>&1\r\n'
            f'move /Y "{old}" "{backup}" >NUL\r\n'
            f'move /Y "{new}" "{old}" >NUL\r\n'
            f'if exist "{old}" (\r\n'
            f'  start "" "{old}"\r\n'
            f'  timeout /T 3 /NOBREAK >NUL\r\n'
            f'  del /F /Q "{backup}" >NUL 2>&1\r\n'
            ") else (\r\n"
            f'  rem swap failed — roll back\r\n'
            f'  if exist "{backup}" move /Y "{backup}" "{old}" >NUL\r\n'
            f'  start "" "{old}"\r\n'
            ")\r\n"
            '(goto) 2>nul & del "%~f0"\r\n'
        )
        bat.write_text(script, encoding="utf-8")

        DETACHED = 0x00000008   # subprocess.DETACHED_PROCESS (not exposed on all Py versions)
        NEW_GROUP = 0x00000200
        flags = 0
        try:
            flags = DETACHED | NEW_GROUP
        except Exception:
            flags = 0
        try:
            subprocess.Popen(["cmd.exe", "/c", str(bat)],
                             creationflags=flags,
                             close_fds=True)
        except Exception:
            # Fallback — no special flags
            subprocess.Popen(["cmd.exe", "/c", str(bat)], close_fds=True)

        try:
            self.app.save_state()
        except Exception:
            pass
        try:
            self.app.destroy()
        except Exception:
            pass
        sys.exit(0)


