    def _autohide_scrollbar(self, vbar, manager="grid", **place_kwargs):
        """Return a yscrollcommand callback that hides vbar when the view fully fits.
        manager: 'grid' or 'pack'. place_kwargs are re-applied when re-showing."""
        shown = [True]
        def _set(lo, hi):
            try:
                lo_f, hi_f = float(lo), float(hi)
            except (TypeError, ValueError):
                lo_f, hi_f = 0.0, 1.0
            vbar.set(lo, hi)
            needs = not (lo_f <= 0.0 and hi_f >= 1.0)
            if needs and not shown[0]:
                if manager == "grid":
                    vbar.grid(**place_kwargs)
                else:
                    vbar.pack(**place_kwargs)
                shown[0] = True
            elif (not needs) and shown[0]:
                if manager == "grid":
                    vbar.grid_remove()
                else:
                    vbar.pack_forget()
                shown[0] = False
        return _set

    def _make_scrolled_text(self, parent, height=18):
        parent.rowconfigure(0, weight=1)
        parent.columnconfigure(0, weight=1)
        text = tk.Text(parent, wrap="word", width=1, height=height, bg=UI_SURFACE, fg=UI_TEXT, relief="flat", font=FONT_BODY, padx=SP_MD, pady=SP_MD, highlightthickness=1, highlightbackground=UI_BORDER, insertbackground=UI_TEXT)
        scroll = ttk.Scrollbar(parent, orient="vertical", command=text.yview)
        text.grid(row=0, column=0, sticky="nsew")
        scroll.grid(row=0, column=1, sticky="ns")
        text.configure(yscrollcommand=self._autohide_scrollbar(scroll, "grid", row=0, column=1, sticky="ns"))
        return text

    @staticmethod
    def _draw_gradient(canvas, color_top, color_bot, width=800, height=200):
        """Draw a vertical gradient on a canvas using thin horizontal lines."""
        canvas.delete("gradient")
        r1, g1, b1 = int(color_top[1:3], 16), int(color_top[3:5], 16), int(color_top[5:7], 16)
        r2, g2, b2 = int(color_bot[1:3], 16), int(color_bot[3:5], 16), int(color_bot[5:7], 16)
        steps = max(height // 2, 1)
        for i in range(steps):
            t = i / max(steps - 1, 1)
            r = int(r1 + (r2 - r1) * t)
            g = int(g1 + (g2 - g1) * t)
            b = int(b1 + (b2 - b1) * t)
            color = f"#{r:02x}{g:02x}{b:02x}"
            y = i * height // steps
            canvas.create_line(0, y, width, y, fill=color, tags="gradient")

    def _gradient_hero(self, parent, height=140, top_color=None, bot_color=None):
        """Create a gradient background hero section. Returns (canvas, content_frame).
        The canvas auto-sizes to fit its content frame height."""
        tc = top_color or UI_GRADIENT_TOP
        bc = bot_color or UI_GRADIENT_BOT
        canvas = tk.Canvas(parent, height=height, bg=tc, highlightthickness=0)
        content = tk.Frame(canvas, bg=tc)
        win = canvas.create_window(0, 0, window=content, anchor="nw")
        def _on_canvas_resize(e):
            self._draw_gradient(canvas, tc, bc, e.width, e.height)
            canvas.itemconfigure(win, width=e.width)
            canvas.tag_lower("gradient")
        def _on_content_resize(_e=None):
            # Let content dictate canvas height
            content.update_idletasks()
            req_h = content.winfo_reqheight()
            if req_h > 0 and req_h != canvas.winfo_height():
                canvas.configure(height=req_h)
        canvas.bind("<Configure>", _on_canvas_resize)
        content.bind("<Configure>", _on_content_resize)
        return canvas, content

    def _apply_zebra(self, tree):
        """Apply alternating row colors to a Treeview for better readability."""
        tree.tag_configure("zebra_even", background=UI_SURFACE)
        tree.tag_configure("zebra_odd", background="#101c30")

    def _restripe_tree(self, tree):
        """Re-apply zebra stripes after inserting/deleting rows.
        Zebra tag is prepended so semantic tags (overdue, urgent, etc.) override it."""
        for i, iid in enumerate(tree.get_children("")):
            existing = list(tree.item(iid, "tags") or ())
            cleaned = [t for t in existing if not t.startswith("zebra_")]
            stripe = "zebra_even" if i % 2 == 0 else "zebra_odd"
            tree.item(iid, tags=[stripe] + cleaned)

    @staticmethod
    def _progress_bar(saved: float, target: float, width: int = 8) -> str:
        if target <= 0:
            return "—"
        frac = min(saved / target, 1.0)
        filled = round(frac * width)
        bar = "\u2588" * filled + "\u2591" * (width - filled)
        return f"{bar} {frac * 100:.0f}%"

    def _make_sortable(self, tree):
        """Bind column headers to sort rows on click."""
        for col in tree["columns"]:
            tree.heading(col, command=lambda _c=col: self._sort_tree_column(tree, _c, False))
        tree.heading("#0", command=lambda: self._sort_tree_column(tree, "#0", False))

    def _sort_tree_column(self, tree, col, reverse):
        data = []
        for iid in tree.get_children(""):
            val = tree.item(iid, "text") if col == "#0" else tree.set(iid, col)
            data.append((val, iid))
        try:
            data.sort(key=lambda x: float(x[0].replace("$", "").replace(",", "").split()[0]), reverse=reverse)
        except (ValueError, IndexError):
            data.sort(key=lambda x: x[0].lower(), reverse=reverse)
        for idx, (_val, iid) in enumerate(data):
            tree.move(iid, "", idx)
        tree.heading(col, command=lambda: self._sort_tree_column(tree, col, not reverse))

    def _apply_tree_tags(self, tree):
        tree.tag_configure("overdue",  background=UI_DANGER_SOFT,  foreground=UI_RUBY)
        tree.tag_configure("urgent",   background=UI_WARNING_SOFT, foreground=UI_GOLD)
        tree.tag_configure("good",     background=UI_SUCCESS_SOFT, foreground=UI_EMERALD)
        tree.tag_configure("high",     background=UI_SUCCESS_SOFT, foreground=UI_EMERALD)
        tree.tag_configure("medium",   background=UI_WARNING_SOFT, foreground=UI_GOLD)
        tree.tag_configure("low",      background=UI_DANGER_SOFT,  foreground=UI_RUBY)
        tree.tag_configure("review",   background=UI_WARNING_SOFT, foreground=UI_GOLD)
        tree.tag_configure("matched",  background=UI_SUCCESS_SOFT, foreground=UI_EMERALD)

    def _card_frame(self, parent, padx=16, pady=14, **kwargs) -> tk.Frame:
        """A surface card with subtle border."""
        return tk.Frame(parent, bg=UI_SURFACE, padx=padx, pady=pady,
                        highlightthickness=1, highlightbackground=UI_BORDER, **kwargs)

    def _attach_info_tooltip(self, widget, text: str, *, wraplength: int = 280):
        """Hover-tooltip: show a small borderless Toplevel near `widget`
        while the mouse is over it. Used for info/help icons."""
        state = {"tip": None, "show_job": None}

        def _close():
            job = state.get("show_job")
            if job is not None:
                try: widget.after_cancel(job)
                except tk.TclError: pass
                state["show_job"] = None
            tip = state.get("tip")
            if tip is not None:
                try: tip.destroy()
                except tk.TclError: pass
                state["tip"] = None

        def _show():
            state["show_job"] = None
            if state.get("tip") is not None:
                return
            try:
                x = widget.winfo_rootx() + widget.winfo_width() + 8
                y = widget.winfo_rooty() + widget.winfo_height() // 2 - 12
            except tk.TclError:
                return
            tip = tk.Toplevel(self)
            tip.wm_overrideredirect(True)
            try: tip.wm_attributes("-topmost", True)
            except tk.TclError: pass
            outer = tk.Frame(tip, bg=UI_ACCENT, padx=1, pady=1)
            outer.pack()
            inner = tk.Frame(outer, bg=UI_SURFACE2, padx=SP_SM, pady=SP_XS)
            inner.pack()
            tk.Label(inner, text=text, bg=UI_SURFACE2, fg=UI_TEXT,
                     font=FONT_SMALL, wraplength=wraplength, justify="left",
                     anchor="w").pack(anchor="w")
            tip.geometry(f"+{x}+{y}")
            state["tip"] = tip

        def _enter(_e=None):
            if state.get("show_job") is None and state.get("tip") is None:
                state["show_job"] = widget.after(220, _show)

        widget.bind("<Enter>", _enter)
        widget.bind("<Leave>", lambda _e: _close())
        widget.bind("<Button-1>", lambda _e: (_close(), _show()))
        widget.bind("<Destroy>", lambda _e: _close())

    def _info_icon(self, parent, tooltip_text: str, *, bg=None, glyph="\u24D8"):
        """Small clickable ⓘ label that reveals `tooltip_text` on hover/click.
        Pass `bg` to match the surrounding surface color."""
        bg_color = bg if bg is not None else UI_SURFACE
        lbl = tk.Label(parent, text=glyph, bg=bg_color, fg=UI_MUTED,
                       font=FONT_SMALL, cursor="question_arrow")
        self._attach_info_tooltip(lbl, tooltip_text)
        return lbl

    def _attach_tree_empty_state(self, tree, host, icon: str, headline: str,
                                   subtext: str, cta_label: str = "", cta_cb=None):
        """Attach an empty-state overlay to a tree's host frame.
        The overlay is placed centered and shown when the tree has zero rows."""
        empty = tk.Frame(host, bg=UI_SURFACE)
        tk.Label(empty, text=icon, bg=UI_SURFACE, fg=UI_GOLD,
                 font=FONT_DISPLAY_XL).pack(pady=(0, SP_XS))
        tk.Label(empty, text=headline, bg=UI_SURFACE, fg=UI_TEXT,
                 font=FONT_HEADING).pack()
        tk.Label(empty, text=subtext, bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_SMALL, wraplength=360, justify="center").pack(pady=(SP_XS, SP_SM))
        if cta_label and cta_cb is not None:
            ttk.Button(empty, text=cta_label, style="Accent.TButton",
                       command=cta_cb).pack()
        tree._empty_state_frame = empty
        tree._empty_state_visible = False

    def _toggle_tree_empty_state(self, tree):
        """Show empty-state overlay iff tree has no rows. Call after refresh."""
        empty = getattr(tree, "_empty_state_frame", None)
        if empty is None:
            return
        has_rows = bool(tree.get_children())
        if has_rows and getattr(tree, "_empty_state_visible", False):
            empty.place_forget()
            tree._empty_state_visible = False
        elif not has_rows and not getattr(tree, "_empty_state_visible", False):
            empty.place(relx=0.5, rely=0.5, anchor="center")
            empty.lift()
            tree._empty_state_visible = True

    def _create_page_frame(self, parent, key: str):
        container = tk.Frame(parent, bg=UI_BG)
        container.grid(row=0, column=0, sticky="nsew")
        container.columnconfigure(0, weight=1)
        container.rowconfigure(0, weight=1)

        canvas = tk.Canvas(container, bg=UI_BG, highlightthickness=0)
        vbar = ttk.Scrollbar(container, orient="vertical", command=canvas.yview)
        canvas.grid(row=0, column=0, sticky="nsew")
        vbar.grid(row=0, column=1, sticky="ns")
        canvas.configure(yscrollcommand=self._autohide_scrollbar(vbar, "grid", row=0, column=1, sticky="ns"))

        inner = ttk.Frame(canvas)
        win = canvas.create_window((0, 0), window=inner, anchor="nw")

        def _on_inner_config(_e=None):
            canvas.configure(scrollregion=canvas.bbox("all"))

        def _on_canvas_config(e):
            canvas.itemconfigure(win, width=e.width)

        inner.bind("<Configure>", _on_inner_config)
        canvas.bind("<Configure>", _on_canvas_config)

        self._scroll_canvases.append(canvas)
        self._scroll_canvas_page[id(canvas)] = key
        self.page_frames[key] = container
        return inner

    def _create_nav_button(self, parent, key: str, title: str, subtitle: str, primary: bool):
        display_title = self.nav_compact_labels.get(key, title)
        # Outer container — active indicator bar + content
        wrap = tk.Frame(parent, bg=UI_PANEL_ALT, cursor="hand2")
        wrap.columnconfigure(1, weight=1)
        # Left active-state indicator — 2px, invisible except when current
        accent_bar = tk.Frame(wrap, bg=UI_PANEL_ALT, width=2)
        accent_bar.grid(row=0, column=0, sticky="ns")
        accent_bar.grid_propagate(False)
        # Content area
        content = tk.Frame(wrap, bg=UI_PANEL_ALT, padx=SP_MD + 2, pady=SP_SM + 1, cursor="hand2")
        content.grid(row=0, column=1, sticky="nsew")
        content.columnconfigure(0, weight=1)
        # All nav items get the same refined treatment — primary vs secondary
        # now differs only by subtitle visibility, not chunky weight differences.
        title_font = FONT_BODY_BOLD
        title_fg = UI_TEXT if primary else UI_MUTED
        subtitle_fg = UI_MUTED if primary else "#5a5e6b"
        title_lbl = tk.Label(content, text=display_title, bg=UI_PANEL_ALT, fg=title_fg,
                             font=title_font, anchor="w", cursor="hand2")
        title_lbl.grid(row=0, column=0, sticky="w")
        subtitle_lbl = tk.Label(content, text=subtitle, bg=UI_PANEL_ALT, fg=subtitle_fg,
                                font=FONT_MICRO, anchor="w", cursor="hand2")
        subtitle_lbl.grid(row=1, column=0, sticky="w", pady=(1, 0))
        self.page_button_meta[key] = {"frame": wrap, "content": content, "accent": accent_bar,
                                      "title": title_lbl, "subtitle": subtitle_lbl,
                                      "pill": None, "primary": primary}

        def _go(_event=None):
            self._show_page(key)

        def _hover_enter(_event=None):
            if self.current_page_key != key:
                for w in [content, title_lbl, subtitle_lbl]:
                    w.configure(bg=UI_SURFACE_HOVER)
                title_lbl.configure(fg=UI_TEXT)

        def _hover_leave(_event=None):
            if self.current_page_key != key:
                for w in [content, title_lbl, subtitle_lbl]:
                    w.configure(bg=UI_PANEL_ALT)
                meta = self.page_button_meta[key]
                title_lbl.configure(fg=UI_TEXT if meta["primary"] else UI_MUTED)

        for w in [wrap, content, title_lbl, subtitle_lbl]:
            w.bind("<Button-1>", _go)
            w.bind("<Enter>", _hover_enter)
            w.bind("<Leave>", _hover_leave)
        self.nav_buttons[key] = wrap
        return wrap

    def _nav_badge_counts(self) -> dict:
        """Compute pending-action counts per nav key."""
        counts: dict = {}
        # Transactions: outgoing preview rows still needing review
        try:
            needs_review = sum(1 for t in self.latest_import
                               if t.direction() == "out" and not t.user_verified
                               and t.matched_type != "ignore")
            if needs_review:
                counts["transactions"] = needs_review
        except Exception:
            pass
        # Today: overdue bills get a count; else pay-overdue nudge falls back to "!"
        try:
            today = date.today()
            overdue_bills = sum(1 for b in self.state.bills
                                if b.due_date and b.due_date < today)
            if overdue_bills:
                counts["today"] = overdue_bills
            elif hasattr(self, "_check_pay_overdue") and self._check_pay_overdue():
                counts["today"] = "!"
        except Exception:
            pass
        # Score: unclaimed season tiers
        try:
            g = self.state.game
            claimable = 0
            for i, tier in enumerate(SEASON_TIERS):
                if i in g.season_claimed_tiers:
                    continue
                if g.season_xp >= tier[0]:
                    claimable += 1
            if claimable:
                counts["score"] = claimable
        except Exception:
            pass
        # Setup: nothing configured yet
        try:
            if not self.state.bills and not self.state.funds and not self.state.goals:
                counts["setup"] = "!"
        except Exception:
            pass
        return counts

    def _update_nav_badges(self):
        """Attach/update a small colored pill on each nav entry with pending action."""
        if not hasattr(self, "page_button_meta"):
            return
        counts = self._nav_badge_counts()
        color_map = {"transactions": UI_RUBY, "today": UI_GOLD,
                     "score": UI_EMERALD, "setup": UI_SAPPHIRE}
        for key, meta in self.page_button_meta.items():
            content = meta["content"]
            existing = meta.get("pill")
            val = counts.get(key)
            if val is None:
                if existing is not None:
                    try:
                        existing.destroy()
                    except Exception:
                        pass
                    meta["pill"] = None
                continue
            color = color_map.get(key, UI_RUBY)
            text = str(val)
            if existing is None:
                pill = tk.Label(content, text=text, bg=color, fg="#ffffff",
                                font=FONT_MICRO, padx=6, pady=1)
                pill.grid(row=0, column=1, sticky="e", padx=(SP_SM, 0))
                meta["pill"] = pill
            else:
                try:
                    existing.configure(text=text, bg=color)
                except Exception:
                    pass

    def _show_page(self, key: str):
        # Route build sub-tab keys to the merged setup tab
        if key in {"bills", "funds", "goals", "investments", "rules", "accounts"} and key not in self.page_frames:
            self._show_page("setup")
            if hasattr(self, "_show_setup_sub"):
                self._show_setup_sub(key)
            return
        if key not in self.page_frames:
            return
        self.current_page_key = key
        self._update_nav_badges()
        self.page_frames[key].tkraise()
        # Refresh scrollregion for the raised page so mousewheel works immediately
        for c in self._scroll_canvases:
            if self._scroll_canvas_page.get(id(c)) == key:
                c.configure(scrollregion=c.bbox("all") or "0 0 0 0")
        # Stop/start avatar animation based on visible tab
        if key != "character" and hasattr(self, "_avatar_anim_active"):
            self._stop_avatar_anim()
        elif key == "character" and hasattr(self, "avatar_canvas"):
            self._start_avatar_anim()
        # Focus Gerald input when opening the chat
        if key == "gerald" and hasattr(self, "_gerald_entry"):
            self._gerald_entry.focus_set()
            try:
                self.gerald_assistant.greet_contextually()
                self._render_gerald_transcript()
            except Exception:
                pass
        for page_key, meta in self.page_button_meta.items():
            active = page_key == key
            primary = meta["primary"]
            if active:
                bg = UI_NAV_ACTIVE
                accent_bg = UI_TEXT_BRIGHT
                title_fg = UI_TEXT_BRIGHT
                subtitle_fg = UI_MUTED
            else:
                bg = UI_PANEL_ALT
                accent_bg = UI_PANEL_ALT
                title_fg = UI_TEXT if primary else UI_MUTED
                subtitle_fg = UI_MUTED if primary else "#5a5e6b"
            meta["frame"].configure(bg=UI_PANEL_ALT)
            meta["accent"].configure(bg=accent_bg)
            meta["content"].configure(bg=bg)
            meta["title"].configure(bg=bg, fg=title_fg)
            meta["subtitle"].configure(bg=bg, fg=subtitle_fg)

    def _on_global_wheel(self, event):
        """Route MouseWheel to the correct scrollable widget under the cursor.

        Priority: inner scrollable widget (Treeview, Text) > inner canvas > page canvas.
        This prevents the outer page canvas from stealing scroll from nested widgets.
        """
        x, y = event.x_root, event.y_root
        delta = -1 * (int(event.delta / 120) if event.delta else 0)
        if not delta:
            return

        # Check if cursor is over a natively-scrollable widget (Treeview/Text)
        # Walk from the widget under cursor up through parents
        try:
            w = self.winfo_containing(x, y)
        except Exception:
            w = None
        while w is not None and w is not self:
            if isinstance(w, (ttk.Treeview, tk.Text)):
                # Let the widget's built-in scroll handle it
                w.yview_scroll(delta, "units")
                return
            try:
                w = w.master
            except Exception:
                break

        # Find the smallest (innermost) matching canvas from our scroll list
        cur = self.current_page_key
        best = None
        best_area = float("inf")
        for c in self._scroll_canvases:
            page = self._scroll_canvas_page.get(id(c))
            if page is not None and page != cur:
                continue
            try:
                cx, cy = c.winfo_rootx(), c.winfo_rooty()
                cw, ch = c.winfo_width(), c.winfo_height()
            except Exception:
                continue
            if cx <= x < cx + cw and cy <= y < cy + ch:
                area = cw * ch
                if area < best_area:
                    best = c
                    best_area = area
        if best is not None:
            best.yview_scroll(delta, "units")

    # ── Toast notification system ───────────────────────────────────────────
    _TOAST_STYLES = {
        "info":    {"bg": UI_INFO_SOFT,    "fg": UI_SAPPHIRE, "icon": "ℹ"},
        "success": {"bg": UI_SUCCESS_SOFT, "fg": UI_EMERALD,  "icon": "✓"},
        "warning": {"bg": UI_WARNING_SOFT, "fg": UI_GOLD,     "icon": "⚠"},
        "error":   {"bg": UI_DANGER_SOFT,  "fg": UI_RUBY,     "icon": "✕"},
    }

    def _show_toast(self, message: str, style: str = "info", duration: int = 3000,
                    action_label: str = "", action_cb=None):
        """Show a non-blocking toast notification in the bottom-right corner.
        When action_label + action_cb are provided, a clickable text button is
        appended to the toast (used for Undo)."""
        s = self._TOAST_STYLES.get(style, self._TOAST_STYLES["info"])
        toast = tk.Frame(self, bg=s["bg"], highlightthickness=1,
                         highlightbackground=s["fg"], padx=SP_MD, pady=SP_SM)
        icon_lbl = tk.Label(toast, text=s["icon"], bg=s["bg"], fg=s["fg"],
                            font=FONT_BODY_BOLD)
        icon_lbl.pack(side="left", padx=(0, SP_SM))
        msg_lbl = tk.Label(toast, text=message, bg=s["bg"], fg=UI_TEXT,
                           font=FONT_SMALL, wraplength=300, justify="left")
        msg_lbl.pack(side="left", fill="x")
        if action_label and action_cb is not None:
            def _fire(_e=None):
                try:
                    action_cb()
                finally:
                    self._dismiss_toast(toast)
            sep = tk.Label(toast, text="  |  ", bg=s["bg"], fg=UI_BORDER_LT,
                           font=FONT_SMALL)
            sep.pack(side="left")
            act = tk.Label(toast, text=action_label, bg=s["bg"], fg=s["fg"],
                           font=FONT_SMALL_BOLD, cursor="hand2")
            act.pack(side="left", padx=(0, SP_SM))
            act.bind("<Button-1>", _fire)
        # Position: bottom-right, stacked above existing toasts
        self._toast_stack.append(toast)
        self._reposition_toasts()
        toast.lift()
        toast.after(duration, lambda: self._dismiss_toast(toast))

    def _dismiss_toast(self, toast):
        """Remove a toast and reposition remaining stack."""
        if toast in self._toast_stack:
            self._toast_stack.remove(toast)
            toast.destroy()
            self._reposition_toasts()

    def _reposition_toasts(self):
        """Stack active toasts from bottom-right, going upward."""
        margin_right = 20
        margin_bottom = 20
        gap = 6
        y_offset = margin_bottom
        for toast in reversed(self._toast_stack):
            toast.update_idletasks()
            tw = toast.winfo_reqwidth()
            th = toast.winfo_reqheight()
            ww = self.winfo_width()
            wh = self.winfo_height()
            x = ww - tw - margin_right
            y = wh - th - y_offset
            toast.place(x=x, y=y)
            toast.lift()
            y_offset += th + gap

