    def _build_score_section_selector(self, parent):
        """Underline-style segmented selector — Progress / Arcade."""
        self._score_section_pills = {}
        bar = tk.Frame(parent, bg=UI_BG)
        bar.pack(side="left")
        pills = [
            ("progress", "Progress"),
            ("arcade",   "Arcade"),
        ]
        for i, (key, label) in enumerate(pills):
            wrap = tk.Frame(bar, bg=UI_BG, cursor="hand2")
            wrap.pack(side="left", padx=(0 if i == 0 else SP_LG, 0))
            lbl = tk.Label(wrap, text=label, bg=UI_BG, fg=UI_MUTED,
                           font=FONT_BODY_BOLD, pady=SP_SM + 2)
            lbl.pack()
            # 2px underline indicator — lights up only when active
            underline = tk.Frame(wrap, bg=UI_BG, height=2)
            underline.pack(fill="x")
            def _on_enter(_e, k=key):
                meta = self._score_section_pills[k]
                if meta["underline"].cget("bg") != UI_TEXT_BRIGHT:
                    meta["label"].configure(fg=UI_TEXT)
            def _on_leave(_e, k=key):
                meta = self._score_section_pills[k]
                if meta["underline"].cget("bg") != UI_TEXT_BRIGHT:
                    meta["label"].configure(fg=UI_MUTED)
            for w in (wrap, lbl, underline):
                w.bind("<Button-1>", lambda _e, k=key: self._show_score_section(k))
                w.bind("<Enter>", _on_enter)
                w.bind("<Leave>", _on_leave)
            self._score_section_pills[key] = {"wrap": wrap, "label": lbl, "underline": underline}

    def _show_score_section(self, section: str):
        if section not in ("progress", "arcade"):
            return
        if section == "progress":
            self._score_arcade_host.grid_remove()
            self._score_progress_host.grid()
        else:
            self._score_progress_host.grid_remove()
            self._score_arcade_host.grid()
        # Update underline-style pills: active gets bright label + white underline.
        for key, meta in self._score_section_pills.items():
            if key == section:
                meta["label"].configure(fg=UI_TEXT_BRIGHT)
                meta["underline"].configure(bg=UI_TEXT_BRIGHT)
            else:
                meta["label"].configure(fg=UI_MUTED)
                meta["underline"].configure(bg=UI_BG)
        # If switching away mid-game, auto-quit (prevents a hidden timer running)
        if section == "progress":
            if getattr(self, "_mini_running", False):
                try: self._mini_end_round("manual")
                except Exception: pass
            if getattr(self, "_cc_running", False):
                try: self._cc_end_round("manual")
                except Exception: pass
            if getattr(self, "_dr_running", False):
                try: self._dr_end_round("manual")
                except Exception: pass

    # Arcade game registry — append dicts here to add future games.
    # Each entry: {"key","name","tag","desc","start": callable_that_builds_into_host}
    def _arcade_game_registry(self):
        return [
            {
                "key":   "sprint",
                "name":  "Budget Sprint",
                "tag":   "60s · Hearts · Combos",
                "desc":  "Classify spends, triage tight weeks, spot category leaks. Combo multiplier rewards streaks.",
                "build": self._build_budget_sprint_game,
            },
            {
                "key":   "coin",
                "name":  "Coin Catcher",
                "tag":   "Arrow keys · 60s · Reflex",
                "desc":  "Move the vault with ← / → (or A / D). Catch coins, gems, and bundles. Dodge red impulse-buy traps.",
                "build": self._build_coin_catcher_game,
            },
            {
                "key":   "runner",
                "name":  "Debt Dasher",
                "tag":   "Space to jump · ↓ to duck",
                "desc":  "Endless runner. Jump over debt cacti, duck under interest birds. Speeds up the longer you survive.",
                "build": self._build_debt_runner_game,
            },
        ]

    def _build_score_arcade_section(self, host):
        host.columnconfigure(0, weight=1)
        host.rowconfigure(1, weight=1)

        # Row 0 — Game picker strip
        picker_outer = tk.Frame(host, bg=UI_BG)
        picker_outer.grid(row=0, column=0, sticky="ew", padx=SP_XL, pady=(0, SP_MD))
        picker_outer.columnconfigure(0, weight=1)

        header = tk.Frame(picker_outer, bg=UI_BG)
        header.grid(row=0, column=0, sticky="ew", pady=(0, SP_SM))
        tk.Label(header, text="ARCADE", bg=UI_BG, fg=UI_MUTED,
                 font=FONT_CAPTION_BOLD).pack(side="left")
        tk.Label(header, text="  Choose a game — more coming.", bg=UI_BG, fg=UI_MUTED,
                 font=FONT_SMALL).pack(side="left")

        self._arcade_cards_frame = tk.Frame(picker_outer, bg=UI_BG)
        self._arcade_cards_frame.grid(row=1, column=0, sticky="ew")
        self._arcade_card_widgets = {}

        # Row 1 — Selected game host
        self._arcade_game_host = tk.Frame(host, bg=UI_BG)
        self._arcade_game_host.grid(row=1, column=0, sticky="nsew", padx=SP_XL, pady=(0, SP_XL))
        self._arcade_game_host.columnconfigure(0, weight=1)
        self._arcade_game_host.rowconfigure(0, weight=1)

        # Pre-build all registered games into their own frames; toggle visibility.
        self._arcade_game_frames = {}
        self._active_arcade_game = None
        for entry in self._arcade_game_registry():
            game_frame = tk.Frame(self._arcade_game_host, bg=UI_BG)
            game_frame.grid(row=0, column=0, sticky="nsew")
            game_frame.columnconfigure(0, weight=1)
            entry["build"](game_frame)
            game_frame.grid_remove()
            self._arcade_game_frames[entry["key"]] = game_frame

        self._render_arcade_cards()
        # Activate first game by default
        reg = self._arcade_game_registry()
        if reg:
            self._select_arcade_game(reg[0]["key"])

    def _render_arcade_cards(self):
        for w in list(self._arcade_cards_frame.children.values()):
            w.destroy()
        self._arcade_card_widgets.clear()
        for i, entry in enumerate(self._arcade_game_registry()):
            card = tk.Frame(self._arcade_cards_frame, bg=UI_SURFACE,
                            highlightthickness=1, highlightbackground=UI_BORDER,
                            cursor="hand2")
            card.grid(row=0, column=i, sticky="w",
                      padx=(0 if i == 0 else SP_MD, 0))
            inner = tk.Frame(card, bg=UI_SURFACE, padx=SP_LG, pady=SP_MD)
            inner.pack(fill="both", expand=True)
            name = tk.Label(inner, text=entry["name"], bg=UI_SURFACE, fg=UI_TEXT,
                            font=FONT_BODY_BOLD, anchor="w")
            name.pack(anchor="w")
            tag = tk.Label(inner, text=entry["tag"], bg=UI_SURFACE, fg=UI_MUTED,
                           font=FONT_CAPTION, anchor="w")
            tag.pack(anchor="w", pady=(2, 4))
            desc = tk.Label(inner, text=entry["desc"], bg=UI_SURFACE, fg=UI_MUTED,
                            font=FONT_SMALL, anchor="w", justify="left", wraplength=320)
            desc.pack(anchor="w")

            def _enter(_e, k=entry["key"]):
                if self._active_arcade_game != k:
                    meta = self._arcade_card_widgets[k]
                    meta["card"].configure(highlightbackground=UI_BORDER_LT)
            def _leave(_e, k=entry["key"]):
                if self._active_arcade_game != k:
                    meta = self._arcade_card_widgets[k]
                    meta["card"].configure(highlightbackground=UI_BORDER)

            for w in (card, inner, name, tag, desc):
                w.bind("<Button-1>",
                       lambda _e, k=entry["key"]: self._select_arcade_game(k))
                w.bind("<Enter>", _enter)
                w.bind("<Leave>", _leave)
            self._arcade_card_widgets[entry["key"]] = {
                "card": card, "name": name,
                "tag": tag, "desc": desc, "inner": inner,
            }

    def _select_arcade_game(self, key: str):
        if key not in self._arcade_game_frames:
            return
        # Hide all, show chosen
        for k, f in self._arcade_game_frames.items():
            f.grid_remove()
        self._arcade_game_frames[key].grid()
        # Quit any running game if switching away
        if self._active_arcade_game == "sprint" and key != "sprint":
            if getattr(self, "_mini_running", False):
                try: self._mini_end_round("manual")
                except Exception: pass
        if self._active_arcade_game == "coin" and key != "coin":
            if getattr(self, "_cc_running", False):
                try: self._cc_end_round("manual")
                except Exception: pass
        if self._active_arcade_game == "runner" and key != "runner":
            if getattr(self, "_dr_running", False):
                try: self._dr_end_round("manual")
                except Exception: pass
        self._active_arcade_game = key
        # Focus the active game's canvas so key controls work immediately.
        if key == "coin" and hasattr(self, "_cc_canvas"):
            try: self._cc_canvas.focus_set()
            except Exception: pass
        if key == "runner" and hasattr(self, "_dr_canvas"):
            try: self._dr_canvas.focus_set()
            except Exception: pass
        # Active card: near-white border + bright title. Others: quiet.
        for k, w in self._arcade_card_widgets.items():
            if k == key:
                w["card"].configure(highlightbackground=UI_TEXT_BRIGHT)
                w["name"].configure(fg=UI_TEXT_BRIGHT)
            else:
                w["card"].configure(highlightbackground=UI_BORDER)
                w["name"].configure(fg=UI_TEXT)

