    # ── Coin Catcher (arcade game #2) ─────────────────────────────────────
    def _build_coin_catcher_game(self, host):
        """Arrow/A-D to move the vault. Catch coins/gems/bundles, dodge impulse traps."""
        host.columnconfigure(0, weight=1)
        box = ttk.LabelFrame(host, text="Coin Catcher", padding=SP_MD)
        box.grid(row=0, column=0, sticky="nsew")
        box.columnconfigure(0, weight=1)
        box.configure(style="MiniGame.TLabelframe")

        # HUD row
        hud = tk.Frame(box, bg=UI_WARNING_SOFT)
        hud.grid(row=0, column=0, sticky="ew", pady=(0, SP_SM))
        hud.columnconfigure(1, weight=1)
        tk.Label(hud, text="TIME", bg=UI_WARNING_SOFT, fg=UI_GOLD,
                 font=FONT_CAPTION_BOLD).grid(row=0, column=0, padx=(0, SP_SM))
        self._cc_timer_canvas = tk.Canvas(hud, height=14, bg=UI_SURFACE2,
                                          highlightthickness=1,
                                          highlightbackground=UI_BORDER)
        self._cc_timer_canvas.grid(row=0, column=1, sticky="ew")
        self._cc_timer_canvas.bind("<Configure>", lambda _e: self._draw_cc_timer())

        self._cc_hearts_frame = tk.Frame(hud, bg=UI_WARNING_SOFT)
        self._cc_hearts_frame.grid(row=0, column=2, padx=(SP_MD, SP_MD))
        self._cc_heart_labels: list = []
        for _i in range(3):
            hl = tk.Label(self._cc_hearts_frame, text="\u2665",
                          bg=UI_WARNING_SOFT, fg=UI_RUBY,
                          font=FONT_SUBHEADING)
            hl.pack(side="left", padx=1)
            self._cc_heart_labels.append(hl)

        self._cc_combo_var = tk.StringVar(value="x1")
        self._cc_combo_lbl = tk.Label(hud, textvariable=self._cc_combo_var,
                                      bg=UI_SURFACE2, fg=UI_MUTED,
                                      font=FONT_SUBHEADING, padx=SP_SM, pady=2)
        self._cc_combo_lbl.grid(row=0, column=3, padx=(0, SP_MD))

        self._cc_score_var = tk.StringVar(value="0")
        tk.Label(hud, textvariable=self._cc_score_var, bg=UI_WARNING_SOFT,
                 fg=UI_GOLD, font=FONT_STAT_NUM).grid(row=0, column=4)

        # Power-up chip strip (row 1 of HUD)
        self._cc_power_strip = tk.Frame(hud, bg=UI_WARNING_SOFT)
        self._cc_power_strip.grid(row=1, column=0, columnspan=5,
                                  sticky="w", pady=(SP_XS, 0))
        self._cc_power_chips: dict = {}  # kind -> (wrap, label)

        # Play area
        self._cc_canvas = tk.Canvas(box, height=360, bg=UI_SURFACE2,
                                    highlightthickness=1,
                                    highlightbackground=UI_BORDER,
                                    takefocus=1)
        self._cc_canvas.grid(row=1, column=0, sticky="nsew", pady=(0, SP_SM))
        self._cc_canvas.bind("<Configure>", self._cc_on_resize)
        self._cc_canvas.bind("<Button-1>", lambda _e: self._cc_canvas.focus_set())
        # Key bindings: bind on the canvas so they only fire while canvas has focus.
        for seq in ("<KeyPress-Left>", "<KeyPress-a>", "<KeyPress-A>"):
            self._cc_canvas.bind(seq, lambda _e: self._cc_set_pressed("left", True))
        for seq in ("<KeyRelease-Left>", "<KeyRelease-a>", "<KeyRelease-A>"):
            self._cc_canvas.bind(seq, lambda _e: self._cc_set_pressed("left", False))
        for seq in ("<KeyPress-Right>", "<KeyPress-d>", "<KeyPress-D>"):
            self._cc_canvas.bind(seq, lambda _e: self._cc_set_pressed("right", True))
        for seq in ("<KeyRelease-Right>", "<KeyRelease-d>", "<KeyRelease-D>"):
            self._cc_canvas.bind(seq, lambda _e: self._cc_set_pressed("right", False))

        # Controls
        controls = tk.Frame(box, bg=UI_WARNING_SOFT)
        controls.grid(row=2, column=0, sticky="ew")
        ttk.Button(controls, text="Start Catcher", style="RoundCtrl.TButton",
                   command=self.start_cc_round).pack(side="left")
        ttk.Button(controls, text="Quit Catcher", style="Accent.TButton",
                   command=self.finish_cc_round).pack(side="left", padx=(SP_MD, 0))
        tk.Label(controls, text="   ← / →  or  A / D to move",
                 bg=UI_WARNING_SOFT, fg=UI_MUTED,
                 font=FONT_SMALL).pack(side="left", padx=(SP_MD, 0))

        self._cc_status_var = tk.StringVar(value="Click the play area, then Start. Catch coins, dodge impulse buys.")
        tk.Label(box, textvariable=self._cc_status_var,
                 bg=UI_WARNING_SOFT, fg=UI_MUTED,
                 font=FONT_SMALL).grid(row=3, column=0, sticky="w", pady=(SP_XS, 0))

        # State
        self._cc_running = False
        self._cc_score = 0
        self._cc_hearts = 3
        self._cc_time_left = 0.0
        self._cc_time_total = 60.0
        self._cc_player_x = 0.0
        self._cc_player_w = 80.0
        self._cc_player_h = 28.0
        self._cc_items: list = []
        self._cc_particles: list = []
        self._cc_spawn_accum = 0.0
        self._cc_power_spawn_accum = 0.0
        self._cc_shower_spawn_accum = 0.0
        self._cc_speed_mult = 1.0
        self._cc_pressed = {"left": False, "right": False}
        self._cc_tick_job = None
        self._cc_high_score = 0
        self._cc_best_streak = 0
        self._cc_caught_good = 0
        self._cc_caught_bad = 0
        self._cc_streak = 0          # combo count
        self._cc_powers = {"magnet": 0.0, "double": 0.0, "shield": 0.0}
        self._cc_mouth_open = 0.0    # animation phase (0..1) after catch
        self._cc_flash_color = None  # ("emerald"/"ruby"/"gold") after event
        self._cc_flash_until = 0.0

    def _cc_set_pressed(self, key: str, down: bool):
        self._cc_pressed[key] = down

    def _cc_on_resize(self, _e=None):
        c = self._cc_canvas
        w = c.winfo_width()
        h = c.winfo_height()
        if w <= 1 or h <= 1:
            return
        # Center player if not yet placed.
        if self._cc_player_x <= 0 or self._cc_player_x > w:
            self._cc_player_x = w / 2
        self._cc_redraw()

    def _cc_redraw(self):
        c = self._cc_canvas
        c.delete("all")
        w = c.winfo_width() or 1
        h = c.winfo_height() or 1

        # Magnet active — faint concentric rings around player
        if self._cc_powers["magnet"] > 0 and self._cc_player_x > 0:
            px = self._cc_player_x
            py = h - 8 - self._cc_player_h / 2
            for r in (60, 100, 140):
                c.create_oval(px - r, py - r, px + r, py - r + r * 2,
                              outline=UI_AMETHYST, dash=(3, 4), width=1)

        # Ground line
        c.create_line(0, h - 6, w, h - 6, fill=UI_BORDER, width=1)

        # Falling items
        for it in self._cc_items:
            self._cc_draw_item(it)

        # Particles (on top of items)
        self._cc_draw_particles()

        # Player
        self._cc_draw_player(w, h)

        # Brief border flash after an event
        import time as _time
        if self._cc_flash_color and _time.monotonic() < self._cc_flash_until:
            col = {"emerald": UI_EMERALD, "ruby": UI_RUBY,
                   "gold": UI_GOLD, "purple": UI_AMETHYST}.get(self._cc_flash_color, UI_EMERALD)
            c.create_rectangle(1, 1, w - 1, h - 1, outline=col, width=3)

    def _cc_draw_player(self, w: int, h: int):
        c = self._cc_canvas
        px = max(self._cc_player_w / 2, min(w - self._cc_player_w / 2, self._cc_player_x))
        self._cc_player_x = px
        pw = self._cc_player_w
        ph = self._cc_player_h
        y1 = h - 8 - ph
        y2 = h - 8
        x1 = px - pw / 2
        x2 = px + pw / 2
        cx = (x1 + x2) / 2

        # Shield glow (behind vault)
        if self._cc_powers["shield"] > 0:
            c.create_rectangle(x1 - 5, y1 - 5, x2 + 5, y2 + 5,
                               outline=UI_EMERALD, width=2)
            c.create_rectangle(x1 - 2, y1 - 2, x2 + 2, y2 + 2,
                               outline=UI_EMERALD, width=1)

        # Vault body
        c.create_rectangle(x1, y1, x2, y2, fill=UI_WARNING_SOFT,
                           outline=UI_GOLD, width=2)
        c.create_rectangle(x1 + 6, y1 + 5, x2 - 6, y2 - 5,
                           fill="", outline=UI_GOLD, width=1)

        # "Mouth" opens on catch — a top-edge gap
        if self._cc_mouth_open > 0.02:
            mw = int(pw * 0.5 * self._cc_mouth_open)
            c.create_rectangle(cx - mw / 2, y1 - 5, cx + mw / 2, y1 + 3,
                               fill=UI_BG, outline="")

        # Dial
        dial_r = 5
        c.create_oval(cx - dial_r, (y1 + y2) / 2 - dial_r,
                      cx + dial_r, (y1 + y2) / 2 + dial_r,
                      fill=UI_GOLD, outline=UI_GOLD)
        c.create_text(cx, (y1 + y2) / 2, text="$", fill=UI_BG,
                      font=FONT_CAPTION_BOLD)

        # Double-score aura — gold outline pulsing
        if self._cc_powers["double"] > 0:
            c.create_rectangle(x1 - 2, y1 - 2, x2 + 2, y2 + 2,
                               outline=UI_GOLD, width=2, dash=(2, 2))

    def _cc_draw_item(self, it: dict):
        c = self._cc_canvas
        x, y = it["x"], it["y"]
        k = it["kind"]
        if k == "coin":
            r = 12
            c.create_oval(x - r, y - r, x + r, y + r,
                          fill=UI_GOLD, outline=UI_GOLD, width=2)
            c.create_text(x, y, text="$", fill=UI_BG, font=FONT_CAPTION_BOLD)
        elif k == "gem":
            r = 12
            c.create_polygon(x, y - r, x + r, y, x, y + r, x - r, y,
                             fill=UI_SAPPHIRE, outline=UI_INFO_SOFT, width=2)
        elif k == "bundle":
            r = 14
            c.create_rectangle(x - r, y - r / 1.4, x + r, y + r / 1.4,
                               fill=UI_EMERALD, outline=UI_EMERALD, width=2)
            c.create_text(x, y, text="$$", fill=UI_BG,
                          font=FONT_CAPTION_BOLD)
        elif k == "trap":
            r = 12
            c.create_oval(x - r, y - r, x + r, y + r,
                          fill=UI_DANGER_SOFT, outline=UI_RUBY, width=2)
            c.create_line(x - r / 1.6, y - r / 1.6, x + r / 1.6, y + r / 1.6,
                          fill=UI_RUBY, width=3)
            c.create_line(x - r / 1.6, y + r / 1.6, x + r / 1.6, y - r / 1.6,
                          fill=UI_RUBY, width=3)
        elif k.startswith("power_"):
            r = 14
            sub = k.split("_", 1)[1]
            colors = {"magnet": UI_AMETHYST, "double": UI_GOLD,
                      "shield": UI_EMERALD}
            fill = colors.get(sub, UI_MUTED)
            # Hexagon body
            import math
            pts = []
            for i in range(6):
                a = math.radians(60 * i - 30)
                pts.extend((x + r * math.cos(a), y + r * math.sin(a)))
            c.create_polygon(pts, fill=UI_BG, outline=fill, width=2)
            # Icon
            icon = {"magnet": "U", "double": "x2", "shield": "◆"}.get(sub, "?")
            c.create_text(x, y, text=icon, fill=fill,
                          font=FONT_CAPTION_BOLD)
            # Sparkle pips
            for i, a_deg in enumerate((0, 90, 180, 270)):
                a = math.radians(a_deg + (self._frame_phase() % 4) * 22.5)
                sx = x + (r + 6) * math.cos(a)
                sy = y + (r + 6) * math.sin(a)
                c.create_oval(sx - 1.5, sy - 1.5, sx + 1.5, sy + 1.5,
                              fill=fill, outline="")

    def _frame_phase(self):
        import time as _time
        return int(_time.monotonic() * 8)

    # ── Particles ────────────────────────────────────────────────────
    def _cc_spawn_particles(self, x: float, y: float, kind: str, count: int = 10):
        import random, math
        if kind == "sparkle":
            color_pool = (UI_GOLD, UI_EMERALD, "#fde68a")
        elif kind == "shard":
            color_pool = (UI_RUBY, "#ef4444")
        elif kind == "purple":
            color_pool = (UI_AMETHYST, "#c4b5fd")
        elif kind == "gem":
            color_pool = (UI_SAPPHIRE, UI_ACCENT_BRIGHT)
        else:
            color_pool = (UI_GOLD,)
        for _ in range(count):
            ang = random.uniform(0, math.tau)
            spd = random.uniform(2, 6)
            life = random.randint(10, 22)
            self._cc_particles.append({
                "x": x, "y": y,
                "vx": math.cos(ang) * spd,
                "vy": math.sin(ang) * spd - 1.0,
                "life": life, "max_life": life,
                "color": random.choice(color_pool),
                "r": random.uniform(1.4, 2.8),
            })

    def _cc_update_particles(self):
        for p in self._cc_particles:
            p["x"] += p["vx"]
            p["y"] += p["vy"]
            p["vy"] += 0.22  # gravity
            p["life"] -= 1
        self._cc_particles = [p for p in self._cc_particles if p["life"] > 0]

    def _cc_draw_particles(self):
        c = self._cc_canvas
        for p in self._cc_particles:
            frac = p["life"] / p["max_life"]
            r = max(0.5, p["r"] * frac)
            c.create_oval(p["x"] - r, p["y"] - r,
                          p["x"] + r, p["y"] + r,
                          fill=p["color"], outline="")

    # ── Combo tiers / multiplier ─────────────────────────────────────
    def _cc_combo_mult(self) -> float:
        s = self._cc_streak
        if s >= 15: return 3.0
        if s >= 10: return 2.5
        if s >= 6:  return 2.0
        if s >= 3:  return 1.5
        return 1.0

    def _cc_update_combo_badge(self):
        mult = self._cc_combo_mult()
        self._cc_combo_var.set(f"x{mult:g}")
        # Tier colors
        if mult >= 3.0:   bg, fg = UI_RUBY, UI_BG
        elif mult >= 2.5: bg, fg = UI_GOLD, UI_BG
        elif mult >= 2.0: bg, fg = UI_EMERALD, UI_BG
        elif mult >= 1.5: bg, fg = UI_SAPPHIRE, UI_BG
        else:             bg, fg = UI_SURFACE2, UI_MUTED
        self._cc_combo_lbl.configure(bg=bg, fg=fg)

    # ── Power-up HUD chips ───────────────────────────────────────────
    def _cc_refresh_power_chips(self):
        strip = self._cc_power_strip
        for k, (wrap, _lbl) in list(self._cc_power_chips.items()):
            if self._cc_powers.get(k, 0.0) <= 0:
                wrap.destroy()
                self._cc_power_chips.pop(k, None)
        active = [(k, v) for k, v in self._cc_powers.items() if v > 0]
        for k, remaining in active:
            if k in self._cc_power_chips:
                wrap, lbl = self._cc_power_chips[k]
                lbl.configure(text=self._cc_power_chip_text(k, remaining))
            else:
                color = {"magnet": UI_AMETHYST, "double": UI_GOLD,
                         "shield": UI_EMERALD}.get(k, UI_MUTED)
                wrap = tk.Frame(strip, bg=UI_SURFACE2,
                                highlightthickness=1,
                                highlightbackground=color)
                wrap.pack(side="left", padx=(0, SP_SM))
                lbl = tk.Label(wrap, text=self._cc_power_chip_text(k, remaining),
                               bg=UI_SURFACE2, fg=color,
                               font=FONT_CAPTION_BOLD, padx=SP_SM, pady=1)
                lbl.pack()
                self._cc_power_chips[k] = (wrap, lbl)

    def _cc_power_chip_text(self, kind: str, remaining: float) -> str:
        if kind == "shield":
            return "SHIELD"
        name = {"magnet": "MAGNET", "double": "x2 SCORE"}.get(kind, kind.upper())
        return f"{name} {remaining:.1f}s"

    def _draw_cc_timer(self):
        c = self._cc_timer_canvas
        if not c.winfo_exists(): return
        c.delete("all")
        w = c.winfo_width() or 1
        h = c.winfo_height() or 14
        frac = 0.0
        if self._cc_time_total > 0:
            frac = max(0.0, min(1.0, self._cc_time_left / self._cc_time_total))
        fill_w = int(w * frac)
        if frac > 0.5: color = UI_EMERALD
        elif frac > 0.25: color = UI_GOLD
        else: color = UI_RUBY
        if fill_w > 0:
            c.create_rectangle(0, 0, fill_w, h, fill=color, outline="")

    def _update_cc_hearts(self):
        for i, lbl in enumerate(self._cc_heart_labels):
            if i < self._cc_hearts:
                lbl.configure(text="\u2665", fg=UI_RUBY)
            else:
                lbl.configure(text="\u2661", fg=UI_MUTED)

    def start_cc_round(self):
        if self._cc_running:
            return
        self._cc_running = True
        self._cc_score = 0
        self._cc_hearts = 3
        self._cc_time_left = self._cc_time_total
        self._cc_items.clear()
        self._cc_particles.clear()
        self._cc_spawn_accum = 0.0
        self._cc_power_spawn_accum = 0.0
        self._cc_shower_spawn_accum = 0.0
        self._cc_speed_mult = 1.0
        self._cc_streak = 0
        self._cc_best_streak = 0
        self._cc_caught_good = 0
        self._cc_caught_bad = 0
        self._cc_powers = {"magnet": 0.0, "double": 0.0, "shield": 0.0}
        self._cc_mouth_open = 0.0
        self._cc_flash_color = None
        self._cc_flash_until = 0.0
        for _k, (wrap, _lbl) in list(self._cc_power_chips.items()):
            try: wrap.destroy()
            except Exception: pass
        self._cc_power_chips.clear()
        self._cc_score_var.set("0")
        self._cc_update_combo_badge()
        self._update_cc_hearts()
        self._draw_cc_timer()
        self._cc_redraw()
        self._cc_status_var.set("Go! 60 seconds. Catch money, dodge impulse buys. Grab hexagons for power-ups.")
        self._cc_canvas.focus_set()
        if self._cc_tick_job is not None:
            try: self.after_cancel(self._cc_tick_job)
            except Exception: pass
        self._cc_tick_job = self.after(33, self._cc_tick)

    def _cc_tick(self):
        if not self._cc_running:
            return
        import math
        dt = 0.033
        # Decay power-up timers (shield is persistent until consumed)
        for _k in ("magnet", "double"):
            if self._cc_powers[_k] > 0:
                self._cc_powers[_k] = max(0.0, self._cc_powers[_k] - dt)
        # Mouth animation decays
        if self._cc_mouth_open > 0:
            self._cc_mouth_open = max(0.0, self._cc_mouth_open - dt * 3.2)

        # Timer
        self._cc_time_left = max(0.0, self._cc_time_left - dt)
        if self._cc_time_left <= 0:
            self._cc_end_round("time")
            return
        # Difficulty ramps with elapsed time (0→1 over full sprint).
        progress = 1.0 - (self._cc_time_left / self._cc_time_total)
        self._cc_speed_mult = 1.0 + progress * 1.4  # 1x → 2.4x fall speed
        spawn_rate = 1.1 + progress * 2.2  # items/sec

        # Move player
        c = self._cc_canvas
        w = c.winfo_width() or 1
        h = c.winfo_height() or 1
        step = 9.0 + progress * 5.0
        if self._cc_pressed["left"]:
            self._cc_player_x -= step
        if self._cc_pressed["right"]:
            self._cc_player_x += step
        self._cc_player_x = max(self._cc_player_w / 2,
                                min(w - self._cc_player_w / 2, self._cc_player_x))

        # Spawn regular items
        self._cc_spawn_accum += dt * spawn_rate
        while self._cc_spawn_accum >= 1.0:
            self._cc_spawn_accum -= 1.0
            self._cc_spawn_item(w)

        # Power-up spawn (~every 10s)
        self._cc_power_spawn_accum += dt
        if self._cc_power_spawn_accum >= 10.0:
            self._cc_power_spawn_accum = 0.0
            self._cc_spawn_powerup(w)

        # Coin shower (~every 14s)
        self._cc_shower_spawn_accum += dt
        if self._cc_shower_spawn_accum >= 14.0:
            self._cc_shower_spawn_accum = 0.0
            self._cc_spawn_coin_shower(w)

        # Magnet pull on nearby good items
        if self._cc_powers["magnet"] > 0:
            px = self._cc_player_x
            py = h - 8 - self._cc_player_h / 2
            for it in self._cc_items:
                if it["kind"] in ("coin", "gem", "bundle"):
                    dx = px - it["x"]
                    dy = py - it["y"]
                    dist = math.hypot(dx, dy)
                    if 1 < dist < 170:
                        pull = 1.0 - dist / 170.0
                        it["x"] += (dx / dist) * pull * 8.5
                        it["y"] += (dy / dist) * pull * 3.0

        # Move items + collisions
        player_top = h - 8 - self._cc_player_h
        player_left = self._cc_player_x - self._cc_player_w / 2
        player_right = self._cc_player_x + self._cc_player_w / 2
        caught_good_this_tick = False
        for it in self._cc_items:
            it["y"] += it["vy"] * self._cc_speed_mult
            # Caught when item center is within player band and within player x-range.
            if (not it.get("done")) and it["y"] >= player_top and it["y"] <= h - 8 \
                    and player_left <= it["x"] <= player_right:
                self._cc_handle_catch(it)
                it["done"] = True
                if it["kind"] in ("coin", "gem", "bundle"):
                    caught_good_this_tick = True
            # Missed: passed below ground
            elif (not it.get("done")) and it["y"] >= h - 4:
                it["done"] = True
                if it["kind"] in ("coin", "gem", "bundle"):
                    # Missed money resets streak but no life loss.
                    self._cc_streak = 0
        # Cull
        self._cc_items = [it for it in self._cc_items if not it.get("done")]

        # Particles
        self._cc_update_particles()

        # HUD + redraw
        self._cc_score_var.set(str(self._cc_score))
        self._cc_update_combo_badge()
        self._cc_refresh_power_chips()
        self._draw_cc_timer()
        self._cc_redraw()
        if caught_good_this_tick:
            self._cc_best_streak = max(self._cc_best_streak, self._cc_streak)

        self._cc_tick_job = self.after(33, self._cc_tick)

    def _cc_spawn_item(self, w: int):
        import random
        # Weighted by rarity (and traps get commoner as difficulty ramps).
        progress = 1.0 - (self._cc_time_left / self._cc_time_total)
        trap_w = 24 + int(progress * 22)   # 24 → 46
        roll = random.randint(1, 100 + trap_w)
        if roll <= 55:
            kind = "coin"; vy = 4.0
        elif roll <= 78:
            kind = "gem"; vy = 5.2
        elif roll <= 88:
            kind = "bundle"; vy = 6.0
        else:
            kind = "trap"; vy = 5.0
        x = random.randint(20, max(21, w - 20))
        self._cc_items.append({"x": x, "y": -14, "vy": vy, "kind": kind})

    def _cc_spawn_powerup(self, w: int):
        import random
        sub = random.choice(["magnet", "double", "shield"])
        x = random.randint(30, max(31, w - 30))
        self._cc_items.append({"x": x, "y": -18, "vy": 3.6,
                               "kind": f"power_{sub}"})

    def _cc_spawn_coin_shower(self, w: int):
        import random
        base_x = random.randint(60, max(61, w - 60))
        for i in range(5):
            ox = (i - 2) * 22 + random.randint(-4, 4)
            x = min(max(20, base_x + ox), w - 20)
            self._cc_items.append({"x": x, "y": -18 - i * 12,
                                   "vy": 4.2, "kind": "coin"})

    def _cc_handle_catch(self, it: dict):
        import time as _time
        k = it["kind"]
        now = _time.monotonic()
        if k in ("coin", "gem", "bundle"):
            base = {"coin": 5, "gem": 15, "bundle": 25}[k]
            mult = self._cc_combo_mult()
            if self._cc_powers["double"] > 0:
                mult *= 2.0
            self._cc_score += int(round(base * mult))
            self._cc_streak += 1
            self._cc_caught_good += 1
            self._cc_mouth_open = 1.0
            self._cc_flash_color = "emerald"
            self._cc_flash_until = now + 0.14
            p_kind = "gem" if k == "gem" else "sparkle"
            self._cc_spawn_particles(it["x"], it["y"], p_kind,
                                     count=14 if k == "bundle" else (10 if k == "gem" else 7))
        elif k == "trap":
            if self._cc_powers["shield"] > 0:
                # Shield absorbs trap — consumed, no heart loss, streak survives.
                self._cc_powers["shield"] = 0.0
                self._cc_spawn_particles(it["x"], it["y"], "purple", count=14)
                self._cc_flash_color = "purple"
                self._cc_flash_until = now + 0.18
            else:
                self._cc_hearts = max(0, self._cc_hearts - 1)
                self._cc_score = max(0, self._cc_score - 3)
                self._cc_streak = 0
                self._cc_caught_bad += 1
                self._update_cc_hearts()
                self._cc_spawn_particles(it["x"], it["y"], "shard", count=14)
                self._cc_flash_color = "ruby"
                self._cc_flash_until = now + 0.22
                if self._cc_hearts <= 0:
                    self._cc_end_round("hearts")
        elif k.startswith("power_"):
            sub = k.split("_", 1)[1]
            if sub == "shield":
                self._cc_powers["shield"] = 1.0   # sentinel — persists until trap
            elif sub == "magnet":
                self._cc_powers["magnet"] = 6.0
            elif sub == "double":
                self._cc_powers["double"] = 6.0
            self._cc_mouth_open = 1.0
            self._cc_flash_color = "purple"
            self._cc_flash_until = now + 0.24
            self._cc_spawn_particles(it["x"], it["y"], "purple", count=18)

    def finish_cc_round(self):
        if self._cc_running:
            self._cc_end_round("manual")

    def _cc_end_round(self, reason: str = "time"):
        if not self._cc_running:
            return
        self._cc_running = False
        if self._cc_tick_job is not None:
            try: self.after_cancel(self._cc_tick_job)
            except Exception: pass
            self._cc_tick_job = None

        # Final score with bonuses
        base = self._cc_score
        heart_bonus = self._cc_hearts * 8
        streak_bonus = self._cc_best_streak * 3
        gained = max(base + heart_bonus + streak_bonus, 0)
        mult = getattr(self.state.game, "score_multiplier", 1.0) or 1.0
        gained = int(round(gained * mult))

        self.state.game.total_score += gained
        self.state.game.last_score_gain = gained
        self.state.game.mini_game_rounds_won += 1
        new_high = gained > self.state.game.mini_game_high_score
        if new_high:
            self.state.game.mini_game_high_score = gained
            if "Mini Game High Scorer" not in self.state.game.achievements:
                self.state.game.achievements.append("Mini Game High Scorer")

        gems = (gained // 60) + self._cc_hearts
        if gems > 0:
            self.state.game.gems = getattr(self.state.game, "gems", 0) + gems
            self.state.game.lifetime_gems_earned = getattr(self.state.game, "lifetime_gems_earned", 0) + gems

        self.game_engine.add_season_xp(15)
        self.game_engine.complete_challenge("mini_game")

        reason_txt = {
            "time":   "Time's up!",
            "hearts": "Out of hearts!",
            "manual": "Ended.",
        }.get(reason, "Round over.")
        msg = (f"{reason_txt}  Final +{gained} pts"
               + ("  \U0001F3C6 NEW HIGH" if new_high else "")
               + f"  ·  Caught {self._cc_caught_good}  ·  Traps {self._cc_caught_bad}"
               + f"  ·  Best combo {self._cc_best_streak}"
               + (f"  ·  Gems +{gems}" if gems else ""))
        self._cc_status_var.set(msg)

        try:
            self.save_state()
            self.refresh_game_text()
        except Exception:
            pass

        # Clear play area to a tidy state.
        self._cc_items.clear()
        self._cc_redraw()
        self._draw_cc_timer()

    # ── Debt Dasher (arcade game #3 — Chrome dino clone) ─────────────────
    def _build_debt_runner_game(self, host):
        host.columnconfigure(0, weight=1)
        box = ttk.LabelFrame(host, text="Debt Dasher", padding=SP_MD)
        box.grid(row=0, column=0, sticky="nsew")
        box.columnconfigure(0, weight=1)
        box.configure(style="MiniGame.TLabelframe")

        # HUD
        hud = tk.Frame(box, bg=UI_WARNING_SOFT)
        hud.grid(row=0, column=0, sticky="ew", pady=(0, SP_SM))
        hud.columnconfigure(0, weight=1)
        tk.Label(hud, text="DISTANCE", bg=UI_WARNING_SOFT, fg=UI_GOLD,
                 font=FONT_CAPTION_BOLD).pack(side="left")
        self._dr_score_var = tk.StringVar(value="0")
        tk.Label(hud, textvariable=self._dr_score_var, bg=UI_WARNING_SOFT,
                 fg=UI_GOLD, font=FONT_STAT_NUM).pack(side="left", padx=(SP_SM, 0))
        self._dr_high_var = tk.StringVar(value="Best 0")
        tk.Label(hud, textvariable=self._dr_high_var, bg=UI_WARNING_SOFT,
                 fg=UI_MUTED, font=FONT_CAPTION_BOLD).pack(side="right")

        # Play area
        self._dr_canvas = tk.Canvas(box, height=260, bg=UI_SURFACE2,
                                    highlightthickness=1,
                                    highlightbackground=UI_BORDER,
                                    takefocus=1)
        self._dr_canvas.grid(row=1, column=0, sticky="nsew", pady=(0, SP_SM))
        self._dr_canvas.bind("<Configure>", lambda _e: self._dr_redraw())
        self._dr_canvas.bind("<Button-1>", lambda _e: self._dr_canvas.focus_set())
        for seq in ("<KeyPress-space>", "<KeyPress-Up>", "<KeyPress-w>", "<KeyPress-W>"):
            self._dr_canvas.bind(seq, lambda _e: self._dr_jump())
        for seq in ("<KeyPress-Down>", "<KeyPress-s>", "<KeyPress-S>"):
            self._dr_canvas.bind(seq, lambda _e: self._dr_set_duck(True))
        for seq in ("<KeyRelease-Down>", "<KeyRelease-s>", "<KeyRelease-S>"):
            self._dr_canvas.bind(seq, lambda _e: self._dr_set_duck(False))

        # Controls
        controls = tk.Frame(box, bg=UI_WARNING_SOFT)
        controls.grid(row=2, column=0, sticky="ew")
        ttk.Button(controls, text="Start Run", style="RoundCtrl.TButton",
                   command=self.start_dr_round).pack(side="left")
        ttk.Button(controls, text="Quit Run", style="Accent.TButton",
                   command=self.finish_dr_round).pack(side="left", padx=(SP_MD, 0))
        tk.Label(controls,
                 text="   Space / ↑ jump  ·  ↓ duck  ·  ↓ mid-air = dive-slam  ·  Click the play area first",
                 bg=UI_WARNING_SOFT, fg=UI_MUTED,
                 font=FONT_SMALL).pack(side="left", padx=(SP_MD, 0))

        self._dr_status_var = tk.StringVar(
            value="Outrun the debt. Jump cacti, duck birds. Keep going — the longer you run, the faster it gets.")
        tk.Label(box, textvariable=self._dr_status_var,
                 bg=UI_WARNING_SOFT, fg=UI_MUTED,
                 font=FONT_SMALL).grid(row=3, column=0, sticky="w", pady=(SP_XS, 0))

        # State
        self._dr_running = False
        self._dr_score = 0
        self._dr_high_score = 0
        self._dr_player_x = 80
        self._dr_player_y = 0.0   # y of feet (above ground)
        self._dr_player_vy = 0.0
        self._dr_on_ground = True
        self._dr_ducking = False
        self._dr_diving = False   # airborne + down held
        self._dr_obstacles: list = []
        self._dr_particles: list = []  # dust + streak effects
        self._dr_speed = 9.0
        self._dr_spawn_accum = 0.0
        self._dr_spawn_target = 260.0  # px until next spawn
        self._dr_pickup_accum = 0.0
        self._dr_pickup_target = 220.0
        self._dr_tick_job = None
        self._dr_frame = 0
        self._dr_ground_offset = 0
        self._dr_shake = 0
        self._dr_redraw()

    # Geometry helpers
    def _dr_ground_y(self) -> int:
        h = self._dr_canvas.winfo_height() or 260
        return h - 36  # ground line y

    def _dr_player_hitbox(self):
        """Returns (x1, y1, x2, y2) of player hitbox in canvas coords."""
        g = self._dr_ground_y()
        if self._dr_ducking and self._dr_on_ground:
            w, h = 58, 26
        elif self._dr_diving:
            # Tight vertical slice during dive — like an arrow
            w, h = 26, 44
        elif not self._dr_on_ground:
            # Tucked ball mid-jump — slightly shorter, same width
            w, h = 34, 38
        else:
            w, h = 36, 46
        x1 = self._dr_player_x - w / 2
        x2 = self._dr_player_x + w / 2
        y2 = g - self._dr_player_y
        y1 = y2 - h
        return x1, y1, x2, y2

    # Controls
    def _dr_jump(self):
        if not self._dr_running:
            # Space also starts the run when idle.
            self.start_dr_round()
            return
        if self._dr_on_ground and not self._dr_ducking:
            self._dr_player_vy = 20.0
            self._dr_on_ground = False
            self._dr_spawn_dust(6, kick=True)  # takeoff puff

    def _dr_set_duck(self, on: bool):
        self._dr_ducking = bool(on)
        if on and not self._dr_on_ground:
            # Dive-slam — instant strong downward impulse, then continuous
            # heavy gravity handled in _dr_tick.
            self._dr_player_vy = min(self._dr_player_vy, -14.0)
            self._dr_diving = True
        elif not on:
            self._dr_diving = False

    # Drawing
    def _dr_redraw(self):
        c = self._dr_canvas
        c.delete("all")
        w = c.winfo_width() or 1
        h = c.winfo_height() or 1
        g = self._dr_ground_y()

        # Crash shake offset
        sx = sy = 0
        if self._dr_shake > 0:
            import random
            mag = min(self._dr_shake, 5)
            sx = random.randint(-mag, mag)
            sy = random.randint(-mag, mag)
            # Translate whole scene by re-drawing with offsets — just apply to
            # the ground-scroll so the world jolts without clipping.

        # Parallax back layer — slow scrolling ground shadow
        back_dash_w = 26; back_gap = 40
        back_total = back_dash_w + back_gap
        back_off = int(self._dr_ground_offset * 0.35) % back_total
        x = -back_off
        while x < w:
            c.create_line(x, g + 14, x + back_dash_w, g + 14,
                          fill=UI_BORDER, width=1)
            x += back_total

        # Sky/ground separator
        c.create_line(0, g + sy, w, g + sy, fill=UI_BORDER_LT, width=2)

        # Foreground ground dashes scrolling left
        dash_w = 18; gap = 22
        total = dash_w + gap
        off = int(self._dr_ground_offset) % total
        x = -off
        while x < w:
            c.create_line(x, g + 6 + sy, x + dash_w, g + 6 + sy,
                          fill=UI_MUTED, width=1)
            x += total

        # Distant "clouds" (decorative dollar signs)
        for i, cx in enumerate((w * 0.18, w * 0.48, w * 0.78)):
            cy = 36 + (i * 14) % 18
            c.create_text(cx, cy, text="$", fill=UI_BORDER_LT,
                          font=FONT_SUBHEADING)

        # Particles (behind obstacles so dust sits close to ground)
        self._dr_draw_particles()

        # Obstacles
        for ob in self._dr_obstacles:
            self._dr_draw_obstacle(ob, g)

        # Player (shakes with the ground)
        self._dr_draw_player(g + sy)

        # Game-over veil
        if not self._dr_running and self._dr_score > 0:
            c.create_rectangle(0, 0, w, h, fill=UI_BG, stipple="gray25", outline="")
            c.create_text(w / 2, h / 2 - 18, text="CRASHED",
                          fill=UI_RUBY, font=FONT_HEADING)
            c.create_text(w / 2, h / 2 + 14,
                          text=f"Distance {self._dr_score}  ·  Best {self._dr_high_score}",
                          fill=UI_TEXT, font=FONT_SUBHEADING)
            c.create_text(w / 2, h / 2 + 40,
                          text="Press Start Run or Space to try again.",
                          fill=UI_MUTED, font=FONT_SMALL)

    def _dr_draw_player(self, g: int):
        c = self._dr_canvas
        x1, y1, x2, y2 = self._dr_player_hitbox()
        cx = (x1 + x2) / 2

        skin      = "#d4a574"
        skin_sh   = "#bf9470"
        hair_c    = "#8b3a1a"
        vest      = "#0d9488"
        vest_edge = "#0f766e"
        shirt     = "#e2e8f0"
        eye_c     = "#1a1a1a"
        button    = "#fbbf24"

        # ── Dive-slam (airborne + holding down) ──────────────────────────
        if self._dr_diving:
            # Motion blur streaks above him
            for i in range(3):
                ly = y1 - 4 - i * 5
                c.create_line(cx - 6, ly, cx + 6, ly,
                              fill=UI_GOLD, width=2)
            # Head at top
            head_r = 10
            hy = y1 + head_r
            # Hair mass + spikes flipped for downward motion (trailing upward)
            c.create_arc(cx - head_r * 1.1, hy - head_r,
                         cx + head_r * 1.1, hy + head_r * 0.3,
                         fill=hair_c, outline="",
                         start=0, extent=180, style="pieslice")
            for sx2, sh in ((-4, -12), (0, -14), (4, -11)):
                c.create_polygon(cx + sx2 - 2, hy - head_r + 2,
                                 cx + sx2,     hy + sh,
                                 cx + sx2 + 2, hy - head_r + 2,
                                 fill=hair_c, outline="")
            # Head
            c.create_oval(cx - head_r, hy - head_r,
                          cx + head_r, hy + head_r,
                          fill=skin, outline=skin_sh, width=1)
            # Focused eyes — narrow slits
            c.create_line(cx - 5, hy, cx - 2, hy, fill=eye_c, width=2)
            c.create_line(cx + 2, hy, cx + 5, hy, fill=eye_c, width=2)
            # Body — narrow vertical vest (arrow shape)
            body_top = hy + head_r - 1
            body_bot = y2 - 2
            c.create_polygon(cx - 10, body_top,
                             cx + 10, body_top,
                             cx + 3,  body_bot,
                             cx - 3,  body_bot,
                             fill=vest, outline=vest_edge, width=1)
            # Trailing wind lines behind/beside him
            c.create_line(cx - 14, body_top + 4, cx - 10, body_top + 10,
                          fill=UI_GOLD, width=1)
            c.create_line(cx + 10, body_top + 6, cx + 14, body_top + 12,
                          fill=UI_GOLD, width=1)
            return

        if self._dr_ducking and self._dr_on_ground:
            # Lunge/slide posture — head at right, body stretched leftward.
            head_r = 9
            hx = x2 - head_r - 3
            hy = (y1 + y2) / 2
            # Vest body (horizontal trapezoid-ish)
            c.create_polygon(
                x1 + 2, y1 + 8,
                hx - 2, y1 + 2,
                hx - 2, y2 - 2,
                x1 + 4, y2 - 2,
                fill=vest, outline=vest_edge, width=1)
            # Shirt band (trailing arm)
            c.create_rectangle(x1, y2 - 6, x1 + 8, y2 - 2,
                               fill=shirt, outline=vest_edge, width=1)
            # Back hair tuft
            c.create_polygon(hx - 4, hy - head_r + 1,
                             hx - 1, hy - head_r - 5,
                             hx + 2, hy - head_r,
                             hx + 5, hy - head_r - 4,
                             hx + 7, hy - head_r + 2,
                             fill=hair_c, outline="")
            # Head
            c.create_oval(hx - head_r, hy - head_r,
                          hx + head_r, hy + head_r,
                          fill=skin, outline=skin_sh, width=1)
            # Forward-facing eye
            c.create_oval(hx + 2, hy - 2, hx + 5, hy + 1,
                          fill=eye_c, outline="")
            # Determined mouth
            c.create_line(hx - 1, hy + 4, hx + 5, hy + 4,
                          fill=skin_sh, width=1)
            return

        # Standing / airborne Gerald
        head_r = 11
        # Slight forward lean while running (head drifts right a hair);
        # in the air he's upright (tucked).
        lean = 2 if self._dr_on_ground else 0
        hx = cx + lean
        hy = y1 + head_r + 2

        # Hair mass + spikes (swept back when moving fast)
        sweep = 0
        if self._dr_on_ground:
            sweep = min(3, int(self._dr_speed * 0.18))
        c.create_arc(hx - head_r * 1.1 - sweep, hy - head_r * 1.0,
                     hx + head_r * 1.1 - sweep, hy + head_r * 0.35,
                     fill=hair_c, outline="",
                     start=0, extent=180, style="pieslice")
        for sx2, sh in ((-5, -12), (-1, -14), (3, -11), (6, -8)):
            c.create_polygon(hx + sx2 - 2 - sweep, hy - head_r + 2,
                             hx + sx2 - sweep,     hy + sh,
                             hx + sx2 + 2 - sweep, hy - head_r + 2,
                             fill=hair_c, outline="")

        # Head
        c.create_oval(hx - head_r, hy - head_r,
                      hx + head_r, hy + head_r,
                      fill=skin, outline=skin_sh, width=1)

        # Eyes
        if not self._dr_on_ground:
            # Airborne wink (cheeky)
            c.create_oval(hx - 5, hy - 1, hx - 2, hy + 2, fill=eye_c, outline="")
            c.create_line(hx + 2, hy + 1, hx + 6, hy + 1, fill=skin_sh, width=1)
        else:
            c.create_oval(hx - 5, hy - 1, hx - 2, hy + 2, fill=eye_c, outline="")
            c.create_oval(hx + 2, hy - 1, hx + 5, hy + 2, fill=eye_c, outline="")
        # Smirk
        c.create_arc(hx - 4, hy + 2, hx + 4, hy + 8,
                     start=200, extent=140, style="arc",
                     outline=skin_sh, width=1)

        # Vest body
        body_top = hy + head_r - 1
        body_bot = y2 - 10 if self._dr_on_ground else y2 - 6
        c.create_polygon(cx - 13 + lean, body_top,
                         cx + 13 + lean, body_top,
                         cx + 11,        body_bot,
                         cx - 11,        body_bot,
                         fill=vest, outline=vest_edge, width=1)
        # White shirt V
        c.create_polygon(cx - 4 + lean, body_top,
                         cx + 4 + lean, body_top,
                         cx + lean,     body_top + 6,
                         fill=shirt, outline="")
        # Two gold buttons
        for yb in (body_top + 10, body_top + 18):
            c.create_oval(cx - 1.2 + lean, yb - 1.2,
                          cx + 1.2 + lean, yb + 1.2,
                          fill=button, outline="")

        if self._dr_on_ground:
            # ── Running: 4-phase cycle, dramatic leg swings + arm swing ──
            phase = (self._dr_frame // 3) % 4
            # Leg positions by phase (front_x_offset, back_x_offset, extension)
            # Phase 0: right (front) leg lifted high, left (back) extended straight down
            # Phase 1: both passing — both near center
            # Phase 2: left leg lifted high, right leg extended
            # Phase 3: passing
            if phase == 0:
                # Front leg high kick
                c.create_polygon(cx + 2, body_bot,
                                 cx + 12, body_bot + 2,
                                 cx + 10, body_bot + 12,
                                 cx + 1, body_bot + 8,
                                 fill=vest, outline="")
                # Back leg extended down + behind
                c.create_rectangle(cx - 11, body_bot, cx - 5, y2,
                                   fill=vest, outline="")
                c.create_rectangle(cx - 6, y2 - 4, cx + 1, y2,  # shoe
                                   fill=vest_edge, outline="")
            elif phase == 1:
                c.create_rectangle(cx - 7, body_bot, cx - 2, y2 - 1,
                                   fill=vest, outline="")
                c.create_rectangle(cx + 2, body_bot, cx + 7, y2 - 3,
                                   fill=vest, outline="")
            elif phase == 2:
                # Left leg high kick
                c.create_polygon(cx - 2, body_bot,
                                 cx - 12, body_bot + 2,
                                 cx - 10, body_bot + 12,
                                 cx - 1, body_bot + 8,
                                 fill=vest, outline="")
                c.create_rectangle(cx + 5, body_bot, cx + 11, y2,
                                   fill=vest, outline="")
                c.create_rectangle(cx - 1, y2 - 4, cx + 6, y2,
                                   fill=vest_edge, outline="")
            else:  # phase 3
                c.create_rectangle(cx - 7, body_bot, cx - 2, y2 - 3,
                                   fill=vest, outline="")
                c.create_rectangle(cx + 2, body_bot, cx + 7, y2 - 1,
                                   fill=vest, outline="")

            # Arm swing (opposite-phase to legs, small motion in front of vest)
            arm_y = body_top + 12
            if phase == 0 or phase == 3:
                # Arm swung back
                c.create_line(cx - 10 + lean, arm_y,
                              cx - 14 + lean, arm_y + 6,
                              fill=skin, width=3)
            else:
                # Arm swung forward
                c.create_line(cx + 10 + lean, arm_y,
                              cx + 16 + lean, arm_y - 2,
                              fill=skin, width=3)
        else:
            # ── Airborne: knees tucked up, arms close ──
            # Knees drawn as rounded rectangles angled up
            c.create_polygon(cx - 9, body_bot,
                             cx + 9, body_bot,
                             cx + 6, body_bot + 8,
                             cx - 6, body_bot + 8,
                             fill=vest, outline=vest_edge, width=1)
            # Shoes peeking at the bottom
            c.create_oval(cx - 8, body_bot + 6, cx - 2, body_bot + 11,
                          fill=vest_edge, outline="")
            c.create_oval(cx + 2, body_bot + 6, cx + 8, body_bot + 11,
                          fill=vest_edge, outline="")
            # Arm raised triumphantly
            c.create_line(cx + 12, body_top + 4,
                          cx + 18, body_top - 4,
                          fill=skin, width=3)

    def _dr_draw_obstacle(self, ob: dict, g: int):
        c = self._dr_canvas
        k = ob["kind"]
        x = ob["x"]
        if k == "cactus":
            w = ob["w"]; h = ob["h"]
            # Main stalk
            c.create_rectangle(x - w / 2, g - h, x + w / 2, g,
                               fill=UI_RUBY, outline=UI_RUBY, width=1)
            # Side arms
            arm_h = max(8, h // 3)
            c.create_rectangle(x - w / 2 - 6, g - h + 6,
                               x - w / 2, g - h + 6 + arm_h,
                               fill=UI_RUBY, outline="")
            c.create_rectangle(x + w / 2, g - h + h // 2,
                               x + w / 2 + 6, g - h + h // 2 + arm_h,
                               fill=UI_RUBY, outline="")
            # Label
            c.create_text(x, g + 2, text="$",
                          fill=UI_RUBY, font=FONT_CAPTION_BOLD)
        elif k == "bird":
            w = ob["w"]; h = ob["h"]
            y_center = ob["y"]
            phase = (self._dr_frame // 5) % 2
            # Body
            c.create_oval(x - w / 2, y_center - h / 2,
                          x + w / 2, y_center + h / 2,
                          fill=UI_AMETHYST, outline=UI_AMETHYST)
            # Wings (flap)
            if phase == 0:
                c.create_polygon(x - 4, y_center,
                                 x - 20, y_center - 14,
                                 x - 14, y_center,
                                 fill=UI_AMETHYST, outline="")
                c.create_polygon(x + 4, y_center,
                                 x + 20, y_center - 14,
                                 x + 14, y_center,
                                 fill=UI_AMETHYST, outline="")
            else:
                c.create_polygon(x - 4, y_center,
                                 x - 20, y_center + 14,
                                 x - 14, y_center,
                                 fill=UI_AMETHYST, outline="")
                c.create_polygon(x + 4, y_center,
                                 x + 20, y_center + 14,
                                 x + 14, y_center,
                                 fill=UI_AMETHYST, outline="")
            # Beak + symbol
            c.create_polygon(x + w / 2, y_center,
                             x + w / 2 + 6, y_center - 2,
                             x + w / 2 + 6, y_center + 2,
                             fill=UI_GOLD, outline="")
            c.create_text(x, y_center, text="%",
                          fill=UI_BG, font=FONT_CAPTION_BOLD)
        elif k == "coin":
            r = 11
            yc = ob["y"]
            # Subtle pulse via frame count
            pulse = 1 + (self._dr_frame // 4) % 2
            c.create_oval(x - r, yc - r, x + r, yc + r,
                          fill=UI_GOLD, outline=UI_WARNING_SOFT, width=pulse)
            c.create_text(x, yc, text="$", fill=UI_BG, font=FONT_CAPTION_BOLD)
        elif k == "gem":
            r = 13
            yc = ob["y"]
            c.create_polygon(x, yc - r, x + r, yc,
                             x, yc + r, x - r, yc,
                             fill=UI_SAPPHIRE, outline=UI_INFO_SOFT, width=2)
            c.create_text(x, yc, text="◆", fill=UI_BG, font=FONT_CAPTION_BOLD)

    # FX helpers
    def _dr_spawn_dust(self, count: int = 4, kick: bool = False):
        import random
        g = self._dr_ground_y()
        for _ in range(count):
            vx = random.uniform(-3.5, -0.5) if not kick else random.uniform(-5.0, -1.5)
            vy = random.uniform(-2.6, -0.4) if not kick else random.uniform(-3.4, -1.0)
            life = random.randint(10, 22)
            self._dr_particles.append({
                "kind": "dust",
                "x": self._dr_player_x + random.uniform(-10, 4),
                "y": g - 2 + random.uniform(-1, 1),
                "vx": vx, "vy": vy,
                "life": life, "max_life": life,
                "r": random.uniform(1.6, 3.0),
            })

    def _dr_spawn_streak(self):
        import random
        # Speed streaks at high velocity — horizontal slashes behind Gerald
        self._dr_particles.append({
            "kind": "streak",
            "x": self._dr_player_x + random.uniform(-8, 2),
            "y": self._dr_ground_y() - random.randint(8, 40),
            "vx": 0.0, "vy": 0.0,
            "life": 6, "max_life": 6,
            "len": random.randint(14, 28),
        })

    def _dr_update_particles(self):
        for p in self._dr_particles:
            k = p["kind"]
            if k == "dust":
                p["x"] += p["vx"] - self._dr_speed * 0.35
                p["y"] += p["vy"]
                p["vy"] += 0.18
            elif k == "sparkle":
                p["x"] += p["vx"] - self._dr_speed * 0.45
                p["y"] += p["vy"]
                p["vy"] += 0.30
            elif k == "floater":
                p["x"] += p["vx"] - self._dr_speed * 0.35
                p["y"] += p["vy"]
            else:  # streak — static, just fades
                p["x"] -= self._dr_speed * 1.1
            p["life"] -= 1
        self._dr_particles = [p for p in self._dr_particles
                              if p["life"] > 0 and p["x"] > -60]

    def _dr_draw_particles(self):
        c = self._dr_canvas
        for p in self._dr_particles:
            frac = p["life"] / p["max_life"]
            k = p["kind"]
            if k == "dust":
                r = max(0.5, p["r"] * frac)
                shade = UI_BORDER_LT if frac > 0.5 else UI_BORDER
                c.create_oval(p["x"] - r, p["y"] - r,
                              p["x"] + r, p["y"] + r,
                              fill=shade, outline="")
            elif k == "sparkle":
                r = max(0.6, p["r"] * frac)
                c.create_oval(p["x"] - r, p["y"] - r,
                              p["x"] + r, p["y"] + r,
                              fill=p["color"], outline="")
            elif k == "floater":
                c.create_text(p["x"], p["y"], text=p["text"],
                              fill=p["color"], font=FONT_CAPTION_BOLD)
            else:  # streak
                ln = p["len"] * frac
                c.create_line(p["x"] - ln, p["y"],
                              p["x"], p["y"],
                              fill=UI_GOLD, width=2)

    # Round lifecycle
    def start_dr_round(self):
        if self._dr_running:
            return
        self._dr_running = True
        self._dr_score = 0
        self._dr_obstacles.clear()
        self._dr_particles.clear()
        self._dr_speed = 9.0
        self._dr_spawn_accum = 0.0
        self._dr_spawn_target = 240.0
        self._dr_pickup_accum = 0.0
        self._dr_pickup_target = 200.0
        self._dr_player_y = 0.0
        self._dr_player_vy = 0.0
        self._dr_on_ground = True
        self._dr_ducking = False
        self._dr_diving = False
        self._dr_shake = 0
        self._dr_frame = 0
        self._dr_score_var.set("0")
        self._dr_status_var.set("Running. Jump · hold ↓ to dive-slam mid-air · duck birds.")
        self._dr_canvas.focus_set()
        if self._dr_tick_job is not None:
            try: self.after_cancel(self._dr_tick_job)
            except Exception: pass
        self._dr_tick_job = self.after(33, self._dr_tick)

    def _dr_tick(self):
        if not self._dr_running:
            return
        import random
        self._dr_frame += 1
        # Speed ramp: faster base + higher ceiling to match the extra control
        self._dr_speed = min(19.0, 9.0 + (self._dr_score / 220.0) * 0.75)

        # Physics
        was_airborne = not self._dr_on_ground
        if was_airborne:
            grav = 3.2 if self._dr_diving else 1.35
            self._dr_player_vy -= grav
            self._dr_player_y += self._dr_player_vy
            if self._dr_player_y <= 0:
                self._dr_player_y = 0.0
                self._dr_player_vy = 0.0
                self._dr_on_ground = True
                # Dive landing is heavier than a normal landing.
                burst = 10 if self._dr_diving else 5
                self._dr_spawn_dust(burst, kick=True)
                if self._dr_diving:
                    self._dr_shake = 5
                self._dr_diving = False

        # Ground scroll offset
        self._dr_ground_offset += self._dr_speed

        # Move obstacles leftward
        for ob in self._dr_obstacles:
            ob["x"] -= self._dr_speed
        self._dr_obstacles = [ob for ob in self._dr_obstacles if ob["x"] > -60]

        # Running dust trail (while grounded and not ducking)
        if self._dr_on_ground and not self._dr_ducking and self._dr_frame % 4 == 0:
            self._dr_spawn_dust(1)
        # Speed streaks when fast
        if self._dr_speed > 13.5 and self._dr_frame % 2 == 0:
            self._dr_spawn_streak()

        # Spawn by distance
        self._dr_spawn_accum += self._dr_speed
        if self._dr_spawn_accum >= self._dr_spawn_target:
            self._dr_spawn_accum = 0.0
            gap_min = max(130, 240 - self._dr_score // 5)
            self._dr_spawn_target = random.randint(gap_min, gap_min + 170)
            self._dr_spawn_obstacle()

        # Pickup lines spawn on their own cadence
        self._dr_pickup_accum += self._dr_speed
        if self._dr_pickup_accum >= self._dr_pickup_target:
            self._dr_pickup_accum = 0.0
            self._dr_pickup_target = random.randint(180, 340)
            self._dr_spawn_pickups()

        # Particles step
        self._dr_update_particles()
        if self._dr_shake > 0:
            self._dr_shake -= 1

        # Collision — pickups award score, real obstacles end the run.
        px1, py1, px2, py2 = self._dr_player_hitbox()
        caught = []
        for ob in self._dr_obstacles:
            ox1, oy1, ox2, oy2 = self._dr_obstacle_hitbox(ob)
            if px1 < ox2 and px2 > ox1 and py1 < oy2 and py2 > oy1:
                if ob["kind"] in ("coin", "gem"):
                    caught.append(ob)
                else:
                    self._dr_end_round("crash")
                    return
        for ob in caught:
            self._dr_pickup(ob)
            try: self._dr_obstacles.remove(ob)
            except ValueError: pass

        # Score — faster tempo since speed is higher
        self._dr_score += 1
        if self._dr_score % 5 == 0:
            self._dr_score_var.set(str(self._dr_score))

        self._dr_redraw()
        self._dr_tick_job = self.after(33, self._dr_tick)

    def _dr_obstacle_hitbox(self, ob: dict):
        g = self._dr_ground_y()
        x = ob["x"]; w = ob["w"]; h = ob["h"]
        k = ob["kind"]
        if k == "cactus":
            return (x - w / 2, g - h, x + w / 2, g)
        else:  # bird / coin / gem — all use centered box at ob["y"]
            yc = ob["y"]
            return (x - w / 2, yc - h / 2, x + w / 2, yc + h / 2)

    def _dr_spawn_obstacle(self):
        import random
        c = self._dr_canvas
        w = c.winfo_width() or 800
        g = self._dr_ground_y()
        # Birds unlock after distance 180
        allow_bird = self._dr_score >= 180
        kind = "cactus"
        if allow_bird and random.random() < 0.35:
            kind = "bird"
        if kind == "cactus":
            # Occasional double-cactus for harder jumps
            choice = random.choices(["s", "m", "l", "dbl"],
                                    weights=[36, 36, 18, 10], k=1)[0]
            if choice == "s":
                ob = {"x": w + 20, "w": 18, "h": 30, "kind": "cactus"}
            elif choice == "m":
                ob = {"x": w + 20, "w": 20, "h": 42, "kind": "cactus"}
            elif choice == "l":
                ob = {"x": w + 20, "w": 24, "h": 56, "kind": "cactus"}
            else:
                ob = {"x": w + 20, "w": 34, "h": 42, "kind": "cactus"}
            self._dr_obstacles.append(ob)
        else:
            # Bird altitudes: low (must duck), mid (must jump or duck), high (must jump under)
            alt = random.choice(["low", "mid", "high"])
            if alt == "low":
                y = g - 26  # forces duck
            elif alt == "mid":
                y = g - 52  # jump or duck both work
            else:
                y = g - 78  # must stay grounded (don't jump into it)
            ob = {"x": w + 20, "y": y, "w": 36, "h": 22, "kind": "bird"}
            self._dr_obstacles.append(ob)

    def _dr_spawn_pickups(self):
        import random
        c = self._dr_canvas
        w = c.winfo_width() or 800
        g = self._dr_ground_y()
        alt = random.choice(["ground", "ground", "jump", "high"])
        y = {"ground": g - 16, "jump": g - 52, "high": g - 84}[alt]
        n = random.randint(3, 5)
        # Sometimes end the line with a gem as the jackpot reward
        has_gem = random.random() < 0.30
        for i in range(n):
            kind = "gem" if (has_gem and i == n - 1) else "coin"
            self._dr_obstacles.append({
                "x": w + 30 + i * 36,
                "y": y, "w": 22, "h": 22,
                "kind": kind,
            })

    def _dr_pickup(self, ob: dict):
        import random
        val = 10 if ob["kind"] == "coin" else 30
        color = UI_GOLD if ob["kind"] == "coin" else UI_SAPPHIRE
        self._dr_score += val
        for _ in range(10):
            self._dr_particles.append({
                "kind": "sparkle",
                "x": ob["x"], "y": ob["y"],
                "vx": random.uniform(-3.2, 3.2),
                "vy": random.uniform(-5.0, -0.8),
                "life": 18, "max_life": 18,
                "color": color,
                "r": random.uniform(1.6, 3.0),
            })
        self._dr_particles.append({
            "kind": "floater",
            "x": ob["x"], "y": ob["y"] - 10,
            "vx": 0.0, "vy": -1.6,
            "life": 26, "max_life": 26,
            "text": f"+{val}",
            "color": color,
        })

    def finish_dr_round(self):
        if self._dr_running:
            self._dr_end_round("manual")

    def _dr_end_round(self, reason: str = "crash"):
        if not self._dr_running:
            return
        self._dr_running = False
        if self._dr_tick_job is not None:
            try: self.after_cancel(self._dr_tick_job)
            except Exception: pass
            self._dr_tick_job = None

        final = self._dr_score
        self._dr_score_var.set(str(final))
        if final > self._dr_high_score:
            self._dr_high_score = final
        self._dr_high_var.set(f"Best {self._dr_high_score}")

        # Reward: 1 pt per 4 distance, then × multiplier
        mult = getattr(self.state.game, "score_multiplier", 1.0) or 1.0
        gained = int(round((final / 4.0) * mult))

        self.state.game.total_score += gained
        self.state.game.last_score_gain = gained
        self.state.game.mini_game_rounds_won += 1
        new_high = gained > self.state.game.mini_game_high_score
        if new_high:
            self.state.game.mini_game_high_score = gained
            if "Mini Game High Scorer" not in self.state.game.achievements:
                self.state.game.achievements.append("Mini Game High Scorer")

        gems = final // 150
        if gems > 0:
            self.state.game.gems = getattr(self.state.game, "gems", 0) + gems
            self.state.game.lifetime_gems_earned = getattr(self.state.game, "lifetime_gems_earned", 0) + gems

        self.game_engine.add_season_xp(10)
        self.game_engine.complete_challenge("mini_game")

        reason_txt = {
            "crash":  "Hit by debt!",
            "manual": "Run ended.",
        }.get(reason, "Run over.")
        self._dr_status_var.set(
            f"{reason_txt}  Distance {final}  ·  +{gained} Gold"
            + ("  \U0001F3C6 NEW HIGH" if new_high else "")
            + (f"  ·  Gems +{gems}" if gems else "")
            + "  ·  Press Space to run again.")

        try:
            self.save_state()
            self.refresh_game_text()
        except Exception:
            pass

        self._dr_redraw()

