    def _setup_completeness_steps(self):
        """Return list of (label, done) tuples for the checklist."""
        s = self.state
        steps = [
            (f"Pay frequency · {s.pay_frequency or 'not set'}",
             bool(s.pay_frequency)),
            ("First bill added", len(s.bills) > 0),
            ("First sinking fund added", len(s.funds) > 0),
            ("First savings goal added", len(s.goals) > 0),
            ("Target spending mix locked",
             bool(getattr(s, "target_is_locked", False))),
            ("First pay logged", len(s.incomes) > 0),
        ]
        return steps

    def _draw_health_ring(self, canvas, pct: float):
        """Draw a thick progress ring. pct is 0..1."""
        canvas.delete("all")
        w = int(canvas.winfo_reqwidth()) or 72
        h = int(canvas.winfo_reqheight()) or 72
        cx, cy = w / 2, h / 2
        r = min(w, h) / 2 - 4
        # Track
        canvas.create_oval(cx - r, cy - r, cx + r, cy + r,
                           outline=UI_BORDER, width=6)
        if pct > 0:
            extent = -360 * max(0.0, min(1.0, pct))
            if pct >= 0.8: color = UI_EMERALD
            elif pct >= 0.5: color = UI_GOLD
            else: color = UI_RUBY
            canvas.create_arc(cx - r, cy - r, cx + r, cy + r,
                              start=90, extent=extent, style="arc",
                              outline=color, width=6)
        pct_label = f"{int(round(pct * 100))}%"
        canvas.create_text(cx, cy, text=pct_label, fill=UI_TEXT_BRIGHT,
                           font=FONT_BODY_BOLD)

    def _refresh_setup_completeness(self):
        if not hasattr(self, "_setup_health_checklist"):
            return
        steps = self._setup_completeness_steps()
        done = sum(1 for _, d in steps if d)
        pct = done / len(steps) if steps else 1.0
        self._draw_health_ring(self._setup_health_ring, pct)
        # Rebuild checklist
        for c in list(self._setup_health_checklist.winfo_children()):
            try: c.destroy()
            except tk.TclError: pass
        hdr = f"{done} of {len(steps)} complete"
        tk.Label(self._setup_health_checklist, text=hdr, bg=UI_SURFACE,
                 fg=UI_TEXT_BRIGHT, font=FONT_SMALL_BOLD, anchor="w").pack(
                 fill="x")
        remaining = [lbl for lbl, d in steps if not d]
        completed = [lbl for lbl, d in steps if d]
        for lbl in remaining[:3]:
            line = tk.Frame(self._setup_health_checklist, bg=UI_SURFACE)
            line.pack(fill="x", pady=(SP_XS, 0))
            tk.Label(line, text="○", bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_SMALL_BOLD).pack(side="left")
            tk.Label(line, text=f"  {lbl}", bg=UI_SURFACE, fg=UI_TEXT,
                     font=FONT_SMALL, anchor="w").pack(side="left", fill="x",
                                                        expand=True)
        # If everything is done, show a cheer line
        if not remaining:
            tk.Label(self._setup_health_checklist,
                     text="All set — you're fully configured.",
                     bg=UI_SURFACE, fg=UI_EMERALD, font=FONT_SMALL,
                     anchor="w").pack(fill="x", pady=(SP_XS, 0))
        elif len(remaining) > 3:
            tk.Label(self._setup_health_checklist,
                     text=f"  +{len(remaining) - 3} more step"
                          f"{'s' if len(remaining) - 3 != 1 else ''}",
                     bg=UI_SURFACE, fg=UI_MUTED, font=FONT_MICRO,
                     anchor="w").pack(fill="x", pady=(SP_XS, 0))

    def _at_risk_items(self):
        """Return list of dicts describing at-risk items."""
        today = date.today()
        horizon = today + timedelta(days=7)
        out = []
        for b in self.state.bills:
            if not b.due_date:
                continue
            saved_ratio = (b.current_saved / b.amount) if b.amount > 0 else 1.0
            if b.due_date < today:
                out.append({
                    "kind": "bill", "name": b.name,
                    "severity": "overdue",
                    "detail": f"${b.current_saved:,.0f} of ${b.amount:,.0f} saved · overdue",
                })
            elif b.due_date <= horizon and saved_ratio < 0.5:
                days = (b.due_date - today).days
                when = "today" if days == 0 else ("tomorrow" if days == 1 else f"in {days}d")
                out.append({
                    "kind": "bill", "name": b.name,
                    "severity": "urgent",
                    "detail": f"${b.current_saved:,.0f} of ${b.amount:,.0f} · {when}",
                })
        for f in self.state.funds:
            if not f.target_date or f.target_amount <= 0:
                continue
            days_total = max(1, (f.target_date - today).days +
                              max(0, (today - (f.target_date -
                                                timedelta(days=180))).days))
            # Simpler: ratio of time elapsed vs ratio of saved
            days_left = (f.target_date - today).days
            if days_left <= 0:
                if f.current_saved < f.target_amount:
                    out.append({
                        "kind": "fund", "name": f.name,
                        "severity": "overdue",
                        "detail": f"${f.current_saved:,.0f} of ${f.target_amount:,.0f} · target passed",
                    })
                continue
            saved_ratio = f.current_saved / f.target_amount
            # Pace estimate: we don't know start date, so use a simple 60-day lookback
            # and say "behind" if saved_ratio < (1 - days_left / (days_left + 180))
            expected = 1 - (days_left / max(1, days_left + 180))
            if saved_ratio + 0.15 < expected:
                out.append({
                    "kind": "fund", "name": f.name,
                    "severity": "behind",
                    "detail": f"${f.current_saved:,.0f} of ${f.target_amount:,.0f} · "
                              f"{days_left}d left",
                })
        # Sort overdue first, then urgent, then behind
        order = {"overdue": 0, "urgent": 1, "behind": 2}
        out.sort(key=lambda it: order.get(it["severity"], 9))
        return out

    def _refresh_at_risk(self):
        if not hasattr(self, "_at_risk_body"):
            return
        for c in list(self._at_risk_body.winfo_children()):
            try: c.destroy()
            except tk.TclError: pass
        items = self._at_risk_items()
        if not items:
            tk.Label(self._at_risk_body,
                     text="Nothing at risk right now. Nice work holding the line.",
                     bg=UI_SURFACE, fg=UI_EMERALD, font=FONT_SMALL,
                     wraplength=360, justify="left", anchor="w").pack(
                     fill="x", pady=(SP_XS, 0))
            return
        severity_color = {"overdue": UI_RUBY, "urgent": UI_GOLD,
                           "behind": UI_SAPPHIRE}
        icon_map = {"bill": "\U0001f4a1", "fund": "\U0001f3e6"}
        for it in items[:5]:
            row = tk.Frame(self._at_risk_body, bg=UI_SURFACE, cursor="hand2")
            row.pack(fill="x", pady=(SP_XS, 0))
            stripe = tk.Frame(row, bg=severity_color.get(it["severity"], UI_BORDER),
                               width=3)
            stripe.pack(side="left", fill="y")
            txt = tk.Frame(row, bg=UI_SURFACE, padx=SP_SM, pady=3)
            txt.pack(side="left", fill="x", expand=True)
            tk.Label(txt,
                     text=f"{icon_map.get(it['kind'], '•')}  {it['name']}",
                     bg=UI_SURFACE, fg=UI_TEXT, font=FONT_SMALL_BOLD,
                     anchor="w").pack(fill="x")
            tk.Label(txt, text=it["detail"], bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_MICRO, anchor="w").pack(fill="x")
            sev = tk.Label(row, text=it["severity"].upper(), bg=UI_SURFACE,
                            fg=severity_color.get(it["severity"], UI_MUTED),
                            font=FONT_MICRO, padx=SP_SM)
            sev.pack(side="right")
            # Click jumps to the row
            kind_to_tree = {"bill": ("bills", "bill_tree"),
                             "fund": ("funds", "fund_tree")}
            sub, tree_attr = kind_to_tree[it["kind"]]
            if it["kind"] == "bill":
                idx = self.state.bills.index(
                    next(b for b in self.state.bills if b.name == it["name"]))
            else:
                idx = self.state.funds.index(
                    next(f for f in self.state.funds if f.name == it["name"]))
            for w in (row, stripe, txt, sev, *txt.winfo_children()):
                w.bind("<Button-1>",
                       lambda _e, s=sub, ta=tree_attr, i=idx:
                       self._cmd_palette_select_tree(s, ta, i))
        if len(items) > 5:
            tk.Label(self._at_risk_body,
                     text=f"+{len(items) - 5} more", bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_MICRO, anchor="w").pack(fill="x",
                                                       pady=(SP_XS, 0))

