    def _draw_review_mix_bars(self, rows):
        """Render side-by-side Actual vs Target bars per category."""
        canvas = getattr(self, "review_mix_canvas", None)
        if canvas is None:
            return
        canvas.delete("all")
        canvas.update_idletasks()
        w = max(240, canvas.winfo_width())
        h = max(120, canvas.winfo_height())

        if not rows:
            scope = getattr(self, "_review_mix_scope_word", "this period")
            canvas.create_text(w // 2, h // 2,
                               text=f"No outgoing mix to compare for {scope}.",
                               fill=UI_MUTED, font=FONT_CAPTION)
            return

        rows = rows[:8]
        left_gutter = 110          # category label column
        right_gutter = 80          # diff column
        bar_area_w = max(80, w - left_gutter - right_gutter - 20)
        # Each row: label top, two stacked bars (actual + target), spacer
        row_h = 38
        pad_top = 26

        # Legend
        canvas.create_rectangle(10, 6, 22, 16, fill=UI_SAPPHIRE, outline="")
        canvas.create_text(26, 11, text="Actual", fill=UI_TEXT,
                           font=FONT_MICRO, anchor="w")
        canvas.create_rectangle(80, 6, 92, 16, fill=UI_MUTED, outline="")
        canvas.create_text(96, 11, text="Target", fill=UI_TEXT,
                           font=FONT_MICRO, anchor="w")

        max_pct = max((max(a, t) for _lbl, a, t, _d in rows), default=10.0)
        max_pct = max(10.0, math.ceil(max_pct / 10.0) * 10.0)  # round up to nearest 10

        scope_start = getattr(self, "_last_mix_start", None)
        scope_end = getattr(self, "_last_mix_end", None)
        scope_word = getattr(self, "_review_mix_scope_word", "this period")

        for idx, (label, actual, target, diff) in enumerate(rows):
            top_y = pad_top + idx * row_h
            mid_y = top_y + 16
            row_tag = f"mix_row_{idx}"
            # Invisible hit zone spanning the whole row (clickable)
            canvas.create_rectangle(4, top_y - 2, w - 4, top_y + 28,
                                     fill="", outline="", tags=(row_tag,))
            # Category label
            canvas.create_text(10, top_y + 8, text=label[:18], fill=UI_TEXT,
                               font=FONT_CAPTION_BOLD, anchor="w", tags=(row_tag,))
            # Actual bar (top half)
            a_w = int(bar_area_w * (actual / max_pct))
            canvas.create_rectangle(left_gutter, top_y,
                                     left_gutter + bar_area_w, top_y + 12,
                                     fill=UI_SURFACE2, outline="", tags=(row_tag,))
            if a_w > 0:
                # Over-target → ruby, under → sapphire, on → emerald
                if diff > 1.0:
                    color = UI_RUBY
                elif diff < -1.0:
                    color = UI_SAPPHIRE
                else:
                    color = UI_EMERALD
                canvas.create_rectangle(left_gutter, top_y,
                                         left_gutter + a_w, top_y + 12,
                                         fill=color, outline="", tags=(row_tag,))
            canvas.create_text(left_gutter + bar_area_w + 4, top_y + 6,
                               text=f"{actual:.1f}%", fill=UI_TEXT,
                               font=FONT_MICRO, anchor="w", tags=(row_tag,))
            # Target bar (bottom half)
            t_w = int(bar_area_w * (target / max_pct))
            canvas.create_rectangle(left_gutter, mid_y,
                                     left_gutter + bar_area_w, mid_y + 8,
                                     fill=UI_SURFACE2, outline="", tags=(row_tag,))
            if t_w > 0:
                canvas.create_rectangle(left_gutter, mid_y,
                                         left_gutter + t_w, mid_y + 8,
                                         fill=UI_MUTED, outline="", tags=(row_tag,))
            canvas.create_text(left_gutter + bar_area_w + 4, mid_y + 4,
                               text=f"{target:.1f}%", fill=UI_MUTED,
                               font=FONT_MICRO, anchor="w", tags=(row_tag,))

            # Diff label (right gutter)
            if abs(diff) < 0.05:
                diff_text = "on target"
                diff_color = UI_EMERALD
            else:
                arrow = "▲" if diff > 0 else "▼"
                diff_text = f"{arrow} {abs(diff):.1f} pts"
                diff_color = UI_RUBY if diff > 1.0 else UI_SAPPHIRE if diff < -1.0 else UI_EMERALD
            canvas.create_text(w - 6, top_y + 11, text=diff_text,
                               fill=diff_color, font=FONT_MICRO, anchor="e", tags=(row_tag,))

            canvas.tag_bind(row_tag, "<Button-1>",
                             lambda _e, c=label: self._open_category_drilldown(
                                 c, start_date=scope_start, end_date=scope_end,
                                 scope_word=scope_word))
            canvas.tag_bind(row_tag, "<Enter>",
                             lambda _e: canvas.configure(cursor="hand2"))
            canvas.tag_bind(row_tag, "<Leave>",
                             lambda _e: canvas.configure(cursor=""))

        # Footer hint
        canvas.create_text(w - 6, h - 6, anchor="se",
                           text="Tip: click a row to see transactions",
                           fill=UI_MUTED, font=FONT_MICRO)

    def _draw_personality_bar(self, canvas: tk.Canvas, value: int, color: str):
        canvas.delete("all")
        canvas.update_idletasks()
        w = max(100, canvas.winfo_width())
        h = int(canvas["height"])
        canvas.create_rectangle(0, 0, w, h, fill=UI_SURFACE2, outline="")
        fill_w = int(w * (value / 99.0))
        if fill_w > 0:
            canvas.create_rectangle(0, 0, fill_w, h, fill=color, outline="")
        for frac in (0.33, 0.66):
            x = int(w * frac)
            canvas.create_line(x, 2, x, h - 2, fill=UI_BORDER, width=1)

    def _draw_personality_radar(self, canvas: tk.Canvas, attrs: dict, target: dict, accent: str):
        """Hexagon radar. User values filled, archetype target outlined."""
        import math
        canvas.delete("all")
        w = int(canvas["width"]); h = int(canvas["height"])
        cx, cy = w // 2, h // 2
        R = min(cx, cy) - 22
        order = [a[0] for a in PERSONALITY_ATTRIBUTES]  # 6 axes
        n = len(order)
        angles = [(-math.pi / 2) + (2 * math.pi * i / n) for i in range(n)]

        # Concentric grid (25/50/75/100 %).
        for frac in (0.25, 0.50, 0.75, 1.0):
            pts = []
            for a in angles:
                pts.append(cx + math.cos(a) * R * frac)
                pts.append(cy + math.sin(a) * R * frac)
            canvas.create_polygon(pts, outline=UI_BORDER, fill="", width=1)
        # Axis spokes.
        for a in angles:
            canvas.create_line(cx, cy, cx + math.cos(a) * R, cy + math.sin(a) * R,
                               fill=UI_BORDER, width=1)

        # Archetype target polygon (outline only).
        tgt_pts = []
        for i, key in enumerate(order):
            r = R * (target.get(key, 0) / 99.0)
            tgt_pts.append(cx + math.cos(angles[i]) * r)
            tgt_pts.append(cy + math.sin(angles[i]) * r)
        canvas.create_polygon(tgt_pts, outline=UI_MUTED, fill="", width=2, dash=(3, 3))

        # User polygon (filled).
        usr_pts = []
        for i, key in enumerate(order):
            r = R * (attrs.get(key, 0) / 99.0)
            usr_pts.append(cx + math.cos(angles[i]) * r)
            usr_pts.append(cy + math.sin(angles[i]) * r)
        canvas.create_polygon(usr_pts, outline=accent, fill=accent, width=2, stipple="gray50")
        canvas.create_polygon(usr_pts, outline=accent, fill="", width=2)

        # Axis labels.
        short_labels = {"discipline": "DISC", "thrift": "THRF", "vision": "VISN",
                        "diversity": "DIV", "volatility": "VOL", "resilience": "RES"}
        for i, key in enumerate(order):
            lx = cx + math.cos(angles[i]) * (R + 14)
            ly = cy + math.sin(angles[i]) * (R + 14)
            canvas.create_text(lx, ly, text=short_labels[key], fill=UI_TEXT,
                               font=("Segoe UI Variable Text", 8, "bold"))

    def _compute_monthly_trend_data(self, num_months: int = 6) -> list:
        """Return [(year, month, label, income, outgoing), ...] for the last N
        calendar months ending at the current review target date (most-recent last)."""
        ref = self._review_target_date() if hasattr(self, "_review_target_date") else date.today()
        # Walk back num_months (inclusive of ref month)
        months = []
        y, m = ref.year, ref.month
        for _ in range(num_months):
            months.append((y, m))
            m -= 1
            if m == 0:
                m = 12
                y -= 1
        months.reverse()

        rows = []
        for (yr, mo) in months:
            start, end = month_bounds(date(yr, mo, 1))
            income = sum(x.amount for x in self.state.incomes
                         if start <= x.received_on <= end)
            outgoing = sum(tx.amount() for tx in self.state.transactions
                           if tx.direction() == "out"
                           and tx.matched_type != "ignore"
                           and start <= tx.tx_date <= end)
            label = date(yr, mo, 1).strftime("%b")
            rows.append((yr, mo, label, income, outgoing))
        return rows

    def _draw_monthly_trend_chart(self, rows):
        """Render a 6-month Income vs Outgoing bar chart on review_trend_canvas."""
        canvas = getattr(self, "review_trend_canvas", None)
        if canvas is None:
            return
        canvas.delete("all")
        if not rows:
            return

        w = canvas.winfo_width() or 600
        h = canvas.winfo_height() or 240
        # Margins
        m_left, m_right, m_top, m_bot = 52, 20, 32, 42
        plot_w = max(10, w - m_left - m_right)
        plot_h = max(10, h - m_top - m_bot)

        max_val = max((max(r[3], r[4]) for r in rows), default=0)
        if max_val <= 0:
            canvas.create_text(w / 2, h / 2,
                               text="No income or outgoing data in this window yet.",
                               fill=UI_MUTED, font=FONT_BODY)
            return

        # Round the max up to a nice value for the y-scale
        def _nice_ceil(v):
            if v <= 0:
                return 1
            import math as _m
            exp = 10 ** (len(str(int(v))) - 1)
            return int(_m.ceil(v / exp) * exp)

        y_top_val = _nice_ceil(max_val * 1.1)

        # Legend (top-right of plot area)
        lg_x = w - m_right
        lg_y = 14
        canvas.create_rectangle(lg_x - 150, lg_y - 4, lg_x - 138, lg_y + 8,
                                 fill=UI_EMERALD, outline="")
        canvas.create_text(lg_x - 134, lg_y + 2, text="Income",
                            fill=UI_TEXT, font=FONT_SMALL, anchor="w")
        canvas.create_rectangle(lg_x - 72, lg_y - 4, lg_x - 60, lg_y + 8,
                                 fill=UI_RUBY, outline="")
        canvas.create_text(lg_x - 56, lg_y + 2, text="Outgoing",
                            fill=UI_TEXT, font=FONT_SMALL, anchor="w")

        # Y-axis gridlines + labels (0, 50%, 100%)
        for frac in (0.0, 0.5, 1.0):
            gy = m_top + plot_h - (frac * plot_h)
            canvas.create_line(m_left, gy, w - m_right, gy,
                                fill=UI_BORDER, dash=(2, 3))
            val_lbl = f"${int(y_top_val * frac):,}"
            canvas.create_text(m_left - 6, gy, text=val_lbl,
                                fill=UI_MUTED, font=FONT_SMALL, anchor="e")

        # Bar geometry — each month gets a cell of width cell_w;
        # within the cell: [gap][income bar][bar_gap][outgoing bar][gap]
        cell_w = plot_w / len(rows)
        bar_pair_ratio = 0.62   # fraction of cell used by both bars combined
        bar_gap = 4             # px between income and outgoing bar
        pair_w = cell_w * bar_pair_ratio
        bar_w_each = max(6, (pair_w - bar_gap) / 2)

        baseline = m_top + plot_h
        for idx, (yr, mo, label, income, outgoing) in enumerate(rows):
            cx = m_left + cell_w * idx + cell_w / 2
            # Month label (x-axis)
            canvas.create_text(cx, baseline + 6, text=label,
                                fill=UI_TEXT, font=FONT_SMALL_BOLD, anchor="n")
            # Net label under month
            net = income - outgoing
            net_color = UI_EMERALD if net >= 0 else UI_RUBY
            net_str = f"{'+' if net >= 0 else '−'}${abs(net):,.0f}"
            canvas.create_text(cx, baseline + 22, text=net_str,
                                fill=net_color, font=FONT_CAPTION, anchor="n")

            # Income bar (left)
            inc_h = (income / y_top_val) * plot_h if y_top_val else 0
            ix0 = cx - bar_gap / 2 - bar_w_each
            ix1 = cx - bar_gap / 2
            if inc_h > 0:
                canvas.create_rectangle(ix0, baseline - inc_h, ix1, baseline,
                                         fill=UI_EMERALD, outline="")
                if inc_h > 14:
                    canvas.create_text((ix0 + ix1) / 2, baseline - inc_h - 2,
                                        text=f"${income:,.0f}",
                                        fill=UI_EMERALD,
                                        font=FONT_CAPTION_BOLD, anchor="s")

            # Outgoing bar (right)
            out_h = (outgoing / y_top_val) * plot_h if y_top_val else 0
            ox0 = cx + bar_gap / 2
            ox1 = cx + bar_gap / 2 + bar_w_each
            if out_h > 0:
                canvas.create_rectangle(ox0, baseline - out_h, ox1, baseline,
                                         fill=UI_RUBY, outline="")
                if out_h > 14:
                    canvas.create_text((ox0 + ox1) / 2, baseline - out_h - 2,
                                        text=f"${outgoing:,.0f}",
                                        fill=UI_RUBY,
                                        font=FONT_CAPTION_BOLD, anchor="s")

        # X-axis baseline
        canvas.create_line(m_left, baseline, w - m_right, baseline,
                            fill=UI_BORDER_LT, width=1)

    def _health_color(self, status: str) -> str:
        """Map a health score status to an accent color."""
        return {"strong": UI_EMERALD, "fair": UI_GOLD, "fragile": UI_RUBY}.get(status, UI_MUTED)

    def _render_review_insights(self, data: dict, health: dict, forecast: dict, scope_word: str):
        """Render Monthly Insights as structured stat rows + observation list."""
        stats_frame = getattr(self, "_review_stats_frame", None)
        obs_frame = getattr(self, "_review_observations_frame", None)
        if stats_frame is None or obs_frame is None:
            return
        for w in stats_frame.winfo_children():
            w.destroy()
        for w in obs_frame.winfo_children():
            w.destroy()

        pr = data["pending_review"]
        stats = [
            ("Income",         f"${data['income_total']:,.0f}",
                UI_EMERALD,
                f"logged {scope_word}"),
            ("Outgoing",       f"${data['outgoing_total']:,.0f}",
                UI_RUBY,
                f"{data['outgoing_count']} txn{'s' if data['outgoing_count'] != 1 else ''}"),
            ("Verified",       f"{data['verified']} / {data['committed']}",
                UI_SAPPHIRE,
                "committed transactions"),
            ("Pending Review", str(pr),
                UI_GOLD if pr > 0 else UI_MUTED,
                "awaiting classification"),
            ("Savings Rate",   f"{data['savings_rate']:.1f}%",
                UI_EMERALD if data['savings_rate'] > 0 else UI_MUTED,
                "of logged income"),
            ("Health Score",   f"{health['score']:.0f} / 100",
                self._health_color(health['status']),
                health['status']),
        ]
        for label, value, color, sub in stats:
            row = tk.Frame(stats_frame, bg=UI_SURFACE)
            row.pack(fill="x", pady=1)
            tk.Frame(row, bg=color, width=3).pack(side="left", fill="y")
            text_f = tk.Frame(row, bg=UI_SURFACE, padx=SP_MD, pady=3)
            text_f.pack(side="left", fill="x", expand=True)
            head = tk.Frame(text_f, bg=UI_SURFACE)
            head.pack(fill="x")
            tk.Label(head, text=label.upper(), bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_CAPTION_BOLD).pack(side="left")
            tk.Label(head, text=value, bg=UI_SURFACE, fg=color,
                     font=FONT_SUBHEADING).pack(side="right")
            if sub:
                tk.Label(text_f, text=sub, bg=UI_SURFACE, fg=UI_MUTED,
                         font=FONT_CAPTION).pack(anchor="w")

        # Observation bullets
        observations = []
        if data["income_total"] > 0 and data["outgoing_total"] > 0:
            spend_share = (data["outgoing_total"] / data["income_total"]) * 100.0
            observations.append(f"Outgoing is {spend_share:.0f}% of income {scope_word}.")
        if data["savings_rate"] >= 20:
            observations.append("Savings rate is strong relative to logged income.")
        elif data["savings_rate"] <= 0:
            observations.append(f"No measurable savings rate {scope_word}. Log a pay + allocate.")
        if data["mix_distance"] > 0:
            observations.append(f"Mix distance from target: {data['mix_distance']:.1f}.")
        if pr > 0:
            observations.append("Pending reviews reduce month-end reliability.")
        if forecast["pressure_points"]:
            observations.append(forecast["pressure_points"][0])
        for line in health["insights"][:2]:
            observations.append(line)

        if observations:
            tk.Label(obs_frame, text="NOTES", bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_CAPTION_BOLD).pack(anchor="w", pady=(0, SP_XS))
            for obs in observations[:6]:
                row = tk.Frame(obs_frame, bg=UI_SURFACE2)
                row.pack(fill="x", pady=1)
                tk.Label(row, text="·", bg=UI_SURFACE2, fg=UI_ACCENT,
                         font=FONT_BODY_BOLD, padx=SP_SM).pack(side="left")
