    def _compute_review_nudges(self, rows: list) -> list:
        """Generate plain-language observations from the 6-month trend rows.

        Returns a list of (icon, text, color) tuples, ordered by salience.
        """
        if not rows or len(rows) < 2:
            return []

        nudges = []
        current = rows[-1]
        prev = rows[-2]
        _, _, cur_label, cur_inc, cur_out = current
        _, _, _, prev_inc, prev_out = prev

        # ── Month-over-month outgoing change
        if prev_out > 0:
            delta_pct = ((cur_out - prev_out) / prev_out) * 100
            if delta_pct >= 15:
                nudges.append(("▲", f"Outgoing up {delta_pct:.0f}% vs last month — "
                                      f"${cur_out - prev_out:,.0f} more than {rows[-2][2]}.",
                                UI_RUBY))
            elif delta_pct <= -15:
                nudges.append(("▼", f"Outgoing down {abs(delta_pct):.0f}% vs last month — "
                                      f"${prev_out - cur_out:,.0f} less than {rows[-2][2]}.",
                                UI_EMERALD))

        # ── Savings trend over last 3 months
        if len(rows) >= 3:
            tail = rows[-3:]
            nets = [r[3] - r[4] for r in tail]
            # All non-trivially positive and monotonically increasing → growth streak
            if all(n > 0 for n in nets) and nets[0] < nets[1] < nets[2]:
                nudges.append(("◆", f"Net savings grew 3 months in a row — "
                                      f"${nets[-1]:,.0f} banked in {cur_label}.",
                                UI_EMERALD))
            elif all(n < 0 for n in nets):
                nudges.append(("!", "3 straight months of net outflow. "
                                      "Review recurring spend or income cadence.",
                                UI_RUBY))

        # ── Current vs 3-month average
        if len(rows) >= 4 and cur_out > 0:
            avg_out = sum(r[4] for r in rows[-4:-1]) / 3 if sum(r[4] for r in rows[-4:-1]) > 0 else 0
            if avg_out > 0:
                vs_avg = ((cur_out - avg_out) / avg_out) * 100
                if vs_avg >= 20:
                    nudges.append(("▲", f"{cur_label} outgoing is {vs_avg:.0f}% above your "
                                          f"3-month average of ${avg_out:,.0f}.",
                                    UI_RUBY))
                elif vs_avg <= -20:
                    nudges.append(("▼", f"{cur_label} outgoing is {abs(vs_avg):.0f}% below your "
                                          f"3-month average — a lean month.",
                                    UI_EMERALD))

        # ── Best / worst month in window
        has_income = any(r[3] > 0 for r in rows)
        if has_income:
            best = max(rows, key=lambda r: r[3] - r[4])
            worst = min(rows, key=lambda r: r[3] - r[4])
            best_net = best[3] - best[4]
            worst_net = worst[3] - worst[4]
            if best[2] == cur_label and best_net > 0:
                nudges.append(("★", f"{cur_label} is your best savings month in the "
                                      f"window (+${best_net:,.0f} net).",
                                UI_GOLD))
            elif worst[2] == cur_label and worst_net < 0:
                nudges.append(("▽", f"{cur_label} is the weakest month in the window "
                                      f"(${worst_net:,.0f} net).",
                                UI_GOLD))

        # ── Income stability
        incs = [r[3] for r in rows if r[3] > 0]
        if len(incs) >= 3:
            avg_inc = sum(incs) / len(incs)
            if avg_inc > 0:
                spread = (max(incs) - min(incs)) / avg_inc
                if spread >= 0.4:
                    nudges.append(("≈", f"Income has varied by {spread * 100:.0f}% "
                                          "across months — plan for lean ones.",
                                    UI_SAPPHIRE))

        # ── No data fallback
        if not nudges:
            nudges.append(("·", "Log pays and commit transactions over multiple months "
                                  "to surface trend observations here.",
                            UI_MUTED))

        return nudges[:3]  # cap at 3 most-salient chips

    def _render_review_nudges(self, nudges: list):
        """Render nudge chips into the _review_nudges_frame."""
        frame = getattr(self, "_review_nudges_frame", None)
        if frame is None:
            return
        for w in frame.winfo_children():
            w.destroy()
        if not nudges:
            return
        for icon, text, color in nudges:
            glow = tk.Frame(frame, bg=color, padx=1, pady=1)
            glow.pack(fill="x", pady=2)
            inner = tk.Frame(glow, bg=UI_SURFACE2, padx=SP_SM, pady=4)
            inner.pack(fill="x")
            tk.Label(inner, text=icon, bg=UI_SURFACE2, fg=color,
                     font=FONT_BODY_BOLD, width=2).pack(side="left")
            tk.Label(inner, text=text, bg=UI_SURFACE2, fg=UI_TEXT,
                     font=FONT_SMALL, anchor="w", justify="left",
                     wraplength=900).pack(side="left", fill="x", expand=True)

    def _current_month_review_data(self, for_date: date = None, bounds: tuple = None) -> dict:
        if bounds is not None:
            start, end = bounds
        else:
            ref = for_date or date.today()
            start, end = month_bounds(ref)
        income_total = sum(x.amount for x in self.state.incomes if start <= x.received_on <= end)
        outgoing = [tx for tx in self.state.transactions if tx.direction() == "out" and tx.matched_type != "ignore" and start <= tx.tx_date <= end]
        outgoing_total = sum(tx.money_out for tx in outgoing)
        category_totals = outgoing_category_totals(self.state.transactions, start, end)
        actual_pct = percents_from_amounts(category_totals)

        target_map = {}
        for idx, label in enumerate(self.state.expense_target_order):
            if idx < len(self.state.expense_target_pct):
                target_map[label] = self.state.expense_target_pct[idx]

        mix_rows = []
        mix_distance = 0.0
        for label, target_pct in target_map.items():
            actual = actual_pct.get(label, 0.0)
            diff = actual - target_pct
            mix_distance += abs(diff)
            mix_rows.append((label, actual, target_pct, diff))
        mix_rows.sort(key=lambda x: abs(x[3]), reverse=True)

        merchant_totals: Dict[str, float] = {}
        merchant_counts: Dict[str, int] = {}
        for tx in outgoing:
            key = normalize_desc_text(tx.description)
            merchant_totals[key] = merchant_totals.get(key, 0.0) + tx.money_out
            merchant_counts[key] = merchant_counts.get(key, 0) + 1
        avg_tx = outgoing_total / len(outgoing) if outgoing else 0.0
        anomalies = []
        for name, total in merchant_totals.items():
            count = merchant_counts[name]
            if total >= max(120.0, avg_tx * 2.5) or count >= 4:
                anomalies.append((name, total, count))
        anomalies.sort(key=lambda x: (-x[1], -x[2], x[0]))

        verified = len([tx for tx in self.state.transactions if tx.user_verified])
        committed = len(self.state.transactions)
        pending_review = len([tx for tx in self.state.transactions if tx.needs_review and not tx.user_verified]) + len([tx for tx in self.latest_import if tx.needs_review and not tx.user_verified])

        savings_rate = 0.0
        if income_total > 0:
            savings_rate = ((self.state.last_reserved_total + self.state.last_fund_total + self.state.last_goal_total + self.state.last_invest_total) / income_total) * 100.0

        return {
            "start": start,
            "end": end,
            "income_total": income_total,
            "outgoing_total": outgoing_total,
            "actual_pct": actual_pct,
            "mix_rows": mix_rows,
            "mix_distance": mix_distance,
            "anomalies": anomalies,
            "verified": verified,
            "committed": committed,
            "pending_review": pending_review,
            "savings_rate": savings_rate,
            "outgoing_count": len(outgoing),
        }

    def _format_transaction_workflow_summary(self) -> str:
        preview_total = len(self.latest_import)
        verified_total = sum(1 for tx in self.latest_import if tx.user_verified)
        pending_outgoing = sum(1 for tx in self.latest_import if tx.direction() == "out" and not tx.user_verified)
        committed_total = len(self.state.transactions)
        parts = [
            f"Preview {preview_total}",
            f"Verified {verified_total}",
            f"Need review {pending_outgoing}",
            f"Committed {committed_total}",
        ]
        return "  •  ".join(parts)

    def _check_pay_overdue(self):
        """Return {last_date, expected_date, days_overdue, cycle_days, freq} when the
        next expected pay date has passed by more than the grace window, else None.
        Grace is roughly 25% of the cycle (2d weekly, 4d fortnightly, 7d monthly)."""
        if not self.state.incomes:
            return None
        last = max(self.state.incomes, key=lambda i: i.received_on)
        # Session-scoped dismissal: if user clicked Dismiss and no new pay has
        # been logged since, stay quiet until restart or next actual pay.
        dismissed = getattr(self, "_pay_overdue_dismissed_anchor", None)
        if dismissed is not None and dismissed == last.received_on:
            return None
        freq = self.state.pay_frequency
        cycle_days = self.engine.PAY_CYCLE_DAYS.get(freq, 14)
        grace = {"weekly": 2, "fortnightly": 4, "monthly": 7}.get(freq, 4)
        expected = last.received_on + timedelta(days=cycle_days)
        today = date.today()
        days_overdue = (today - expected).days
        if days_overdue <= grace:
            return None
        return {
            "last_date": last.received_on,
            "last_amount": last.amount,
            "expected_date": expected,
            "days_overdue": days_overdue,
            "cycle_days": cycle_days,
            "freq": freq,
        }

    def _build_today_get_started(self, parent):
        """Placed full-area overlay shown to users with no data yet.
        refresh_today_tab() toggles visibility and updates checkbox state."""
        overlay = tk.Frame(parent, bg=UI_BG)
        # Held hidden until refresh_today_tab decides to show
        self._today_get_started_overlay = overlay
        overlay.columnconfigure(0, weight=1)
        overlay.rowconfigure(0, weight=1)

        glow = tk.Frame(overlay, bg=UI_GOLD, padx=2, pady=2)
        glow.grid(row=0, column=0, padx=SP_XL, pady=SP_XL)
        card = tk.Frame(glow, bg=UI_SURFACE, padx=SP_XL * 2, pady=SP_XL)
        card.pack(fill="both", expand=True)

        tk.Label(card, text="👋 Welcome to Budget GUI",
                 bg=UI_SURFACE, fg=UI_TEXT,
                 font=FONT_DISPLAY_XL).pack(anchor="w")
        tk.Label(card,
                 text="Let's get you set up. Work through these in order — the app "
                      "comes alive once you log your first pay.",
                 bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_BODY, wraplength=640, justify="left").pack(
            anchor="w", pady=(SP_XS, SP_LG))

        steps_host = tk.Frame(card, bg=UI_SURFACE)
        steps_host.pack(fill="x")
        self._today_get_started_steps_host = steps_host

        # Close hint
        tk.Label(card,
                 text="This checklist will disappear once you've logged a pay "
                      "and added at least one bill.",
                 bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_MICRO, wraplength=640,
                 justify="left").pack(anchor="w", pady=(SP_LG, 0))

    def _render_today_get_started(self):
        """Decide whether to show the overlay, and repopulate step checkboxes."""
        overlay = getattr(self, "_today_get_started_overlay", None)
        host = getattr(self, "_today_get_started_steps_host", None)
        if overlay is None or host is None:
            return
        has_pay = bool(self.state.incomes)
        has_bill = bool(self.state.bills)
        has_savings = bool(self.state.funds) or bool(self.state.goals)
        has_import = bool(self.state.transactions) or bool(self.latest_import)

        # Auto-hide once the two mandatory steps are complete.
        if has_pay and has_bill:
            overlay.place_forget()
            return
        overlay.place(relx=0, rely=0, relwidth=1, relheight=1)
        overlay.lift()

        for w in host.winfo_children():
            w.destroy()

        steps = [
            ("Log your first pay",
             "Income tab → enter amount + date. Triggers allocation and starts your streak.",
             has_pay, "income"),
            ("Add your first bill",
             "Setup → Bills. Recurring expenses (rent, subs, utilities) auto-allocate per pay.",
             has_bill, "setup"),
            ("Add a savings goal or sinking fund",
             "Setup → Funds or Goals. Optional but unlocks the full progression loop.",
             has_savings, "setup"),
            ("Import a bank statement (optional)",
             "Transactions tab → Import PDF. Classifies spending so Analysis works.",
             has_import, "transactions"),
        ]
        for title, desc, done, target_tab in steps:
            row = tk.Frame(host, bg=UI_SURFACE, cursor="hand2")
            row.pack(fill="x", pady=SP_XS)
            mark = "✅" if done else "○"
            mark_color = UI_EMERALD if done else UI_MUTED
            title_color = UI_MUTED if done else UI_TEXT
            tk.Label(row, text=mark, bg=UI_SURFACE, fg=mark_color,
                     font=FONT_DISPLAY_MD).pack(side="left", padx=(0, SP_MD))
            text_box = tk.Frame(row, bg=UI_SURFACE)
            text_box.pack(side="left", fill="x", expand=True)
            tk.Label(text_box, text=title, bg=UI_SURFACE, fg=title_color,
                     font=FONT_BODY_BOLD, anchor="w").pack(anchor="w", fill="x")
            tk.Label(text_box, text=desc, bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_SMALL, anchor="w",
                     wraplength=540, justify="left").pack(anchor="w", fill="x")
            if not done:
                ttk.Button(row, text="Go →",
                           style="Primary.TButton" if target_tab == "income" else "Secondary.TButton",
                           command=lambda t=target_tab: self._show_page(t)).pack(side="right")
            for widget in (row, text_box):
                widget.bind("<Button-1>",
                             lambda _e, t=target_tab, d=done: None if d else self._show_page(t))

    def _render_pay_overdue_nudge(self):
        host = getattr(self, "_pay_overdue_host", None)
        if host is None:
            return
        for w in host.winfo_children():
            w.destroy()
        info = self._check_pay_overdue()
        if not info:
            host.pack_forget()
            return
        host.pack(fill="x", pady=(SP_SM, 0))
        tk.Label(host, text="PAY SEEMS OVERDUE",
                 bg=UI_SURFACE, fg=UI_RUBY,
                 font=FONT_CAPTION_BOLD).pack(anchor="w", pady=(SP_SM, SP_XS))
        glow = tk.Frame(host, bg=UI_RUBY, padx=1, pady=1)
        glow.pack(fill="x", pady=(0, SP_SM))
        card = tk.Frame(glow, bg=UI_SURFACE2, padx=SP_MD, pady=SP_MD)
        card.pack(fill="x")
        tk.Frame(card, bg=UI_RUBY, height=2).pack(fill="x", pady=(0, SP_SM))
        row = tk.Frame(card, bg=UI_SURFACE2)
        row.pack(fill="x")
        left = tk.Frame(row, bg=UI_SURFACE2)
        left.pack(side="left", fill="x", expand=True)
        days = info["days_overdue"]
        headline = (f"Last pay was ${info['last_amount']:,.2f} on "
                    f"{info['last_date'].strftime('%d %b')} — expecting {info['freq']} pay.")
        tk.Label(left, text=headline, bg=UI_SURFACE2, fg=UI_TEXT_BRIGHT,
                 font=FONT_BODY, anchor="w", justify="left",
                 wraplength=560).pack(anchor="w")
        sub = (f"Next pay expected by {info['expected_date'].strftime('%d %b')} "
               f"— {days} day{'s' if days != 1 else ''} past due. "
               "If you were paid, log it so your plan stays accurate.")
        tk.Label(left, text=sub, bg=UI_SURFACE2, fg=UI_MUTED,
                 font=FONT_CAPTION, anchor="w", justify="left",
                 wraplength=560).pack(anchor="w", pady=(2, 0))
        btns = tk.Frame(row, bg=UI_SURFACE2)
        btns.pack(side="right")
        ttk.Button(btns, text="Log Pay", style="Primary.TButton",
                   command=lambda: self._show_page("income")).pack(side="left")
        ttk.Button(btns, text="Dismiss", style="Ghost.TButton",
                   command=self._dismiss_pay_overdue).pack(side="left", padx=(SP_SM, 0))

    def _dismiss_pay_overdue(self):
        """Hide the nudge until the next expected pay cycle. Sets a flag on the
        most recent income so we don't keep renudging within the same cycle."""
        if not self.state.incomes:
            return
        last = max(self.state.incomes, key=lambda i: i.received_on)
        # Bump the received_on forward by one cycle to suppress the nudge until
        # the next expected date. Purely a UX suppression — income history stays
        # in the incomes list, but we record dismissal by bumping the reference
        # point on a transient attribute.
        self._pay_overdue_dismissed_anchor = last.received_on
        host = getattr(self, "_pay_overdue_host", None)
        if host is not None:
            for w in host.winfo_children():
                w.destroy()
            host.pack_forget()

    def _render_income_confirmations(self):
        host = getattr(self, "_confirm_income_host", None)
        if host is None:
            return
        for w in host.winfo_children():
            w.destroy()
        fps = list(self.state.pending_income_confirmations)
        by_fp = {t.fingerprint: t for t in self.state.transactions if t.fingerprint}
        stale = [fp for fp in fps if fp not in by_fp]
        if stale:
            self.state.pending_income_confirmations = [fp for fp in fps if fp not in stale]
            fps = list(self.state.pending_income_confirmations)
        if not fps:
            host.pack_forget()
            return
        host.pack(fill="x", pady=(SP_SM, 0))
        tk.Label(host, text="PAY DETECTED FROM IMPORT",
                 bg=UI_SURFACE, fg=UI_GOLD,
                 font=FONT_CAPTION_BOLD).pack(anchor="w", pady=(SP_SM, SP_XS))
        for fp in fps:
            tx = by_fp.get(fp)
            if tx is None:
                continue
            self._build_income_confirm_card(host, tx, fp)

    def _build_income_confirm_card(self, parent, tx, fp):
        glow = tk.Frame(parent, bg=UI_GOLD, padx=1, pady=1)
        glow.pack(fill="x", pady=(0, SP_SM))
        card = tk.Frame(glow, bg=UI_SURFACE2, padx=SP_MD, pady=SP_MD)
        card.pack(fill="x")
        tk.Frame(card, bg=UI_GOLD, height=2).pack(fill="x", pady=(0, SP_SM))
        row = tk.Frame(card, bg=UI_SURFACE2)
        row.pack(fill="x")
        left = tk.Frame(row, bg=UI_SURFACE2)
        left.pack(side="left", fill="x", expand=True)
        tk.Label(left, text=f"+${tx.money_in:,.2f}  on  {tx.tx_date.strftime('%d %b %Y')}",
                 bg=UI_SURFACE2, fg=UI_TEXT_BRIGHT,
                 font=FONT_DISPLAY_SM, anchor="w").pack(anchor="w")
        desc = tx.description or "(no description)"
        if len(desc) > 90:
            desc = desc[:87] + "…"
        tk.Label(left, text=desc, bg=UI_SURFACE2, fg=UI_MUTED,
                 font=FONT_CAPTION, anchor="w", justify="left",
                 wraplength=520).pack(anchor="w", pady=(2, 0))
        btns = tk.Frame(row, bg=UI_SURFACE2)
        btns.pack(side="right")
        ttk.Button(btns, text="Log as pay", style="Primary.TButton",
                   command=lambda f=fp: self._confirm_income_log(f)).pack(side="left")
        ttk.Button(btns, text="Dismiss", style="Ghost.TButton",
                   command=lambda f=fp: self._confirm_income_dismiss(f)).pack(side="left", padx=(SP_SM, 0))

    def _confirm_income_log(self, fp: str):
        tx = next((t for t in self.state.transactions if t.fingerprint == fp), None)
        if tx is None:
            self._confirm_income_dismiss(fp)
            return
        if fp in self.state.pending_income_confirmations:
            self.state.pending_income_confirmations.remove(fp)
        source = (tx.description or "Imported income").strip()
        if len(source) > 60:
            source = source[:57] + "…"
        self._log_pay_and_allocate(float(tx.money_in), tx.tx_date, source)

    def _confirm_income_dismiss(self, fp: str):
        if fp in self.state.pending_income_confirmations:
            self.state.pending_income_confirmations.remove(fp)
        self.save_state()
        self.refresh_today_tab()

    def _on_today_due_select(self, _event=None):
        self._refresh_today_due_action_state()

    def _refresh_today_due_action_state(self):
        btn = getattr(self, "_today_due_action_btn", None)
        hint = getattr(self, "_today_due_action_hint", None)
        if btn is None or hint is None:
            return
        sel = self.today_due_tree.selection()
        if not sel:
            btn.configure(state="disabled")
            hint.configure(text="Select a bill to mark it paid")
            return
        entry = self._today_due_row_map.get(sel[0])
        if entry and entry[0] == "bill":
            bill = self.state.bills[entry[1]]
            btn.configure(state="normal")
            hint.configure(text=f"{bill.name} — ${bill.amount:,.2f}")
        else:
            btn.configure(state="disabled")
            if entry:
                hint.configure(text="Only bills can be marked paid (funds/goals track progress)")
            else:
                hint.configure(text="Select a bill to mark it paid")

    def _on_today_due_double_click(self, _event=None):
        sel = self.today_due_tree.selection()
        if not sel:
            return
        entry = self._today_due_row_map.get(sel[0])
        if entry and entry[0] == "bill":
            self._mark_selected_today_due_paid()

    def _mark_selected_today_due_paid(self):
        sel = self.today_due_tree.selection()
        if not sel:
            return
        entry = self._today_due_row_map.get(sel[0])
        if not entry or entry[0] != "bill":
            return
        bill = self.state.bills[entry[1]]
        if not messagebox.askyesno("Mark Paid",
                                    f"Mark '{bill.name}' (${bill.amount:,.2f}) as paid?"):
            return
        self._mark_bill_paid_with_undo(bill)

    def _tween_number(self, var: tk.StringVar, target: float,
                        formatter, duration_ms: int = 400,
                        step_ms: int = 25, key: str = ""):
        """Animate the given StringVar from its current displayed value to
        target over duration_ms, formatting each frame via formatter(value).
        Repeated calls with the same key cancel the previous tween.
        """
        if not hasattr(self, "_tween_jobs"):
            self._tween_jobs = {}
        job_key = key or id(var)
        prev_job = self._tween_jobs.get(job_key)
        if prev_job is not None:
            try:
                self.after_cancel(prev_job)
            except Exception:
                pass
            self._tween_jobs[job_key] = None
        # Parse current displayed number from the var's string
        current_text = var.get()
        import re as _re
        m = _re.search(r"-?[0-9][0-9,]*\.?[0-9]*", current_text.replace(",", ""))
        start_val = 0.0
        if m:
            try:
                start_val = float(m.group(0))
            except ValueError:
                start_val = 0.0
        if abs(target - start_val) < 0.01:
            var.set(formatter(target))
            return
        frames = max(1, int(duration_ms / step_ms))
        def _step(i=0):
            if i >= frames:
                var.set(formatter(target))
                self._tween_jobs[job_key] = None
                return
            # ease-out cubic: 1 - (1-t)^3
            t = (i + 1) / frames
            eased = 1 - (1 - t) ** 3
            val = start_val + (target - start_val) * eased
            var.set(formatter(val))
            self._tween_jobs[job_key] = self.after(step_ms, lambda: _step(i + 1))
        _step(0)

    def _draw_gauge(self, canvas, value: float, max_value: float = 100.0,
                     label: str = "", sublabel: str = ""):
        """Render a semicircular health-gauge into the given canvas.

        Color ramps: red <50 → gold 50-74 → emerald >=75. Value clamped to
        [0, max_value]. Designed for compact reuse; canvas bg should already
        match the host panel.
        """
        if canvas is None:
            return
        canvas.delete("all")
        try:
            canvas.update_idletasks()
        except tk.TclError:
            return
        w = max(int(canvas.winfo_width() or 0), 120)
        h = max(int(canvas.winfo_height() or 0), 70)
        v = max(0.0, min(float(value), float(max_value)))
        pct = v / max_value if max_value > 0 else 0.0
        color = (UI_EMERALD if pct >= 0.75
                 else UI_GOLD if pct >= 0.5
                 else UI_RUBY)
        # Gauge geometry — a half-circle centered at bottom
        pad = 8
        diameter = min(w - 2 * pad, (h - pad) * 2)
        cx = w // 2
        # bottom of the arc sits near canvas bottom so labels fit below
        bottom_margin = 18
        cy = h - bottom_margin
        r = diameter // 2
        x1, y1 = cx - r, cy - r
        x2, y2 = cx + r, cy + r
        # Track (full 180°) and value arc
        canvas.create_arc(x1, y1, x2, y2, start=0, extent=180,
                           style="arc", outline=UI_BORDER, width=10)
        if v > 0:
            canvas.create_arc(x1, y1, x2, y2, start=180, extent=-180 * pct,
                               style="arc", outline=color, width=10)
        # Center number
        canvas.create_text(cx, cy - r // 2 - 4, text=f"{v:.0f}",
                           fill=color, font=FONT_HEADING)
        if label:
            canvas.create_text(cx, cy - r // 2 + 16, text=label,
                               fill=UI_MUTED, font=FONT_MICRO)
        if sublabel:
            canvas.create_text(cx, cy + 6, text=sublabel,
                               fill=UI_TEXT, font=FONT_SMALL)

    def _draw_sparkline(self, canvas, values, color: str, *,
                        fill_alpha_hex: str = None, show_dots: bool = True,
                        kind: str = "line"):
        """Render a mini line (or bar) chart in the given canvas.

        values: oldest -> newest. Empty list renders a hint message.
        kind: "line" (default) or "bar".
        """
        if canvas is None:
            return
        canvas.delete("all")
        try:
            canvas.update_idletasks()
        except tk.TclError:
            return
        w = max(int(canvas.winfo_width() or 0), 120)
        h = max(int(canvas.winfo_height() or 0), 30)
        pad_x, pad_y = 4, 4
        inner_w = w - 2 * pad_x
        inner_h = h - 2 * pad_y
        # Baseline grid line
        canvas.create_line(pad_x, h - pad_y, w - pad_x, h - pad_y,
                           fill=UI_BORDER, width=1)
        if not values:
            canvas.create_text(w // 2, h // 2, text="not enough history yet",
                               fill=UI_MUTED, font=FONT_MICRO)
            return
        vmax = max(values)
        vmin = min(values)
        span = (vmax - vmin) if vmax > vmin else max(vmax, 1.0)
        n = len(values)
        if n == 1:
            cx = pad_x + inner_w // 2
            cy = pad_y + inner_h // 2
            canvas.create_oval(cx - 3, cy - 3, cx + 3, cy + 3,
                               fill=color, outline="")
            canvas.create_text(w - pad_x, pad_y,
                               text=f"${values[0]:,.0f}", anchor="ne",
                               fill=UI_MUTED, font=FONT_MICRO)
            return
        step = inner_w / max(n - 1, 1)
        pts = []
        for i, v in enumerate(values):
            x = pad_x + i * step
            frac = (v - vmin) / span if span > 0 else 0.5
            y = pad_y + inner_h - frac * inner_h
            pts.append((x, y))

        if kind == "bar":
            bar_w = max(4, int(step * 0.55))
            for (x, y) in pts:
                canvas.create_rectangle(x - bar_w / 2, y, x + bar_w / 2, h - pad_y,
                                         fill=color, outline="")
        else:
            flat = [c for xy in pts for c in xy]
            canvas.create_line(*flat, fill=color, width=2, smooth=False)
            if show_dots:
                lx, ly = pts[-1]
                canvas.create_oval(lx - 3, ly - 3, lx + 3, ly + 3,
                                   fill=color, outline="")
        # Delta label (top-right)
        first, last = values[0], values[-1]
        delta = last - first
        arrow = "▲" if delta > 0 else "▼" if delta < 0 else "→"
        d_color = UI_EMERALD if delta > 0 else UI_RUBY if delta < 0 else UI_MUTED
        canvas.create_text(w - pad_x, pad_y,
                           text=f"{arrow} ${abs(delta):,.0f}", anchor="ne",
                           fill=d_color, font=FONT_MICRO)

    def _redraw_hero_sparklines(self):
        # Safe-to-Spend → last 8 pay amounts (oldest → newest)
        pays = sorted(self.state.incomes, key=lambda x: x.received_on)
        pay_vals = [i.amount for i in pays[-8:]]
        self._draw_sparkline(self._safe_sparkline_canvas, pay_vals, UI_EMERALD)
        # Daily Pace → outgoing totals per week for last 8 weeks
        weekly = {i: 0.0 for i in range(8)}
        today = date.today()
        for tx in self.state.transactions:
            try:
                if tx.direction() != "out" or tx.matched_type == "ignore":
                    continue
            except Exception:
                continue
            delta = (today - tx.tx_date).days
            if delta < 0 or delta > 55:
                continue
            wk = delta // 7
            if wk in weekly:
                weekly[wk] += tx.money_out
        pace_vals = [weekly[i] for i in range(7, -1, -1)]
        if any(v > 0 for v in pace_vals):
            self._draw_sparkline(self._pace_sparkline_canvas, pace_vals,
                                  UI_SAPPHIRE, kind="bar")
        else:
            self._draw_sparkline(self._pace_sparkline_canvas, [],
                                  UI_SAPPHIRE, kind="bar")

    def _bind_tree_context_menus(self):
        """Wire right-click context menus onto the main row-based trees."""
        def _bind(tree, items_builder):
            if tree is None:
                return
            def _open(event):
                iid = tree.identify_row(event.y)
                if iid:
                    try:
                        tree.selection_set(iid)
                    except tk.TclError:
                        pass
                menu_items = items_builder(iid) if iid else None
                if not menu_items:
                    return
                menu = tk.Menu(self, tearoff=0, bg=UI_SURFACE, fg=UI_TEXT,
                               activebackground=UI_ACCENT, activeforeground="#ffffff",
                               bd=0)
                for entry in menu_items:
                    if entry is None:
                        menu.add_separator()
                    else:
                        label, cb = entry
                        menu.add_command(label=label, command=cb)
                try:
                    menu.tk_popup(event.x_root, event.y_root)
                finally:
                    menu.grab_release()
            tree.bind("<Button-3>", _open)

        def _bill_menu(iid):
            try:
                idx = int(iid)
                bill = self.state.bills[idx]
            except (ValueError, IndexError):
                return None
            return [
                (f"Mark '{bill.name}' paid", lambda b=bill: self._mark_bill_paid_with_undo(b)),
                None,
                ("Edit in form", lambda i=iid: (self.bill_tree.selection_set(i), self.on_bill_select())),
                (f"Contribute to {bill.name}…",
                 lambda i=idx: self._contribute_to_target("bill", i)),
                None,
                ("Delete", lambda i=iid: (self.bill_tree.selection_set(i), self.delete_selected_bill())),
            ]

        def _fund_menu(iid):
            try:
                idx = int(iid)
                fund = self.state.funds[idx]
            except (ValueError, IndexError):
                return None
            return [
                (f"Contribute to {fund.name}…",
                 lambda i=idx: self._contribute_to_target("fund", i)),
                None,
                ("Edit in form", lambda i=iid: (self.fund_tree.selection_set(i), self.on_fund_select())),
                ("Delete", lambda i=iid: (self.fund_tree.selection_set(i), self.delete_selected_fund())),
            ]

        def _goal_menu(iid):
            try:
                idx = int(iid)
                goal = self.state.goals[idx]
            except (ValueError, IndexError):
                return None
            return [
                (f"Contribute to {goal.name}…",
                 lambda i=idx: self._contribute_to_target("goal", i)),
                None,
                ("Edit in form", lambda i=iid: (self.goal_tree.selection_set(i), self.on_goal_select())),
                ("Delete", lambda i=iid: (self.goal_tree.selection_set(i), self.delete_selected_goal())),
            ]

        def _today_due_menu(iid):
            entry = getattr(self, "_today_due_row_map", {}).get(iid)
            if not entry:
                return None
            kind, idx = entry
            if kind == "bill":
                try:
                    bill = self.state.bills[idx]
                except IndexError:
                    return None
                return [
                    (f"Mark '{bill.name}' paid", lambda b=bill: self._mark_bill_paid_with_undo(b)),
                    None,
                    (f"Contribute to {bill.name}…",
                     lambda i=idx: self._contribute_to_target("bill", i)),
                    ("Open in Setup", lambda: (self._show_page("setup"), self._show_setup_sub("bills"))),
                ]
            elif kind == "fund":
                try:
                    fund = self.state.funds[idx]
                except IndexError:
                    return None
                return [
                    (f"Contribute to {fund.name}…",
                     lambda i=idx: self._contribute_to_target("fund", i)),
                    ("Open in Setup", lambda: (self._show_page("setup"), self._show_setup_sub("funds"))),
                ]
            elif kind == "goal":
                try:
                    goal = self.state.goals[idx]
                except IndexError:
                    return None
                return [
                    (f"Contribute to {goal.name}…",
                     lambda i=idx: self._contribute_to_target("goal", i)),
                    ("Open in Setup", lambda: (self._show_page("setup"), self._show_setup_sub("goals"))),
                ]
            return None

        _bind(getattr(self, "bill_tree", None), _bill_menu)
        _bind(getattr(self, "fund_tree", None), _fund_menu)
        _bind(getattr(self, "goal_tree", None), _goal_menu)
        _bind(getattr(self, "today_due_tree", None), _today_due_menu)

    def _contribute_to_target(self, kind: str, idx: int):
        """Prompt for an amount and add it to the target's current_saved (undoable)."""
        if kind == "bill":
            obj = self.state.bills[idx]
            cap = obj.amount
            name = obj.name
        elif kind == "fund":
            obj = self.state.funds[idx]
            cap = obj.target_amount
            name = obj.name
        elif kind == "goal":
            obj = self.state.goals[idx]
            cap = obj.target_amount
            name = obj.name
        else:
            return
        from tkinter import simpledialog
        amt = simpledialog.askfloat(
            "Contribute",
            f"Add how much to '{name}'?\n"
            f"Currently saved: ${obj.current_saved:,.2f}"
            + (f"  /  target ${cap:,.2f}" if cap else ""),
            parent=self, minvalue=0.01)
        if not amt:
            return
        prev = obj.current_saved
        obj.current_saved = prev + amt
        if kind == "bill":
            self.refresh_bills()
        elif kind == "fund":
            self.refresh_funds()
        else:
            self.refresh_goals()
        self.refresh_today_tab()
        self.save_state()

        def _undo():
            obj.current_saved = prev
            if kind == "bill":
                self.refresh_bills()
            elif kind == "fund":
                self.refresh_funds()
            else:
                self.refresh_goals()
            self.refresh_today_tab()
            self.save_state()
            self._show_toast(f"{name} contribution reverted.", "info", 2500)

        self._show_toast(f"Added ${amt:,.2f} to {name}.", "success",
                         duration=6000, action_label="Undo", action_cb=_undo)

    def _mark_bill_paid_with_undo(self, bill):
        prev_saved = bill.current_saved
        prev_due = bill.due_date
        self.engine.mark_bill_paid(bill)
        self.refresh_bills()
        self.refresh_today_tab()
        self.save_state()

        def _undo():
            bill.current_saved = prev_saved
            bill.due_date = prev_due
            self.refresh_bills()
            self.refresh_today_tab()
            self.save_state()
            self._show_toast(f"{bill.name} restored.", "info", 2500)

        self._show_toast(f"{bill.name} marked paid.", "success",
                         duration=6000, action_label="Undo", action_cb=_undo)

    def _copy_amount_to_clipboard(self, amount: float, label: str):
        """Copy a numeric amount (no $, no commas) to the clipboard and
        confirm via toast. Format matches what most banking apps expect."""
        text = f"{amount:.2f}"
        try:
            self.clipboard_clear()
            self.clipboard_append(text)
        except tk.TclError:
            self._show_toast("Couldn't copy to clipboard", "error")
            return
        self._show_toast(f"Copied ${amount:,.2f}  —  {label}", "success", 2000)

    def _render_alloc_action_cards(self, a: dict,
                                    bills_acct: str, savings_acct: str,
                                    invest_acct: str, spending_acct: str):
        """Populate the quick-copy transfer action row above the plan."""
        parent = self._alloc_actions_frame
        for w in parent.winfo_children():
            w.destroy()

        steps = []
        if a["bill_total"] > 0:
            steps.append(("Bills", a["bill_total"], bills_acct, UI_RUBY))
        savings_total = a["fund_total"] + a["goal_total"]
        if savings_total > 0:
            steps.append(("Savings", savings_total, savings_acct, UI_EMERALD))
        if a["invest_total"] > 0:
            steps.append(("Invest", a["invest_total"], invest_acct, UI_AMETHYST))
        if a["safe_to_spend"] > 0:
            steps.append(("Keep", a["safe_to_spend"], spending_acct, UI_SAPPHIRE))

        if not steps:
            return

        header = tk.Frame(parent, bg=UI_SURFACE)
        header.pack(fill="x")
        tk.Label(header, text="QUICK-COPY TRANSFERS", bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_MICRO).pack(anchor="w", padx=(2, 0), pady=(0, 2))

        grid = tk.Frame(parent, bg=UI_SURFACE)
        grid.pack(fill="x")
        cols = min(4, len(steps))
        for idx in range(cols):
            grid.columnconfigure(idx, weight=1, uniform="alloc_cards")

        for idx, (label, amount, acct, color) in enumerate(steps):
            r, c = divmod(idx, cols)
            glow = tk.Frame(grid, bg=color, padx=1, pady=1)
            glow.grid(row=r, column=c, sticky="nsew", padx=2, pady=2)
            card = tk.Frame(glow, bg=UI_SURFACE2, padx=SP_SM, pady=SP_SM)
            card.pack(fill="both", expand=True)
            tk.Frame(card, bg=color, height=2).pack(fill="x", pady=(0, 4))
            tk.Label(card, text=label.upper(), bg=UI_SURFACE2, fg=color,
                     font=FONT_CAPTION_BOLD).pack(anchor="w")
            tk.Label(card, text=f"${amount:,.2f}", bg=UI_SURFACE2, fg=UI_TEXT,
                     font=FONT_SUBHEADING).pack(anchor="w")
            tk.Label(card, text=f"→ {acct}", bg=UI_SURFACE2, fg=UI_MUTED,
                     font=FONT_MICRO, wraplength=140, justify="left").pack(anchor="w", pady=(0, 4))
            btn = tk.Button(card, text="📋 Copy amount", bg=UI_SURFACE, fg=UI_TEXT,
                            font=FONT_CAPTION, relief="flat", cursor="hand2",
                            activebackground=color, activeforeground="#ffffff",
                            padx=SP_SM, pady=2,
                            command=lambda amt=amount, lbl=f"{label} → {acct}":
                                self._copy_amount_to_clipboard(amt, lbl))
            btn.pack(fill="x")

    def _render_allocation_plan_cards(self, a: dict, pace: dict, health: dict,
                                       forecast: dict, days_in_cycle: int, cycle: str,
                                       bills_acct: str, savings_acct: str,
                                       invest_acct: str, spending_acct: str):
        """Render the step-by-step transfer plan as visual cards."""
        parent = self._alloc_plan_frame
        for w in parent.winfo_children():
            w.destroy()
        parent.columnconfigure(0, weight=1)

        if not a:
            # Empty state
            empty = tk.Frame(parent, bg=UI_SURFACE2, padx=SP_LG, pady=SP_LG)
            empty.grid(row=0, column=0, sticky="ew", pady=SP_SM)
            tk.Label(empty, text="YOUR TRANSFER PLAN APPEARS HERE", bg=UI_SURFACE2,
                     fg=UI_MUTED, font=FONT_CAPTION_BOLD).pack(anchor="w")
            tk.Label(empty, text="After you log a pay on the Income tab, this panel "
                                 "shows exactly how to split your money across your bank accounts.",
                     bg=UI_SURFACE2, fg=UI_TEXT, font=FONT_SMALL, wraplength=520,
                     justify="left").pack(anchor="w", pady=(SP_SM, SP_SM))
            for step_text in ("1. Setup → Accounts: name your bank accounts",
                               "2. Log Pay: enter your pay amount",
                               "3. Follow the step-by-step plan that appears here",
                               "4. Open your bank app and make the transfers"):
                tk.Label(empty, text=step_text, bg=UI_SURFACE2, fg=UI_TEXT,
                         font=FONT_SMALL).pack(anchor="w")
            return

        # Header: pay + cycle
        header = tk.Frame(parent, bg=UI_SURFACE)
        header.grid(row=0, column=0, sticky="ew", pady=(0, SP_SM))
        tk.Label(header, text="PAY RECEIVED", bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_MICRO).pack(anchor="w")
        tk.Label(header, text=f"${a['pay_amount']:,.2f}", bg=UI_SURFACE, fg=UI_GOLD,
                 font=FONT_HEADING).pack(anchor="w")
        tk.Label(header, text=f"{cycle.title()} cycle  •  Next {days_in_cycle} days",
                 bg=UI_SURFACE, fg=UI_MUTED, font=FONT_SMALL).pack(anchor="w", pady=(0, SP_SM))

        # Build step list
        steps = []
        step_no = 1
        if a["bill_total"] > 0:
            bill_items = [(n, x) for _i, n, x, _r in a.get("bill_breakdown", []) if x > 0]
            steps.append({"num": step_no, "title": "Bills", "amount": a["bill_total"],
                          "dest": bills_acct, "color": UI_RUBY, "items": bill_items,
                          "verb": "Transfer"})
            step_no += 1
        savings_total = a["fund_total"] + a["goal_total"]
        if savings_total > 0:
            sav_items = [(f"Fund: {n}", x) for _i, n, x, _r in a.get("fund_breakdown", []) if x > 0]
            sav_items += [(f"Goal: {n}", x) for _i, n, x, _r in a.get("goal_breakdown", []) if x > 0]
            steps.append({"num": step_no, "title": "Savings", "amount": savings_total,
                          "dest": savings_acct, "color": UI_EMERALD, "items": sav_items,
                          "verb": "Transfer"})
            step_no += 1
        if a["invest_total"] > 0:
            steps.append({"num": step_no, "title": "Invest", "amount": a["invest_total"],
                          "dest": invest_acct, "color": UI_AMETHYST, "items": [],
                          "verb": "Transfer"})
            step_no += 1
        steps.append({"num": step_no, "title": "Keep (Safe to Spend)",
                      "amount": a["safe_to_spend"], "dest": spending_acct,
                      "color": UI_SAPPHIRE, "items": [], "verb": "Leave"})

        # Steps stack
        stack = tk.Frame(parent, bg=UI_SURFACE)
        stack.grid(row=1, column=0, sticky="ew")
        stack.columnconfigure(0, weight=1)
        for i, step in enumerate(steps):
            self._alloc_step_card(stack, step).grid(row=i, column=0, sticky="ew", pady=2)

        # Summary card — gauge on left, numeric facts on right
        summary = tk.Frame(parent, bg=UI_SURFACE2, padx=SP_MD, pady=SP_SM)
        summary.grid(row=2, column=0, sticky="ew", pady=(SP_SM, 0))
        summary.columnconfigure(1, weight=1)
        tk.Label(summary, text="SUMMARY", bg=UI_SURFACE2, fg=UI_MUTED,
                 font=FONT_MICRO).grid(row=0, column=0, columnspan=2, sticky="w")
        gauge_canvas = tk.Canvas(summary, bg=UI_SURFACE2, width=130, height=78,
                                  bd=0, highlightthickness=0)
        gauge_canvas.grid(row=1, column=0, sticky="w", padx=(0, SP_MD))
        self._draw_gauge(gauge_canvas, health["score"], 100.0,
                          label="HEALTH", sublabel=health["status"])
        facts = tk.Frame(summary, bg=UI_SURFACE2)
        facts.grid(row=1, column=1, sticky="nsew")
        if pace["safe_per_day"] > 0:
            tk.Label(facts, text=f"Daily budget  ${pace['safe_per_day']:,.2f} / day",
                     bg=UI_SURFACE2, fg=UI_TEXT, font=FONT_SMALL).pack(anchor="w")
        if forecast["windows"]:
            tk.Label(facts,
                     text=f"30-day projection  ${forecast['windows'][0]['projected_end_balance']:,.2f}",
                     bg=UI_SURFACE2, fg=UI_TEXT, font=FONT_SMALL).pack(anchor="w")

        # Alerts card
        all_warnings = list(a.get("warnings", []))
        if forecast["pressure_points"]:
            all_warnings.append(forecast["pressure_points"][0])
        if all_warnings:
            alerts_glow = tk.Frame(parent, bg=UI_GOLD, padx=1, pady=1)
            alerts_glow.grid(row=3, column=0, sticky="ew", pady=(SP_SM, 0))
            alerts = tk.Frame(alerts_glow, bg=UI_SURFACE2, padx=SP_MD, pady=SP_SM)
            alerts.pack(fill="x")
            tk.Label(alerts, text="⚠  ALERTS", bg=UI_SURFACE2, fg=UI_GOLD,
                     font=FONT_CAPTION_BOLD).pack(anchor="w")
            for w in all_warnings:
                tk.Label(alerts, text=f"• {w}", bg=UI_SURFACE2, fg=UI_TEXT,
                         font=FONT_SMALL, wraplength=520, justify="left").pack(anchor="w")

        # Footer note
        tk.Label(parent,
                 text="Open your bank app and make these transfers now. "
                      "Import your statement next month to score accuracy.",
                 bg=UI_SURFACE, fg=UI_MUTED, font=FONT_MICRO,
                 wraplength=560, justify="left").grid(row=4, column=0, sticky="w",
                                                       pady=(SP_SM, 0))

    def _alloc_step_card(self, parent, step: dict):
        """Build one step card (glow-bordered, with badge, amount, dest, items)."""
        color = step["color"]
        glow = tk.Frame(parent, bg=color, padx=1, pady=1)
        inner = tk.Frame(glow, bg=UI_SURFACE2)
        inner.pack(fill="both", expand=True)
        inner.columnconfigure(1, weight=1)

        # Left badge column (step number)
        badge = tk.Frame(inner, bg=color, width=44, padx=SP_SM, pady=SP_SM)
        badge.grid(row=0, column=0, rowspan=2, sticky="ns")
        badge.pack_propagate(False)
        tk.Label(badge, text=str(step["num"]), bg=color, fg="#ffffff",
                 font=FONT_HEADING).pack(expand=True)

        # Main content
        content = tk.Frame(inner, bg=UI_SURFACE2, padx=SP_MD, pady=SP_SM)
        content.grid(row=0, column=1, sticky="ew")
        content.columnconfigure(0, weight=1)

        top = tk.Frame(content, bg=UI_SURFACE2)
        top.grid(row=0, column=0, sticky="ew")
        top.columnconfigure(1, weight=1)
        tk.Label(top, text=step["title"].upper(), bg=UI_SURFACE2, fg=color,
                 font=FONT_CAPTION_BOLD).grid(row=0, column=0, sticky="w")
        tk.Label(top, text=f"${step['amount']:,.2f}", bg=UI_SURFACE2, fg=UI_TEXT,
                 font=FONT_HEADING).grid(row=1, column=0, sticky="w")

        # Destination pill + copy button on right
        right = tk.Frame(top, bg=UI_SURFACE2)
        right.grid(row=0, column=1, rowspan=2, sticky="e")
        pill = tk.Frame(right, bg=UI_SURFACE, padx=SP_SM, pady=2)
        pill.pack(side="top", anchor="e")
        tk.Label(pill, text=f"{step['verb']} →  {step['dest']}",
                 bg=UI_SURFACE, fg=UI_TEXT, font=FONT_SMALL).pack()
        lbl = f"{step['title']} → {step['dest']}"
        amt = step["amount"]
        tk.Button(right, text="📋 Copy", bg=UI_SURFACE, fg=UI_TEXT,
                  font=FONT_CAPTION, relief="flat", cursor="hand2",
                  activebackground=color, activeforeground="#ffffff",
                  padx=SP_SM, pady=2,
                  command=lambda a=amt, l=lbl: self._copy_amount_to_clipboard(a, l)).pack(
            side="top", anchor="e", pady=(2, 0))

        # Items breakdown (optional)
        if step.get("items"):
            items_frame = tk.Frame(content, bg=UI_SURFACE2)
            items_frame.grid(row=1, column=0, sticky="ew", pady=(SP_SM, 0))
            tk.Label(items_frame, text="Includes:", bg=UI_SURFACE2, fg=UI_MUTED,
                     font=FONT_MICRO).pack(anchor="w")
            for name, amt in step["items"]:
                row = tk.Frame(items_frame, bg=UI_SURFACE2)
                row.pack(fill="x")
                tk.Label(row, text=f"  • {name}", bg=UI_SURFACE2, fg=UI_TEXT,
                         font=FONT_SMALL).pack(side="left")
                tk.Label(row, text=f"${amt:,.2f}", bg=UI_SURFACE2, fg=UI_MUTED,
                         font=FONT_SMALL).pack(side="right")
        return glow

    def refresh_today_tab(self):
        self._update_nav_badges()
        self._redraw_hero_sparklines()
        self._render_today_get_started()
        self._render_pay_overdue_nudge()
        self._render_income_confirmations()
        self._refresh_setup_completeness()
        self._refresh_at_risk()
        snapshot = self._next_actions_snapshot()
        pending_review = snapshot["pending_review"]
        pace = snapshot["pace"]
        forecast = snapshot["forecast"]
        health = snapshot["health"]
        due_items = snapshot["due_items"]
        actions = snapshot["actions"]

        # ── Hero cards ───────────────────────────────────────────────────────
        self._tween_number(self.today_safe_to_spend_var,
                            float(self.state.last_safe_to_spend),
                            lambda v: f"${v:,.2f}", key="today_safe")
        self._tween_number(self.today_daily_pace_var,
                            float(pace["safe_per_day"]),
                            lambda v: f"${v:,.2f} / day", key="today_pace")
        self.today_pending_reviews_var.set(f"{pending_review} needing review")
        self.today_workflow_summary_var.set(self._format_transaction_workflow_summary())

        # Spending velocity subtitle
        days_left = pace["days_left_in_cycle"]
        spent = pace["spent_this_cycle"]
        safe = self.state.last_safe_to_spend
        remaining = max(0.0, safe - spent)
        if safe > 0 and days_left > 0:
            pct_used = (spent / safe) * 100 if safe > 0 else 0
            self.today_velocity_var.set(
                f"{days_left}d left · ${remaining:,.0f} of ${safe:,.0f} remaining · {pace['status']}"
            )
        elif self.state.incomes:
            self.today_velocity_var.set(f"${remaining:,.0f} remaining this cycle")
        else:
            self.today_velocity_var.set("Log a pay to get started.")

        top_action = actions[0]
        if top_action["priority"] >= 85:
            self.today_actions_summary_var.set("High-priority action needs attention now.")
        elif top_action["priority"] >= 60:
            self.today_actions_summary_var.set("System is stable, but there is a clear next move.")
        else:
            self.today_actions_summary_var.set("No critical issues — maintain rhythm.")

        # ── Distribution metrics strip ───────────────────────────────────────
        self.dash_bills_var.set(f"${self.state.last_reserved_total:,.2f}")
        self.dash_funds_var.set(f"${self.state.last_fund_total:,.2f}")
        self.dash_goals_var.set(f"${self.state.last_goal_total:,.2f}")
        self.dash_invest_var.set(f"${self.state.last_invest_total:,.2f}")
        self.dash_gold_var.set(str(self.state.game.total_score))
        self._draw_streak_chain(self._today_streak_canvas, self.state.game.streak_history, self.state.game.streak_pays, max_dots=10)

        # ── Allocation plan cards ────────────────────────────────────────────
        if self.last_allocation:
            a = self.last_allocation
            accts = self.state.transfer_accounts
            bills_acct = accts.get("bills", {}).get("name", "Bills Account")
            savings_acct = accts.get("savings", {}).get("name", "Savings Account")
            invest_acct = accts.get("invest", {}).get("name", "Investment Account")
            spending_acct = accts.get("spending", {}).get("name", "Everyday Account")
            cycle = self.state.pay_frequency
            days_in_cycle = self.engine.current_cycle_days()

            self._render_alloc_action_cards(a, bills_acct, savings_acct,
                                             invest_acct, spending_acct)
            self._render_allocation_plan_cards(a, pace, health, forecast,
                                                days_in_cycle, cycle,
                                                bills_acct, savings_acct,
                                                invest_acct, spending_acct)
        else:
            for w in self._alloc_actions_frame.winfo_children():
                w.destroy()
            self._render_allocation_plan_cards({}, pace, health, forecast,
                                                self.engine.current_cycle_days(),
                                                self.state.pay_frequency, "", "", "", "")

        # ── Upcoming payments treeview ───────────────────────────────────────
        for row in self.today_due_tree.get_children():
            self.today_due_tree.delete(row)
        self._today_due_row_map = {}
        # Build lookup: (kind, name) -> state-list index. Due items are sorted
        # by days/date — the same state list holds the source objects, so we
        # match back by name per-kind.
        bill_idx = {b.name: i for i, b in enumerate(self.state.bills)}
        fund_idx = {f.name: i for i, f in enumerate(self.state.funds)}
        goal_idx = {g.name: i for i, g in enumerate(self.state.goals)}
        for item_type, name, amount, saved, days, _due in due_items[:14]:
            when_text = "Overdue" if days < 0 else "Today" if days == 0 else f"{days}d"
            tag = "overdue" if days < 0 else "urgent" if days <= self.engine.current_cycle_days() else "good"
            iid = self.today_due_tree.insert("", tk.END,
                values=(f"{item_type}: {name}", f"${amount:,.2f}", when_text, f"${saved:,.2f}"),
                tags=(tag,))
            if item_type == "Bill" and name in bill_idx:
                self._today_due_row_map[iid] = ("bill", bill_idx[name])
            elif item_type == "Fund" and name in fund_idx:
                self._today_due_row_map[iid] = ("fund", fund_idx[name])
            elif item_type == "Goal" and name in goal_idx:
                self._today_due_row_map[iid] = ("goal", goal_idx[name])
        self._restripe_tree(self.today_due_tree)
        self._refresh_today_due_action_state()

        # ── Gerald quip ──────────────────────────────────────────────────────
        self._update_gerald_quip(snapshot)

    def _update_gerald_quip(self, snapshot: dict):
        """Pick a contextual Gerald quip based on current app state."""
        g = self.state.game
        pace = snapshot["pace"]
        health = snapshot["health"]
        actions = snapshot["actions"]
        due_items = snapshot["due_items"]

        quips: list[tuple[int, str, str]] = []  # (priority, quip, expression)

        # ── Spending pace alerts
        if pace["status"] == "over":
            quips.append((95, f"Careful — you're at ${pace['current_daily_spend']:,.0f}/day against a safe ${pace['safe_per_day']:,.0f}/day. Pull back a bit.", "normal"))
        elif pace["status"] == "tight":
            quips.append((80, f"Spending's tight this cycle — ${pace['current_daily_spend']:,.0f}/day. You've got this, just stay deliberate.", "normal"))

        # ── Pending reviews
        pr = snapshot["pending_review"]
        if pr >= 5:
            quips.append((88, f"{pr} transactions need review. The data won't sort itself — let's clear the queue.", "normal"))
        elif pr > 0:
            quips.append((60, f"{pr} transaction{'s' if pr > 1 else ''} waiting for your call. Quick job.", "wink"))

        # ── Streak milestones
        streak = g.streak_pays
        if streak >= 10:
            quips.append((85, f"🔥 {streak}-pay streak! That's serious discipline. You've built a real system here.", "wink"))
        elif streak >= 5:
            quips.append((75, f"Five-pay streak and counting. Consistency is the whole game.", "wink"))
        elif streak == 0 and g.best_streak >= 3:
            quips.append((65, "Streak broke. No stress — the system still works. Next pay, we rebuild.", "normal"))

        # ── Fund progress
        for fund in self.state.funds:
            if fund.target_amount > 0:
                pct = (fund.current_saved / fund.target_amount) * 100
                if 75 <= pct < 100:
                    quips.append((70, f"{fund.name} is {pct:.0f}% funded — almost there. A couple more pays should close it out.", "wink"))
                    break
                elif pct >= 100:
                    quips.append((72, f"{fund.name} is fully funded! Time to mark it complete or raise the target.", "wink"))
                    break

        # ── Overdue items
        overdue = [d for d in due_items if d[4] < 0]
        if overdue:
            name = overdue[0][1]
            days = abs(overdue[0][4])
            quips.append((92, f"{name} is {days} day{'s' if days > 1 else ''} overdue. That one needs attention first.", "normal"))

        # ── Health score
        if health["status"] == "fragile":
            quips.append((78, f"Health score is {health['score']:.0f}/100. Focus on coverage and consistency — the score follows.", "normal"))
        elif health["status"] == "strong":
            quips.append((50, f"Health score {health['score']:.0f}/100. Solid. This is what a calm system looks like.", "wink"))

        # ── Gems available
        if g.gems >= 15:
            quips.append((45, f"You're sitting on {g.gems} Gems. The Perk Shop has upgrades that compound.", "wink"))

        # ── Prestige unlocked
        if g.level >= 10 and g.prestige_level == 0:
            quips.append((55, "Level 10 — Prestige is unlocked. Reset for a permanent score multiplier. Worth it.", "wink"))

        # ── Daily challenges
        incomplete = [ch for ch in g.daily_challenges if not ch.get("completed")]
        if incomplete:
            quips.append((40, f"Daily challenge open: \"{incomplete[0]['description']}\" — easy points if you're already here.", "wink"))

        # ── First time / no data
        if not self.state.incomes:
            quips.append((100, "Hey — log your first pay on the Income tab. That's the trigger for everything.", "normal"))

        # ── Idle encouragement (fallback)
        quips.append((1, "System is clear. Maintain the rhythm — that's the whole strategy.", "normal"))

        # Pick highest priority
        quips.sort(key=lambda q: -q[0])
        _, quip_text, expression = quips[0]
        self._gerald_quip_var.set(quip_text)
        # Update expression
        _draw_gerald(self._gerald_canvas, w=60, h=80, expression=expression)

    def _draw_streak_chain(self, canvas, history: list, current_streak: int, max_dots: int = 20):
        """Draw a horizontal chain of colored circles representing streak history.

        Green = good pay, red = broken, grey = future/empty slots.
        """
        canvas.delete("all")
        w = canvas.winfo_reqwidth() or 90
        h = canvas.winfo_reqheight() or 60

        # Layout: up to max_dots circles in rows
        cols = 10
        rows = (max_dots + cols - 1) // cols
        dot_r = 3
        gap_x = (w - 2 * dot_r) / max(cols - 1, 1)
        gap_y = (h - 2 * dot_r) / max(rows - 1, 1) if rows > 1 else 0
        start_y = (h - (rows - 1) * gap_y) / 2 if rows > 1 else h / 2

        # Pad history to max_dots with None (future slots)
        padded = list(history[-max_dots:])
        while len(padded) < max_dots:
            padded.append(None)

        for i, val in enumerate(padded):
            col = i % cols
            row = i // cols
            cx = dot_r + col * gap_x
            cy = start_y + row * gap_y

            if val is True:
                fill = UI_EMERALD
                outline = "#059669"
            elif val is False:
                fill = UI_RUBY
                outline = "#e11d48"
            else:
                fill = UI_SURFACE3
                outline = UI_BORDER

            canvas.create_oval(cx - dot_r, cy - dot_r, cx + dot_r, cy + dot_r,
                               fill=fill, outline=outline, width=1)

        # If current streak >= 3, add a small glow around the latest good dot
        if current_streak >= 3 and history:
            last_idx = min(len(history) - 1, max_dots - 1)
            col = last_idx % cols
            row = last_idx // cols
            cx = dot_r + col * gap_x
            cy = start_y + row * gap_y
            canvas.create_oval(cx - dot_r - 2, cy - dot_r - 2, cx + dot_r + 2, cy + dot_r + 2,
                               fill="", outline=UI_GOLD, width=1)

    def _review_target_date(self) -> date:
        today = date.today()
        offset = getattr(self, "_review_month_offset", 0)
        y, m = today.year, today.month + offset
        while m <= 0:
            m += 12; y -= 1
        while m > 12:
            m -= 12; y += 1
        return date(y, m, 1)

    def _review_prev_month(self):
        self._review_month_offset -= 1
        self.refresh_review_tab()

    def _review_next_month(self):
        if self._review_month_offset < 0:
            self._review_month_offset += 1
            self.refresh_review_tab()

    def _review_this_month(self):
        self._review_month_offset = 0
        self._review_period_scope = "month"
        self.refresh_review_tab()

    def _review_set_period(self, scope: str):
        self._review_period_scope = scope if scope in {"month", "3m", "6m", "ytd"} else "month"
        if self._review_period_scope == "month":
            self._review_month_offset = 0
        self.refresh_review_tab()

    def _resolve_review_period(self) -> tuple:
        """Return (start, end, label, scope_word) for the active period scope."""
        today = date.today()
        scope = getattr(self, "_review_period_scope", "month")
        if scope == "month":
            target = self._review_target_date()
            start, end = month_bounds(target)
            label = target.strftime("%B %Y")
            scope_word = "this month" if self._review_month_offset == 0 else label
            return start, end, label, scope_word
        if scope == "3m":
            start_dt = today - timedelta(days=90)
            return start_dt, today, "Last 3 Months", "the last 3 months"
        if scope == "6m":
            start_dt = today - timedelta(days=180)
            return start_dt, today, "Last 6 Months", "the last 6 months"
        # ytd
        start_dt = date(today.year, 1, 1)
        return start_dt, today, f"{today.year} YTD", f"{today.year} year-to-date"

    def _restyle_review_period_pills(self):
        """Highlight the active period pill; mute the rest."""
        btns = getattr(self, "_review_period_buttons", None)
        if not btns:
            return
        active = getattr(self, "_review_period_scope", "month")
        for key, meta in btns.items():
            on = (key == active)
            meta["outer"].configure(bg=UI_GOLD if on else UI_BORDER)
            meta["inner"].configure(bg=UI_SURFACE2 if on else UI_SURFACE)
            meta["label"].configure(bg=UI_SURFACE2 if on else UI_SURFACE,
                                     fg=UI_GOLD if on else UI_MUTED)

    def refresh_review_tab(self):
        self._restyle_review_period_pills()
        scope = getattr(self, "_review_period_scope", "month")
        start, end, label_text, scope_word = self._resolve_review_period()
        if scope == "month":
            target = self._review_target_date()
            data = self._current_month_review_data(for_date=target)
            is_current = (self._review_month_offset == 0)
            if hasattr(self, "_review_month_label"):
                label = f"{label_text}" + ("  (current)" if is_current else "")
                self._review_month_label.config(text=label)
        else:
            data = self._current_month_review_data(bounds=(start, end))
            if hasattr(self, "_review_month_label"):
                self._review_month_label.config(text=label_text)
        self.review_savings_rate_var.set(f"{data['savings_rate']:.1f}% {scope_word}")
        if data["mix_rows"]:
            lead = data["mix_rows"][0]
            self.review_mix_summary_var.set(f"{lead[0]} {'over' if lead[3] > 0 else 'under'} target by {abs(lead[3]):.1f} pts")
        else:
            self.review_mix_summary_var.set("Import transactions to compare mix")
        if data["anomalies"]:
            self.review_anomaly_var.set(f"{len(data['anomalies'])} merchant pattern(s) stand out")
        else:
            self.review_anomaly_var.set("No strong anomalies detected")

        forecast = self.calculate_cashflow_forecast()
        health = self.calculate_financial_health_score()
        self._render_review_insights(data, health, forecast, scope_word)

        # Cache rows so resize events can redraw without refiltering
        self._last_mix_rows = list(data["mix_rows"])
        self._review_mix_scope_word = scope_word
        self._last_mix_start = data.get("start")
        self._last_mix_end = data.get("end")
        self._draw_review_mix_bars(self._last_mix_rows)

        self._render_review_anomalies(data["anomalies"])

        # 6-month trend chart — cache rows so resize events can redraw
        self._last_trend_rows = self._compute_monthly_trend_data(num_months=6)
        self._draw_monthly_trend_chart(self._last_trend_rows)
        self._render_review_nudges(self._compute_review_nudges(self._last_trend_rows))

    def _refresh_personality_panel(self):
        if not hasattr(self, "_personality_attr_vars"):
            return
        p = self._compute_personality()
        attrs = p["attributes"]
        attr_label_map = {aid: aname for aid, aname, _, _ in PERSONALITY_ATTRIBUTES}
        accent = p["archetype_color"] if not p["analyzing"] else UI_AMETHYST

        # Color-coded accents
        if hasattr(self, "_personality_accent"):
            self._personality_accent.configure(bg=accent)
        if hasattr(self, "_personality_stripe"):
            self._personality_stripe.configure(bg=accent)
        if hasattr(self, "_personality_archetype_lbl"):
            self._personality_archetype_lbl.configure(fg=accent)
        if hasattr(self, "_personality_glyph_lbl"):
            self._personality_glyph_lbl.configure(fg=accent)
        if hasattr(self, "_personality_tier_lbl"):
            self._personality_tier_lbl.configure(fg=p["tier_color"])

        if p["analyzing"]:
            self._personality_archetype_var.set("Analyzing…")
            self._personality_glyph_var.set("◆")
            self._personality_desc_var.set(f"Need more data. Log pays, verify transactions, import statements. ({p['data_points']} signals so far)")
            self._personality_data_var.set(f"{p['data_points']} signal(s)")
            self._personality_tier_var.set("")
            self._personality_confidence_var.set("")
            self._personality_top_var.set("")
            self._personality_runner_var.set("")
        else:
            self._personality_archetype_var.set(p["archetype_name"])
            self._personality_glyph_var.set(p["archetype_glyph"])
            self._personality_desc_var.set(p["archetype_desc"])
            self._personality_data_var.set(f"{p['data_points']} signal(s)")
            self._personality_tier_var.set(f"· {p['tier_name']}")
            self._personality_confidence_var.set(f"Fit confidence {p['confidence']}%  ·  match gap {int(p['match_distance'])}")
            top_names = [f"{attr_label_map[k]} {v}" for k, v in p["top_attributes"]]
            self._personality_top_var.set("Defining traits: " + " · ".join(top_names))
            if p["runner_up_name"] and p["runner_up_deltas"]:
                delta_bits = []
                for k, d in p["runner_up_deltas"]:
                    sign = "+" if d > 0 else ""
                    delta_bits.append(f"{sign}{d} {attr_label_map[k]}")
                self._personality_runner_var.set(
                    f"Next closest: {p['runner_up_name']} — shift " + ", ".join(delta_bits)
                )
            elif p["runner_up_name"]:
                self._personality_runner_var.set(f"Next closest: {p['runner_up_name']}")
            else:
                self._personality_runner_var.set("")

        # Attribute bars + trend arrows
        for aid, val in attrs.items():
            if aid in self._personality_attr_vars:
                self._personality_attr_vars[aid].set(str(val))
            if aid in self._personality_attr_canvases:
                canvas, color = self._personality_attr_canvases[aid]
                self._draw_personality_bar(canvas, val, color)
            if aid in self._personality_attr_trend_vars:
                tvar, tlbl = self._personality_attr_trend_vars[aid]
                tr = p["trends"].get(aid, 0)
                if tr > 0:
                    tvar.set("▲"); tlbl.configure(fg="#4fb07f")
                elif tr < 0:
                    tvar.set("▼"); tlbl.configure(fg="#e06c75")
                else:
                    tvar.set("·"); tlbl.configure(fg=UI_MUTED)

        # Radar chart
        if hasattr(self, "_personality_radar"):
            self._draw_personality_radar(self._personality_radar,
                                          attrs,
                                          p["archetype_profile"],
                                          accent)



