        ttk.Button(filter_bar, text="Clear", command=self._clear_tx_filters).pack(side="left")
        self.tx_filter_count_var = tk.StringVar(value="")
        tk.Label(filter_bar, textvariable=self.tx_filter_count_var, bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_SMALL).pack(side="right")

        self.tx_history_tree = ttk.Treeview(committed_inner,
                                              columns=("date", "desc", "amount", "type", "target", "category", "source"),
                                              show="headings")
        for c, t, w in [("date", "Date", 55), ("desc", "Description", 90), ("amount", "Amt", 50),
                         ("type", "Type", 50), ("target", "Target", 50),
                         ("category", "Cat.", 50), ("source", "Src", 40)]:
            self.tx_history_tree.heading(c, text=t)
