    def _build_rules_tab(self):
        frame = self.rules_tab
        frame.columnconfigure(0, weight=0)
        frame.columnconfigure(1, weight=1)
        frame.rowconfigure(0, weight=1)
        form_wrap = tk.Frame(frame, bg=UI_BG, padx=SP_XL, pady=SP_XL)
        form_wrap.grid(row=0, column=0, sticky="ns")
        form = self._card_frame(form_wrap, padx=SP_XL, pady=SP_XL)
        form.pack(fill="both", expand=True)
        form.columnconfigure(0, weight=1)
        tk.Label(form, text="Add / Edit Rule", bg=UI_SURFACE, fg=UI_TEXT,
                 font=FONT_HEADING).grid(row=0, column=0, sticky="w", pady=(0, 4))
        tk.Label(form, text="Rules auto-classify future imports\nwhen a keyword matches.",
                 bg=UI_SURFACE, fg=UI_MUTED, font=FONT_SMALL, justify="left").grid(
                 row=1, column=0, sticky="w", pady=(0, 10))
        for r, lbl, attr, kw in [
            (2,  "Rule Name",              "rule_name_entry",    {}),
            (4,  "Keyword / Description",  "rule_keyword_entry", {}),
            (6,  "Amount (for amount_contains)", "rule_amount_entry", {}),
            (8,  "Matched Target",         "rule_target_entry",  {}),
            (10, "Category",               "rule_category_entry",{}),
        ]:
            tk.Label(form, text=lbl, bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_SMALL_BOLD).grid(row=r, column=0, sticky="w", pady=(6, 1))
            e = ttk.Entry(form, width=24)
            e.grid(row=r + 1, column=0, sticky="ew", pady=(0, 2))
            setattr(self, attr, e)
        tk.Label(form, text="Rule Type", bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_SMALL_BOLD).grid(row=12, column=0, sticky="w", pady=(6, 1))
        self.rule_type_combo = ttk.Combobox(form, values=["contains", "exact", "amount_contains"],
                                             state="readonly", width=22)
        self.rule_type_combo.set("contains")
        self.rule_type_combo.grid(row=13, column=0, sticky="ew", pady=(0, 2))
        tk.Label(form, text="Matched Type", bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_SMALL_BOLD).grid(row=14, column=0, sticky="w", pady=(6, 1))
        self.rule_match_type_combo = ttk.Combobox(
            form, values=["discretionary", "linked_bill", "linked_fund", "income", "transfer", "ignore"],
            state="readonly", width=22)
        self.rule_match_type_combo.set("discretionary")
        self.rule_match_type_combo.grid(row=15, column=0, sticky="ew", pady=(0, 12))
        tk.Frame(form, bg=UI_BORDER, height=1).grid(row=16, column=0, sticky="ew", pady=(0, 10))
        ttk.Button(form, text="Add Rule", style="Accent.TButton",
                   command=self.add_advanced_rule).grid(row=17, column=0, sticky="ew", pady=(0, 6))
        ttk.Button(form, text="Update Selected",
                   command=self.update_selected_rule).grid(row=18, column=0, sticky="ew", pady=(0, 6))
        ttk.Button(form, text="Delete Selected",
                   command=self.delete_selected_rule).grid(row=19, column=0, sticky="ew")
        tbl_wrap = tk.Frame(frame, bg=UI_BG, pady=SP_XL)
        tbl_wrap.grid(row=0, column=1, sticky="nsew", padx=(0, SP_XL))
        tbl_wrap.columnconfigure(0, weight=1)
        tbl_wrap.rowconfigure(1, weight=1)
        tk.Label(tbl_wrap, text="Saved Rules", bg=UI_BG, fg=UI_TEXT,
                 font=FONT_HEADING).grid(row=0, column=0, sticky="w", pady=(0, 8))
        box = self._card_frame(tbl_wrap, padx=0, pady=0)
        box.grid(row=1, column=0, sticky="nsew")
        box.rowconfigure(0, weight=1)
        box.columnconfigure(0, weight=1)
        self.rules_tree = ttk.Treeview(box, columns=("type", "keyword", "amount", "match", "target", "category", "active"),
                                        show="headings")
        for c, t, w in [("type", "Type", 80), ("keyword", "Keyword", 130), ("amount", "Amount", 60),
                         ("match", "Match Type", 90), ("target", "Target", 85),
                         ("category", "Category", 80), ("active", "Active", 50)]:
            self.rules_tree.heading(c, text=t)
            self.rules_tree.column(c, width=w, minwidth=40)
        self.rules_tree.grid(row=0, column=0, sticky="nsew")
        s = ttk.Scrollbar(box, orient="vertical", command=self.rules_tree.yview)
        s.grid(row=0, column=1, sticky="ns")
        self.rules_tree.configure(yscrollcommand=self._autohide_scrollbar(s, "grid", row=0, column=1, sticky="ns"))
        self._apply_zebra(self.rules_tree)
        self.rules_tree.bind("<<TreeviewSelect>>", self.on_rule_select)

    def _build_accounts_tab(self):
        frame = self.accounts_tab
        frame.columnconfigure(0, weight=1)
        frame.rowconfigure(1, weight=1)

        # ── Guide card ───────────────────────────────────────────────────────
        guide = tk.Frame(frame, bg=UI_SURFACE, padx=SP_XL, pady=SP_LG,
                         highlightthickness=1, highlightbackground=UI_BORDER)
        guide.grid(row=0, column=0, sticky="ew", padx=SP_XL, pady=(SP_XL, SP_MD))
        guide.columnconfigure(0, weight=1)
        tk.Frame(guide, bg=UI_ACCENT, height=3).grid(row=0, column=0, sticky="ew")
        tk.Label(guide, text="How Banking Setup Works", bg=UI_SURFACE, fg=UI_TEXT,
                 font=FONT_SUBHEADING).grid(row=1, column=0, sticky="w", pady=(10, 6))
        guide_lines = [
            "This app tells you exactly where to move your money after each pay.",
            "To make that work, you need 2-4 bank accounts (most banks let you",
            "create extra accounts for free in their app).",
            "",
            "RECOMMENDED SETUP:",
            "",
            "1. Everyday Account  —  where your pay is deposited and daily",
            "   spending comes from.  Your 'safe to spend' stays here.",
            "",
            "2. Bills Account  —  set up all your direct debits and auto-pays",
            "   from this account (rent, utilities, subscriptions, insurance).",
            "   Each pay, transfer the bills amount here.",
            "",
            "3. Savings Account  —  sinking funds (car service, holidays) and",
            "   goals (emergency fund, house deposit) are built here.",
            "   Each pay, transfer the funds + goals amount here.",
            "",
            "4. Investment Account (optional)  —  brokerage or high-interest",
            "   savings for your investing allocation.",
            "",
            "THE ROUTINE:",
            "Pay day arrives → open this app → log your pay → the app shows",
            "your transfer plan → open your bank → make the transfers → done.",
            "That's the entire system.  Repeat every pay cycle.",
            "",
            "Name your accounts below to match your actual bank accounts.",
            "The transfer plan on your Today page will use these names.",
        ]
        for line in guide_lines:
            if line.startswith("RECOMMENDED") or line.startswith("THE ROUTINE"):
                tk.Label(guide, text=line, bg=UI_SURFACE, fg=UI_ACCENT,
                         font=FONT_SMALL_BOLD).grid(
                    row=guide.grid_size()[1], column=0, sticky="w", pady=(4, 0))
            elif line == "":
                tk.Frame(guide, bg=UI_SURFACE, height=4).grid(
                    row=guide.grid_size()[1], column=0, sticky="ew")
            else:
                tk.Label(guide, text=line, bg=UI_SURFACE, fg=UI_MUTED,
                         font=FONT_SMALL, justify="left").grid(
                    row=guide.grid_size()[1], column=0, sticky="w")

        # ── Account name editor ──────────────────────────────────────────────
        editor = tk.Frame(frame, bg=UI_SURFACE, padx=SP_XL, pady=SP_LG,
                          highlightthickness=1, highlightbackground=UI_BORDER)
        editor.grid(row=1, column=0, sticky="nsew", padx=SP_XL, pady=(0, SP_XL))
        editor.columnconfigure(1, weight=1)
        tk.Frame(editor, bg=UI_EMERALD, height=3).grid(row=0, column=0, columnspan=3, sticky="ew")
        tk.Label(editor, text="Your Bank Accounts", bg=UI_SURFACE, fg=UI_TEXT,
                 font=FONT_SUBHEADING).grid(
            row=1, column=0, columnspan=3, sticky="w", pady=(10, 4))
        tk.Label(editor, text="Name these to match your real bank accounts. The transfer plan will use these names.",
                 bg=UI_SURFACE, fg=UI_MUTED,
                 font=FONT_SMALL).grid(
            row=2, column=0, columnspan=3, sticky="w", pady=(0, 12))

        self._account_entries = {}
        acct_defs = [
            ("spending", "Everyday / Spending", UI_EMERALD,
             "Where your pay is deposited. 'Safe to spend' stays here."),
            ("bills", "Bills / Direct Debits", UI_RUBY,
             "Transfer your bills allocation here each pay. Direct debits come out of this account."),
            ("savings", "Savings / Funds & Goals", UI_SAPPHIRE,
             "Transfer your sinking funds + goals allocation here each pay."),
            ("invest", "Investing", UI_AMETHYST,
             "Transfer your investing allocation here each pay. (Optional — leave blank if you don't use one.)"),
        ]
        for i, (key, label, accent, desc) in enumerate(acct_defs):
            r = 3 + i * 2
            tk.Frame(editor, bg=accent, width=4, height=1).grid(row=r, column=0, sticky="ns", padx=(0, 10), rowspan=2)
            tk.Label(editor, text=label, bg=UI_SURFACE, fg=UI_TEXT,
                     font=FONT_BODY_BOLD).grid(row=r, column=1, sticky="w")
            tk.Label(editor, text=desc, bg=UI_SURFACE, fg=UI_MUTED,
                     font=FONT_CAPTION, wraplength=500, justify="left").grid(
                row=r + 1, column=1, sticky="w", pady=(0, 10))
            entry = ttk.Entry(editor, width=30, font=FONT_BODY)
            entry.grid(row=r, column=2, sticky="w", padx=(12, 0), rowspan=2, pady=(0, 10))
            current = self.state.transfer_accounts.get(key, {}).get("name", "")
            entry.insert(0, current)
            self._account_entries[key] = entry

        save_row = 3 + len(acct_defs) * 2
        ttk.Button(editor, text="Save Account Names", style="Accent.TButton",
                   command=self._save_account_names).grid(
            row=save_row, column=1, columnspan=2, sticky="w", pady=(8, 0))

    def _save_account_names(self):
        for key, entry in self._account_entries.items():
            name = entry.get().strip()
            if name:
                if key not in self.state.transfer_accounts:
                    self.state.transfer_accounts[key] = {}
                self.state.transfer_accounts[key]["name"] = name
        self.save_state()
        self.refresh_today_tab()
        self._show_toast("Account names updated — transfer plan refreshed.", "success")

