    def _set_coll_filter(self, val):
        self._coll_filter_var.set(val)
        for v, btn in self._coll_filter_btns.items():
            if v == val:
                btn.configure(bg=UI_ACCENT, fg=UI_HERO)
            else:
                btn.configure(bg=UI_SURFACE2, fg=UI_MUTED)
        self.refresh_collection()

