    def _pie_slice_hover_on(self, tag: str, color: str, label: str, val: float, pct: float):
        canvas = self.expense_pie_canvas
        canvas.configure(cursor="hand2")
        try:
            canvas.itemconfigure(tag, outline=UI_GOLD, width=3)
        except tk.TclError:
            return
        # Restyle center text
        if hasattr(self, "_pie_center_vars"):
            try:
                canvas.itemconfigure("pie_center_label", text=label[:22].upper())
                canvas.itemconfigure("pie_center_total", text=f"${val:,.0f}", fill=color)
                canvas.itemconfigure("pie_center_sub", text=f"{pct:.1f}% of total")
            except tk.TclError:
                pass

    def _pie_slice_hover_off(self, tag: str):
        canvas = self.expense_pie_canvas
        canvas.configure(cursor="")
        try:
            canvas.itemconfigure(tag, outline=UI_BG, width=2)
        except tk.TclError:
            return
        if hasattr(self, "_pie_center_vars"):
            pv = self._pie_center_vars
            try:
                canvas.itemconfigure("pie_center_label", text="TOTAL")
                canvas.itemconfigure("pie_center_total",
                                     text=f"${pv['total_sum']:,.0f}", fill=UI_GOLD)
                canvas.itemconfigure("pie_center_sub", text=f"{pv['count']} categories")
            except tk.TclError:
                pass

    def refresh_expense_pie_chart(self, _event=None):
        canvas = self.expense_pie_canvas
        canvas.delete("all")
        canvas.update_idletasks()
        w = max(int(canvas.winfo_width() or 0), 400)
        h = int(canvas.winfo_height() or 300)
        totals: Dict[str, float] = {}
        for tx in self.state.transactions:
            if tx.direction() != "out":
                continue
            if tx.matched_type == "ignore":
                continue
            cat = (tx.category or "").strip() or "Uncategorized"
            totals[cat] = totals.get(cat, 0.0) + tx.money_out
        if not totals:
            canvas.create_text(w // 2, h // 2, text="No committed outgoing transactions yet.", font=FONT_SUBHEADING, fill=UI_MUTED)
            return
        total_sum = sum(totals.values())
        if total_sum <= 0:
            canvas.create_text(w // 2, h // 2, text="No outgoing amounts in committed data.", font=FONT_SUBHEADING, fill=UI_MUTED)
            return
        items = sorted(totals.items(), key=lambda x: -x[1])
        cx = w // 2
        cy = min(130, h // 2 - 10)
        r = min(w // 2 - 40, 115, cy - 8)
        inner_r = max(int(r * 0.55), 40)
        start = 90.0
        # Cache so hover can restyle without rebuilding
        self._pie_slice_tags = []
        for i, (label, val) in enumerate(items):
            extent = -360.0 * (val / total_sum)
            color = PIE_COLORS[i % len(PIE_COLORS)]
            tag = f"pie_slice_{i}"
            self._pie_slice_tags.append(tag)
            canvas.create_arc(cx - r, cy - r, cx + r, cy + r, start=start, extent=extent,
                              fill=color, outline=UI_BG, width=2,
                              tags=(tag, "pie_clickable"))
            canvas.tag_bind(tag, "<Button-1>",
                             lambda _e, c=label: self._open_category_drilldown(c))
            canvas.tag_bind(tag, "<Enter>",
                             lambda _e, c=color, lbl=label, v=val, pct=100.0 * val / total_sum, t=tag:
                                 self._pie_slice_hover_on(t, c, lbl, v, pct))
            canvas.tag_bind(tag, "<Leave>",
                             lambda _e, t=tag: self._pie_slice_hover_off(t))
            start += extent
        # Donut hole + center total
        canvas.create_oval(cx - inner_r, cy - inner_r, cx + inner_r, cy + inner_r,
                           fill=UI_SURFACE, outline=UI_BORDER, width=1,
                           tags=("pie_center",))
        canvas.create_text(cx, cy - 12, text="TOTAL", fill=UI_MUTED,
                           font=FONT_MICRO, tags=("pie_center_label", "pie_center"))
        canvas.create_text(cx, cy + 6, text=f"${total_sum:,.0f}", fill=UI_GOLD,
                           font=FONT_SUBHEADING, tags=("pie_center_total", "pie_center"))
        canvas.create_text(cx, cy + 24, text=f"{len(items)} categories", fill=UI_MUTED,
                           font=FONT_MICRO, tags=("pie_center_sub", "pie_center"))
        self._pie_center_vars = {
            "cx": cx, "cy": cy, "total_sum": total_sum, "count": len(items),
        }
        y = min(cy + r + 28, h - 40)
        canvas.create_text(16, y, anchor="w", text=f"Total outgoing in chart: ${total_sum:,.2f}", font=FONT_SMALL_BOLD, fill=UI_TEXT)
        canvas.create_text(w - 16, y, anchor="e", text="Tip: click a slice to see transactions",
                            font=FONT_MICRO, fill=UI_MUTED)
        y += 40
        for i, (label, val) in enumerate(items[:18]):
            color = PIE_COLORS[i % len(PIE_COLORS)]
            pct = 100.0 * val / total_sum
            legend_tag = f"pie_legend_{i}"
            canvas.create_rectangle(16, y, 30, y + 12, fill=color, outline="", tags=(legend_tag,))
            canvas.create_text(36, y + 6, anchor="w",
                                text=f"{label}: ${val:,.2f} ({pct:.1f}%)",
                                font=FONT_SMALL, fill=UI_TEXT, tags=(legend_tag,))
            canvas.tag_bind(legend_tag, "<Button-1>",
                             lambda _e, c=label: self._open_category_drilldown(c))
            canvas.tag_bind(legend_tag, "<Enter>",
                             lambda _e: canvas.configure(cursor="hand2"))
            canvas.tag_bind(legend_tag, "<Leave>",
                             lambda _e: canvas.configure(cursor=""))
            y += 18
        if len(items) > 18:
            canvas.create_text(16, y + 4, anchor="w", text=f"… and {len(items) - 18} more categories", font=("Segoe UI Variable Text",9, "italic"), fill=UI_MUTED)

    def _parse_filter_date(self, s: str):
        s = (s or "").strip()
        if not s:
            return None
        for fmt in ("%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y", "%d/%m/%y"):
            try:
                return datetime.strptime(s, fmt).date()
            except ValueError:
                continue
        return None

    def _clear_tx_filters(self):
        if hasattr(self, "tx_filter_keyword_var"):
            self.tx_filter_keyword_var.set("")
        if hasattr(self, "tx_filter_from_var"):
            self.tx_filter_from_var.set("")
        if hasattr(self, "tx_filter_to_var"):
            self.tx_filter_to_var.set("")
        self.refresh_transactions_tab()

    def refresh_transactions_tab(self):
        self._update_nav_badges()
        self.refresh_category_combo()
        for row in self.transaction_tree.get_children(): self.transaction_tree.delete(row)
        for idx, tx in enumerate(self.latest_import):
            status = "Verified" if tx.user_verified else "Needs review"
            tag = "matched" if tx.user_verified else "review" if tx.needs_review else "urgent"
            self.transaction_tree.insert("", tk.END, iid=str(idx), values=(
                tx.tx_date.isoformat(),
                tx.description[:40],
                f"${tx.amount():,.2f}",
                tx.direction(),
                tx.matched_type,
                tx.matched_target,
                (tx.category or "")[:24],
                status,
            ), tags=(tag,))
        self._restripe_tree(self.transaction_tree)
        self._toggle_tree_empty_state(self.transaction_tree)
        for row in self.tx_history_tree.get_children(): self.tx_history_tree.delete(row)
        kw = (getattr(self, "tx_filter_keyword_var", None).get().strip().lower()
              if hasattr(self, "tx_filter_keyword_var") else "")
        d_from = self._parse_filter_date(getattr(self, "tx_filter_from_var", None).get()
                                          if hasattr(self, "tx_filter_from_var") else "")
        d_to = self._parse_filter_date(getattr(self, "tx_filter_to_var", None).get()
                                        if hasattr(self, "tx_filter_to_var") else "")
        shown = 0
        total = len(self.state.transactions)
        for idx, tx in reversed(list(enumerate(self.state.transactions))):
            if kw and kw not in tx.description.lower() and kw not in (tx.category or "").lower() and kw not in (tx.matched_target or "").lower():
                continue
            if d_from and tx.tx_date < d_from:
                continue
            if d_to and tx.tx_date > d_to:
                continue
            self.tx_history_tree.insert("", tk.END, iid=str(idx), values=(
                tx.tx_date.isoformat(),
                tx.description[:40],
                f"${tx.amount():,.2f}",
                tx.matched_type,
                tx.matched_target,
                (tx.category or "")[:24],
                tx.source_file,
            ))
            shown += 1
        self._restripe_tree(self.tx_history_tree)
        if hasattr(self, "tx_filter_count_var"):
            if kw or d_from or d_to:
                self.tx_filter_count_var.set(f"{shown} of {total}")
            else:
                self.tx_filter_count_var.set(f"{total} total")
        self.transaction_log_text.delete("1.0", tk.END)
        verified = sum(1 for t in self.latest_import if t.user_verified)
        needs_review = sum(1 for t in self.latest_import if t.direction() == "out" and not t.user_verified)
        summary = [
            f"Preview transactions: {len(self.latest_import)}",
            f"Verified in preview: {verified}",
            f"Outgoing still needing review: {needs_review}",
            f"Committed transactions: {len(self.state.transactions)}",
        ]
        log_lines = self.latest_import_qa if self.latest_import_qa else ["No active import. Import a bank PDF to preview transactions here."]
        self.transaction_log_text.insert(tk.END, "\n".join(summary + [""] + log_lines + ["", "Note: Suggested matches are not trusted until user-verified."]))
        recurring = self.transaction_insights.get("recurring", [])
        unusual = self.transaction_insights.get("unusual", [])
        new_merchants = self.transaction_insights.get("new_merchants", [])
        insight_lines = []
        if recurring:
            insight_lines.append("Likely recurring: " + " • ".join(recurring[:3]))
        if unusual:
            insight_lines.append("Unusual spend: " + " • ".join(unusual[:3]))
        if new_merchants:
            insight_lines.append("New merchants needing review: " + ", ".join(new_merchants[:5]))
        if not insight_lines:
            insight_lines.append("No notable insights yet. Import a statement and run Suggest Matches.")
        if not self.latest_import:
            self.transaction_workflow_state_var.set("Step 1: import a bank statement PDF to start a review batch.")
        elif needs_review > 0:
            self.transaction_workflow_state_var.set(f"Step 2–3: {needs_review} outgoing transaction(s) still need verification before commit.")
        else:
            self.transaction_workflow_state_var.set("Step 4: all outgoing preview rows are verified — commit this batch when ready.")
        self.transaction_insights_var.set("\n".join(insight_lines))
        self.refresh_expense_pie_chart()

